(function() {
var deu_ch_1_Verses = [
  {num:1,words:[["O upu nei na fai atu ai Mose ia Isaraelu uma lava i le itu mai o Ioritana,", "These be the words which Moses spake unto all Israel on this side Jordan in the wilderness,"], ["i le vao i le eleele laugatasi e feagai ma Sufe,", "in the plain over against the Red sea,"], ["i le va o Parana,", "between Paran,"], ["ma Topelu,", "and Tophel,"], ["ma Lapana,", "and Laban,"], ["ma Haserota,", "and Hazeroth,"], ["ma Tisaapa.", "and Dizahab."]]},
  {num:2,words:[["O le savaliga mai Horepa i le ala e ui i le mauga o Seira e oo atu i Katesapanea, e sefulu ma le tasi ona aso.", "(There are eleven days' journey from Horeb by the way of mount Seir unto Kadesh-barnea.)"]]},
  {num:3,words:[["Ua oo i le tausaga e fagafulu,", "And it came to pass in the fortieth year,"], ["o le masina e tasi le sefulu ma le tasi,", "in the eleventh month,"], ["o le aso muamua o lea masina,", "on the first day of the month, that Moses spake unto the children of Israel,"], ["ona fai atu ai lea o Mose i le fanauga a Isaraelu o mea uma lava na poloai atu ai Ieova ia te ia e fai atu ia i latou;", "according unto all that the LORD had given him in commandment unto them;"]]},
  {num:4,words:[["ina ua uma ona fasia e ia o Sekono le tupu o sa Amorī sa nofo i Hesepona,", "After he had slain Sihon the king of the Amorites, which dwelt in Heshbon,"], ["ma Oko le tupu o Vasana sa nofo i Aserota i Eterei,", "and Og the king of Bashan, which dwelt at Astaroth in Edrei:"]]},
  {num:5,words:[["i le itu mai o Ioritana i le nuu o Moapi na amata ai ona folafolaina e Mose o lenei tulafono,", "On this side Jordan, in the land of Moab,"], ["ua faapea atu,", "began Moses to declare this law, saying,"]]},
  {num:6,words:[["Na fetalai mai Ieova lo tatou Atua ia te i tatou i Horepa,", "The LORD our God spake unto us in Horeb,"], ["ua faapea mai,", "saying,"], ["Ua leva lo outou nonofo i lenei mauga;", "Ye have dwelt long enough in this mount:"]]},
  {num:7,words:[["ia liliu ane outou,", "Turn you,"], ["ma savavali,", "and take your journey,"], ["ma o atu outou i le mauga o sa Amorī,", "and go to the mount of the Amorites,"], ["ma mea uma lava e latalata ane i ai,", "and unto all the places nigh thereunto,"], ["i le eleele laugatasi,", "in the plain,"], ["ma le mauga,", "in the hills,"], ["ma le nuu maulalo,", "and in the vale,"], ["ma le itu i toga,", "and in the south,"], ["ma le matafaga,", "and by the sea side,"], ["e oo i le nuu o sa Kananā,", "to the land of the Canaanites,"], ["ma Lepanona,", "and unto Lebanon,"], ["e oo lava i le vaitafe tele,", "unto the great river,"], ["o le vaitafe o Eufirate.", "the river Euphrates."]]},
  {num:8,words:[["Faauta,", "Behold,"], ["ua ou tuuina atu le nuu i o outou luma,", "I have set the land before you:"], ["o atu ia outou ina fai mo outou le nuu na tauto ai Ieova i o outou tamā o Aperaamo,", "go in and possess the land which the LORD sware unto your fathers, Abraham,"], ["ma Isaako,", "Isaac,"], ["ma Iakopo na te foaiina atu ia te i latou,", "and Jacob,"], ["ma a latou fanau pe a mavae atu i latou.", "to give unto them and to their seed after them."]]},
  {num:9,words:[["Na ou fai atu foi ia te outou i ia ona po,", "And I spake unto you at that time,"], ["ua faapea atu,", "saying,"], ["Ou te le lavatia lava outou e a'u e toatasi;", "I am not able to bear you myself alone:"]]},
  {num:10,words:[["ua faatoateleina outou e Ieova lo outou Atua,", "The LORD your God hath multiplied you,"], ["faauta foi,", "and, behold,"], ["o le aso nei e pei o fetu o le lagi ona toatele o outou.", "ye are this day as the stars of heaven for multitude."]]},
  {num:11,words:[["Ia atili faatoateleina outou e Ieova le Atua o outou tamā,", "(The LORD God of your fathers make you a thousand times so many more as ye are,"], ["ia faatoaafeina lo outou faitau , ma ia manuia outou ia te ia,", "and bless you,"], ["e pei ona fetalai mai o ia ia te outou.", "as he hath promised you!)"]]},
  {num:12,words:[["Ou te lavatia faapefea e a'u e toatasi o a outou mea mamafa,", "How can I myself alone bear your cumbrance,"], ["ma a outou avega,", "and your burden,"], ["ma a outou fefinauaiga?", "and your strife?"]]},
  {num:13,words:[["Ia outou filifilia mo outou o tagata popoto o e ua mafaufau,", "Take you wise men,"], ["ma e ua iloa,", "and understanding,"], ["i o outou itu aiga,", "and known among your tribes,"], ["ina ia ou tofia i latou e fai ma alii ia te outou.", "and I will make them rulers over you."]]},
  {num:14,words:[["Na outou tali mai ia te au,", "And ye answered me,"], ["ua faapea mai,", "and said,"], ["O le mea lelei lea ua e fai mai ai matou te faia.", "The thing which thou hast spoken is good for us to do."]]},
  {num:15,words:[["Ona ou ave ai lea o alii sili o outou itu aiga,", "So I took the chief of your tribes,"], ["o tagata popoto i latou,", "wise men,"], ["ma e ua iloa,", "and known,"], ["ma ou tofia i latou e fai ma alii ia te outou,", "and made them heads over you,"], ["o alii o taitoaafe,", "captains over thousands,"], ["ma alii o taitoaselau,", "and captains over hundreds,"], ["ma alii o taitolimagafulu,", "and captains over fifties,"], ["ma alii o taitoasefulu,", "and captains over tens,"], ["ma faipule i o outou itu aiga.", "and officers among your tribes."]]},
  {num:16,words:[["O ona po lava ia na ou poloai atu ai i o outou faamasino,", "And I charged your judges at that time,"], ["ua faapea atu,", "saying,"], ["Ia outou faalogologo i upu a outou uso,", "Hear the causes between your brethren,"], ["ma ia outou faamasino tonu i le tagata ma lona uso,", "and judge righteously between every man and his brother,"], ["ma le tagata ese o loo ia te ia.", "and the stranger that is with him."]]},
  {num:17,words:[["Aua tou te faailogaina se tasi i le faamasinoga;", "Ye shall not respect persons in judgment;"], ["e pei ona outou faalogologo i le tagata nuu ia faapea foi i le alii;", "but ye shall hear the small as well as the great;"], ["aua lava tou te fefefe i tagata,", "ye shall not be afraid of the face of man;"], ["auā o le faamasinoga o i lo outou Atua lea;", "for the judgment is God's:"], ["a o le mea e faigata ia te outou,", "and the cause that is too hard for you,"], ["ia au mai lea ia te au,", "bring it unto me,"], ["ou te faalogologo i ai.", "and I will hear it."]]},
  {num:18,words:[["O ona po lava ia na ou poloai atu ai ia te outou o mea uma lava tou te faia.", "And I commanded you at that time all the things which ye should do."]]},
  {num:19,words:[["Na tatou o mai mai Horepa,", "And when we departed from Horeb,"], ["na tatou savavali foi i lea vao uma e lautele ma le matautia,", "we went through all that great and terrible wilderness,"], ["na outou iloa ai i le ala i le mauga o sa Amorī,", "which ye saw by the way of the mountain of the Amorites,"], ["e pei ona poloai mai ai Ieova lo tatou Atua ia i tatou;", "as the LORD our God commanded us;"], ["ona tatou o atu lea i Katesapanea.", "and we came to Kadesh-barnea."]]},
  {num:20,words:[["Ona ou fai atu lea ia te outou,", "And I said unto you,"], ["Ua outou oo mai lava i le mauga o sa Amorī,", "Ye are come unto the mountain of the Amorites,"], ["na foaiina mai ia i tatou e Ieova lo tatou Atua.", "which the LORD our God doth give unto us."]]},
  {num:21,words:[["Faauta,", "Behold,"], ["ua tuuiua atu e Ieova lou Atua le nuu i ou luma,", "the LORD thy God hath set the land before thee:"], ["ina e alu ae ia, ia fai mou,", "go up and possess it,"], ["e pei ona fetalai mai ia te oe o Ieova le Atua o ou tamā;", "as the LORD God of thy fathers hath said unto thee;"], ["aua le fefe,", "fear not,"], ["aua le atuatuvale.", "neither be discouraged."]]},
  {num:22,words:[["Ona outou faalatalata mai lea ia te au o outou uma lava,", "And ye came near unto me every one of you,"], ["ua outou fai mai foi,", "and said,"], ["Ia tatou aauina atu tagata e muamua ia i tatou,", "We will send men before us,"], ["ina ia latou asiasi le nuu mo i tatou,", "and they shall search us out the land,"], ["ma latou au mai ai se tala ia i tatou i se ala tatou te o ae ai,", "and bring us word again by what way we must go up,"], ["o aai foi tatou te o i ai.", "and into what cities we shall come."]]},
  {num:23,words:[["Sa lelei lea upu ia te au,", "And the saying pleased me well:"], ["ona ou aauina atu ai lea ni o outou, o tagata e toasefulu ma le toalua,", "and I took twelve men of you,"], ["o le itu aiga ma le tagata.", "one of a tribe:"]]},
  {num:24,words:[["Ona latou faasaga ae lea,", "And they turned and went up into the mountain,"], ["ma o ae i le mauga, ua latou oo atu i le alia o Esekolo,", "and came unto the valley of Eshcol,"], ["ua latou asiasi ai.", "and searched it out."]]},
  {num:25,words:[["Na tago foi o latou lima i fua o le fanua,", "And they took of the fruit of the land in their hands,"], ["ona au mai ai lea ia te i tatou,", "and brought it down unto us,"], ["ma latou foi mai ai ma se tala ia te i tatou,", "and brought us word again,"], ["ua latou faapea mai,", "and said,"], ["Ua lelei le nuu ua foaiina mai e Ieova lo tatou Atua ia i tatou.", "It is a good land which the LORD our God doth give us."]]},
  {num:26,words:[["Na outou le mafafai ona o ae,", "Notwithstanding ye would not go up,"], ["a ua outou fouvale i le afioga a Ieova lo outou Atua.", "but rebelled against the commandment of the LORD your God:"]]},
  {num:27,words:[["Na outou muimui foi i o outou fale ie,", "And ye murmured in your tents, and said,"], ["ua outou faapea ane,", "Because the LORD hated us,"], ["O le 'ino'ino mai o Ieova ia i tatou ua na au mai ai i tatou ai le nuu o Aikupito ina ia tuuina atu i tatou i lima o sa Amorī,", "he hath brought us forth out of the land of Egypt,"], ["ia faaumatia ai i tatou.", "to deliver us into the hand of the Amorites, to destroy us."]]},
  {num:28,words:[["Pe tatou te o ae i fea? Ua faavaivai mai e o tatou uso o tatou loto, ua faapea mai,", "Whither shall we go up? our brethren have discouraged our heart,"], ["O le nuu e sili ona toatele,", "saying,"], ["ma le maualuluga ia te i tatou; o aai foi ua tetele,", "The people is greater and taller than we;"], ["ma ua puipui i pa e oo i le lagi,", "the cities are great and walled up to heaven;"], ["i le ma lea foi, na matou iloa ai atalii o Anaki.", "and moreover we have seen the sons of the Anakims there."]]},
  {num:29,words:[["Ona ou fai atu lea ia te outou,", "Then I said unto you,"], ["Aua tou te fefefe,", "Dread not,"], ["aua foi tou te matatau ia te i latou.", "neither be afraid of them."]]},
  {num:30,words:[["O Ieova lo outou Atua o le na te muamua ia te outou,", "The LORD your God which goeth before you,"], ["e tau o ia mo outou,", "he shall fight for you,"], ["e tusa ma mea uma na na faia mo outou i Aikupito i o outou luma;", "according to all that he did for you in Egypt before your eyes;"]]},
  {num:31,words:[["ma le vao foi,", "And in the wilderness,"], ["na e iloa ai ona tausia oe e Ieova lou Atua,", "where thou hast seen how that the LORD thy God bare thee,"], ["e pei o le tagata ona tausia o lona atalii,", "as a man doth bear his son,"], ["i le ala uma na outou savavali ai,", "in all the way that ye went,"], ["ua oo ina outou oo mai lava i lenei mea.", "until ye came into this place."]]},
  {num:32,words:[["A ua outou le faatuatua ia Ieova lo outou Atua i lenei lava mea,", "Yet in this thing ye did not believe the LORD your God,"]]},
  {num:33,words:[["o le na muamua ia te outou i le ala,", "Who went in the way before you,"], ["e saili se mea tou te to lauapi ai,", "to search you out a place to pitch your tents in,"], ["o i le afi i le po,", "in fire by night,"], ["e faaali atu ai ia te outou le ala tou te savavali ai,", "to shew you by what way ye should go,"], ["o i le ao foi ina o ao.", "and in a cloud by day."]]},
  {num:34,words:[["Ua faafofogaina mai e Ieova o a outou upu,", "And the LORD heard the voice of your words,"], ["ona toasa lea o ia,", "and was wroth,"], ["ua tauto foi ia,", "and sware,"], ["ua faapea,", "saying,"]]},
  {num:35,words:[["E le iloa lava e se toatasi o nei tagata o lenei tupulaga leaga le nuu lelei na ou tauto ai e avatu mo outou tamā,", "Surely there shall not one of these men of this evil generation see that good land, which I sware to give unto your fathers,"]]},
  {num:36,words:[["na o Kalepo le atalii o Iefune,", "Save Caleb the son of Jephunneh;"], ["e iloa ai e ia;", "he shall see it,"], ["ou te avatu foi ia te ia ma ana fanau le nuu na ia alu atu i ai;", "and to him will I give the land that he hath trodden upon, and to his children,"], ["auā ua matuā mulimuli atu o ia ia Ieova.", "because he hath wholly followed the LORD."]]},
  {num:37,words:[["Ua toasa mai foi Ieova ia te au talu o outou,", "Also the LORD was angry with me for your sakes,"], ["ua faapea mai, O oe foi,", "saying,"], ["e te le alu i ai.", "Thou also shalt not go in thither."]]},
  {num:38,words:[["O Iosua le atalii o Nuno,", "But Joshua the son of Nun,"], ["o lē tu i ou luma,", "which standeth before thee,"], ["e alu lava o ia i ai;", "he shall go in thither:"], ["ia e faamalosi ia te ia,", "encourage him:"], ["auā o ia na te tofia le nuu mo Isaraelu.", "for he shall cause Israel to inherit it."]]},
  {num:39,words:[["O a outou tama iti foi na outou fai mai ai,", "Moreover your little ones,"], ["e avea i latou ma tagata o taua,", "which ye said should be a prey,"], ["ma a outou fanau na le iloa i lea aso se mea lelei po o se mea leaga,", "and your children, which in that day had no knowledge between good and evil,"], ["latou te oo lava i ai,", "they shall go in thither,"], ["ou te avatu ai ia te i latou,", "and unto them will I give it,"], ["e fai ai foi mo latou tofi.", "and they shall possess it."]]},
  {num:40,words:[["A o outou,", "But as for you,"], ["ina liliu ane ia outou, ma o atu i le vao,", "turn you,"], ["i le ala i le sami Ulaula.", "and take your journey into the wilderness by the way of the Red sea."]]},
  {num:41,words:[["Ona outou tali mai lea, ua outou faapea mai ia te au,", "Then ye answered and said unto me,"], ["Ua matou agasala atu ia Ieova;", "We have sinned against the LORD,"], ["matou te o ae,", "we will go up and fight,"], ["matou te sii atu le taua, e pei o mea uma lava na poloai mai ai Ieova lo tatou Atua.", "according to all that the LORD our God commanded us."], ["Ona laei ai lea o outou, ua taitasi ai ma ana mea tau,", "And when ye had girded on every man his weapons of war,"], ["ua oso vale foi outou e o ae i le mauga.", "ye were ready to go up into the hill."]]},
  {num:42,words:[["Ona fetalai mai ai lea o Ieova ia te au,", "And the LORD said unto me,"], ["Ia e fai atu ia te i latou,", "Say unto them,"], ["Aua tou te o ae, aua tou te sii atu le taua,", "Go not up,"], ["auā o a'u,", "neither fight;"], ["ou te le i ai ia te outou;", "for I am not among you;"], ["ne'i fasia outou i luma o e ua ita mai ia te outou.", "lest ye be smitten before your enemies."]]},
  {num:43,words:[["Ona ou fai atu ai lea ia te outou,", "So I spake unto you;"], ["a ua outou le faalogo mai lava,", "and ye would not hear,"], ["a ua outou fouvale i le afioga a Ieova, na outou faamaualuga,", "but rebelled against the commandment of the LORD,"], ["ma outou o ae i le mauga.", "and went presumptuously up into the hill."]]},
  {num:44,words:[["Ona o mai ai lea o sa Amorī,", "And the Amorites,"], ["sa nonofo i lea mauga,", "which dwelt in that mountain,"], ["e faafetaiai ia te outou,", "came out against you, and chased you,"], ["na latou tuliloa foi ia te outou,", "as bees do,"], ["e pei ona faia e lagomeli,", "and destroyed you in Seir,"], ["ua latou fafasi ia te outou i Seira e oo atu i Horema.", "even unto Hormah."]]},
  {num:45,words:[["Ona outou toe fai mai lea,", "And ye returned and wept before the LORD;"], ["ma outou fetagisi i luma o Ieova, a ua le faafofogaina mai e Ieova o a outou upu,", "but the LORD would not hearken to your voice,"], ["ua le liliu mai foi ona fofoga ia te outou.", "nor give ear unto you."]]},
  {num:46,words:[["Ona outou nonofo ai lea i Katesa i aso e tele,", "So ye abode in Kadesh many days,"], ["o ona aso lava na outou nonofo ai.", "according unto the days that ye abode there."]]},
];
renderVerseSet(deu_ch_1_Verses, 'deu-ch1-verses');

var deu_ch_2_Verses = [
  {num:1,words:[["Ona tatou liliu ane lea,", "Then we turned,"], ["ma tatou o atu i le vao i le ala i le sami Ulaula,", "and took our journey into the wilderness by the way of the Red sea,"], ["e pei ona fetalai mai o Ieova ia te au;", "as the LORD spake unto me:"], ["e tele lava aso ua tatou siosio ai le mauga o Seira.", "and we compassed mount Seir many days."]]},
  {num:2,words:[["Ona fetalai mai lea o Ieova ia te au,", "And the LORD spake unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:3,words:[["Ua leva ona outou siosioina lenei mauga,", "Ye have compassed this mountain long enough:"], ["ia outou liliu ane i le itu i matu.", "turn you northward."]]},
  {num:4,words:[["Ia e fai atu i le nuu,", "And command thou the people,"], ["ia faapea atu,", "saying,"], ["O le a outou ui ane i le tuaoi o outou uso, o le fanauga a Esau,", "Ye are to pass through the coast of your brethren the children of Esau,"], ["o e nonofo i Seira,", "which dwell in Seir;"], ["latou te matatau ia te outou,", "and they shall be afraid of you:"], ["ia outou lava;", "take ye good heed unto yourselves therefore:"]]},
  {num:5,words:[["aua ne'i outou tau ma i latou,", "Meddle not with them;"], ["auā ou te le avatu ia te outou sina o latou fasi fanua,", "for I will not give you of their land,"], ["e leai sina mea e tusa ma se tulagāvae,", "no,"], ["auā ua ou avatu le mauga o Seira,", "not so much as a foot breadth;"], ["o le tofi lea o Esau.", "because I have given mount Seir unto Esau for a possession."]]},
  {num:6,words:[["Tou te faatau mea e 'ai mai ia te i latou i tupe,", "Ye shall buy meat of them for money,"], ["tou te aai ai,", "that ye may eat;"], ["o le vai foi tou te faatau mai ai ia te i latou i tupe,", "and ye shall also buy water of them for money,"], ["tou te inu ai.", "that ye may drink."]]},
  {num:7,words:[["Auā ua faamanuia oe e Ieova lou Atua i galuega uma a ou lima;", "For the LORD thy God hath blessed thee in all the works of thy hand:"], ["ua na silafia lou savaliga i lenei vao tele,", "he knoweth thy walking through this great wilderness:"], ["na ia te oe Ieova lou Atua i ona tausaga e fagafulu;", "these forty years the LORD thy God hath been with thee;"], ["e leai lava se mea na e mativa ai.", "thou hast lacked nothing."]]},
  {num:8,words:[["Na tatou o ane nai o tatou uso le fanauga a Esau,", "And when we passed by from our brethren the children of Esau,"], ["o e ua nonofo i Seira,", "which dwelt in Seir,"], ["i le ala i le eleele laugatasi nai Elata ma Esiokape,", "through the way of the plain from Elath,"], ["ona tatou liliu lea,", "and from Ezion-gaber,"], ["ma o ane i le ala i le vao o Moapi.", "we turned and passed by the way of the wilderness of Moab."]]},
  {num:9,words:[["Ona fetalai mai lea o Ieova ia te au,", "And the LORD said unto me,"], ["Aua e te faasaua atu ia Moapi,", "Distress not the Moabites,"], ["aua foi e te tau ai se taua ma i latou;", "neither contend with them in battle:"], ["auā ou te le avatua ia te oe sina ona fasi fanua e fai mou,", "for I will not give thee of their land for a possession;"], ["auā ua ou avatu Aro i le fanauga a Lota e fai mo latou.", "because I have given Ar unto the children of Lot for a possession."]]},
  {num:10,words:[["Sa nonofo ai sa Ememā anamua,", "The Emims dwelt therein in times past, a people great,"], ["o le nuu lea e malolosi ma le toatele,", "and many,"], ["e maualuluga foi e pei o sa Anakī.", "and tall, as the Anakims;"]]},
  {num:11,words:[["Ua ta'ua foi i latou o tagata maualuluga,", "Which also were accounted giants,"], ["e pei o sa Anakī,", "as the Anakims;"], ["a ua faaigoaina i latou o Emema e sa Moapī.", "but the Moabites call them Emims."]]},
  {num:12,words:[["Sa nonofo foi o sa Horī i Seira anamua,", "The Horims also dwelt in Seir beforetime;"], ["a ua tulia i latou e le fanauga a Esau,", "but the children of Esau succeeded them,"], ["ma latou faaumatia i latou ai o latou luma,", "when they had destroyed them from before them,"], ["ma nonofo i le mea sa i ai i latou,", "and dwelt in their stead;"], ["e pei ona faia e Isaraelu i le nuu ua fai mona tofi,", "as Israel did unto the land of his possession,"], ["ua foaiina e Ieova ia te i latou.", "which the LORD gave unto them."]]},
  {num:13,words:[["O lenei,", "Now rise up,"], ["ina tutū ia outou,", "said I,"], ["ma sopoia atu le alia o Sareta. Ona tatou sopoia lea o le alia o Sareta.", "and get you over the brook Zered. And we went over the brook Zered."]]},
  {num:14,words:[["O ona aso na tatou savavali ai nai Katesapanea,", "And the space in which we came from Kadesh-barnea,"], ["ua oo ina sopoia atu o le alia o Sareta,", "until we were come over the brook Zered,"], ["e tolu sefulu ma le valu o ona tausaga ia;", "was thirty and eight years;"], ["ua oo ina faaumatia o lea tupulaga o tagata tau ai le toagālauapi,", "until all the generation of the men of war were wasted out from among the host,"], ["e pei ona tauto ai o Ieova ia te i latou.", "as the LORD sware unto them."]]},
  {num:15,words:[["Auā ua oo ia te i latou le aao o Ieova e faauma ai ia i latou ai le toagālauapi,", "For indeed the hand of the LORD was against them, to destroy them from among the host,"], ["ua oo ina faaumatia i latou.", "until they were consumed."]]},
  {num:16,words:[["Ua iu foi ina ua faaumatia i le oti o tagata tau uma lava ai le nuu,", "So it came to pass, when all the men of war were consumed and dead from among the people,"]]},
  {num:17,words:[["ona fetalai mai ai lea o Ieova ia te au,", "That the LORD spake unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:18,words:[["O le aso nei e te ui ane ai i Aro o le tuaoi o Moapi;", "Thou art to pass over through Ar, the coast of Moab, this day:"]]},
  {num:19,words:[["a e faalatalata atu foi e feagai ma le fanauga a Amoni,", "And when thou comest nigh over against the children of Ammon,"], ["aua ne'i e faasaua ia i latou,", "distress them not,"], ["aua foi e te tau ma i latou,", "nor meddle with them:"], ["auā ou te le avatu ia te oe sina fasi fanua o le fanauga a Amoni e fai mou,", "for I will not give thee of the land of the children of Ammon any possession;"], ["auā ua ou avatu ai i le fanauga a Lota e fai mo latou.", "because I have given it unto the children of Lot for a possession."]]},
  {num:20,words:[["Na ta'ua foi lea o le nuu o tagata maualuluga,", "(That also was accounted a land of giants:"], ["sa nonofo ai tagata maualuluga anamua,", "giants dwelt therein in old time;"], ["ua faaigoaina foi i latou e sa Amonī o Samasuma;", "and the Ammonites call them Zamzummims;"]]},
  {num:21,words:[["o le nuu lea e malolosi ma le toatele,", "A people great,"], ["e maualuluga foi e pei o sa Anakī;", "and many, and tall,"], ["a ua faaumatia i latou e Ieova ai o latou luma,", "as the Anakims;"], ["na latou tulia foi i latou,", "but the LORD destroyed them before them; and they succeeded them,"], ["ma latou nonofo i le mea sa i ai i latou;", "and dwelt in their stead:"]]},
  {num:22,words:[["e pei ona faia e ia i le fanauga a Esau e ua nonofo i Seira,", "As he did to the children of Esau,"], ["ina ua faaumatia e ia o sa Horī ai o latou luma,", "which dwelt in Seir,"], ["ua latou tulia i latou,", "when he destroyed the Horims from before them;"], ["ma latou nonofo i le mea sa latou i ai,", "and they succeeded them,"], ["ua oo mai lava i nei ona po.", "and dwelt in their stead even unto this day:"]]},
  {num:23,words:[["O sa Gavī foi sa nonofo i Haserima e oo atu i Kasa,", "And the Avims which dwelt in Hazerim, even unto Azzah,"], ["o sa Kafatorī na o mai mai Kafatori ua faaumatia i latou,", "the Caphtorims, which came forth out of Caphtor,"], ["ma ua latou nonofo i le mea sa i ai i latou.", "destroyed them, and dwelt in their stead.)"]]},
  {num:24,words:[["Ina tutū ia outou,", "Rise ye up,"], ["o atu ia,", "take your journey,"], ["ma sopoia atu le alia o Arinona;", "and pass over the river Arnon:"], ["faauta,", "behold,"], ["ua ou tuuina i lou lima o Sekono le tupu o Hesepona o le sa Amorī,", "I have given into thine hand Sihon the Amorite, king of Heshbon,"], ["ma lona fanua,", "and his land:"], ["ia e amata nei lava ona fai mou,", "begin to possess it,"], ["i le e tau ai le taua mai ia.", "and contend with him in battle."]]},
  {num:25,words:[["O le aso nei e amata ai ona ou faaoo atu le mata'u,", "This day will I begin to put the dread of thee and the fear of thee upon the nations that are under the whole heaven,"], ["ma le atuatuvale ona o oe i nuu o i le lalolagi uma,", "who shall hear report of thee,"], ["e lagona e i latou se tala ia te oe, ma latou gatete,", "and shall tremble,"], ["ma faavaivai i ou luma.", "and be in anguish because of thee."]]},
  {num:26,words:[["Ona ou aauina atu lea o le sāvali ai le vao o Katemoti ia Sekono le tupu o Hesepona, ma upu o le filemu,", "And I sent messengers out of the wilderness of Kedemoth unto Sihon king of Heshbon with words of peace,"], ["ua faapea atu ai,", "saying,"]]},
  {num:27,words:[["Se'i ou ui atu i lou nuu,", "Let me pass through thy land:"], ["o le ala tele ou te savali ai, ou te le liliu ane i le itu taumatau,", "I will go along by the high way,"], ["po o le itu tauagavale.", "I will neither turn unto the right hand nor to the left."]]},
  {num:28,words:[["E te faatauina mai mea e 'ai i tupe,", "Thou shalt sell me meat for money,"], ["ou te 'ai ai,", "that I may eat;"], ["e te au mai foi ni vai i tupe,", "and give me water for money,"], ["ou te inu ai,", "that I may drink:"], ["na ona ui atu lava ou vae.", "only I will pass through on my feet;"]]},
  {num:29,words:[["E pei ona faia ia te au e le fanauga a Esau,", "(As the children of Esau which dwell in Seir,"], ["e ua nonofo i Seira,", "and the Moabites which dwell in Ar,"], ["ma sa Moapī e ua nonofo i Aro, seia ou sopoia atu Ioritana,", "did unto me;"], ["i le nuu ua foaiina mai ia te i matou e Ieova lo matou Atua.", ") until I shall pass over Jordan into the land which the LORD our God giveth us."]]},
  {num:30,words:[["A ua le mafai Sekono le tupu o Hesepona ona tatou ui ane i ai;", "But Sihon king of Heshbon would not let us pass by him:"], ["auā na faamaaa e Ieova lou Atua lona loto,", "for the LORD thy God hardened his spirit,"], ["ma ua faafinauvaleina o ia,", "and made his heart obstinate,"], ["ina ia tuuina atu o ia i lou lima,", "that he might deliver him into thy hand,"], ["e pei ona faia i le aso nei.", "as appeareth this day."]]},
  {num:31,words:[["Ona fetalai mai lea o Ieova ia te au,", "And the LORD said unto me,"], ["Faauta,", "Behold,"], ["ua ou tuuina atu nei lava o Sekono ma lona nuu ia te oe,", "I have begun to give Sihon and his land before thee: begin to possess,"], ["ia e fai nei lava mou lona nuu.", "that thou mayest inherit his land."]]},
  {num:32,words:[["Ona latou o mai lea o Sekono ma lona nuu uma e faafetaiai ia i tatou e tau ai le taua i Iaesa;", "Then Sihon came out against us, he and all his people, to fight at Jahaz."]]},
  {num:33,words:[["na tuuina mai foi i latou e Ieova lo tatou Atua ia te i tatou,", "And the LORD our God delivered him before us;"], ["ona tatou fafasi ai lea ia te ia,", "and we smote him,"], ["ma ona atalii,", "and his sons,"], ["atoa ma lona nuu uma.", "and all his people."]]},
  {num:34,words:[["Ona tatou aea ai lea ona aai uma lava i ia ona po,", "And we took all his cities at that time,"], ["ma tatou faaumatia o tane,", "and utterly destroyed the men,"], ["ma fafine,", "and the women, and the little ones,"], ["ma tama iti i aai uma lava,", "of every city,"], ["ua leai se tasi na tatou faatoeina;", "we left none to remain:"]]},
  {num:35,words:[["na o manu na ave ma tatou,", "Only the cattle we took for a prey unto ourselves,"], ["atoa ma vete i aai na tatou faoa.", "and the spoil of the cities which we took."]]},
  {num:36,words:[["E afua mai i Aroeru,", "From Aroer,"], ["o i le auvai o le alia o Arinona,", "which is by the brink of the river of Arnon,"], ["ma le aai i le alia,", "and from the city that is by the river,"], ["ua oo atu i Kiliata,", "even unto Gilead,"], ["e leai lava se aai na sili lo latou malosi i lo tatou,", "there was not one city too strong for us:"], ["ua foaiina mai uma e Ieova lo tatou Atua ia te i tatou.", "the LORD our God delivered all unto us:"]]},
  {num:37,words:[["Na o le nuu o le fanauga a Amoni ua e le oo i ai,", "Only unto the land of the children of Ammon thou camest not,"], ["o se mea e tasi e latalata ane i le alia o Iapoka,", "nor unto any place of the river Jabbok,"], ["po o aai o i mauga,", "nor unto the cities in the mountains,"], ["po o se mea na vavao mai ai e Ieova lo tatou Atua.", "nor unto whatsoever the LORD our God forbad us."]]},
];
renderVerseSet(deu_ch_2_Verses, 'deu-ch2-verses');

var deu_ch_3_Verses = [
  {num:1,words:[["Ona tatou liliu ane lea,", "Then we turned,"], ["ma tatou o ae i le ala i Vasana,", "and went up the way to Bashan:"], ["ona latou o mai lea,", "and Og the king of Bashan came out against us,"], ["o Oko le tupu o Vasana,", "he and all his people,"], ["o ia ma lona nuu uma lava e faafetaiai ia te i tatou e tau ai le taua i Eterei.", "to battle at Edrei."]]},
  {num:2,words:[["A ua fetalai mai Ieova ia te au,", "And the LORD said unto me,"], ["Aua e te mata'u ia te ia,", "Fear him not:"], ["auā ua ou tuuina atu i lou lima o ia,", "for I will deliver him,"], ["ma lona nuu uma,", "and all his people, and his land,"], ["atoa ma lona laueleele;", "into thy hand;"], ["e te faia ia te ia e pei ona e faia ia Sekono le tupu o sa Amorī,", "and thou shalt do unto him as thou didst unto Sihon king of the Amorites,"], ["o le sa nofo i Hesepona.", "which dwelt at Heshbon."]]},
  {num:3,words:[["Ona tuuina mai ai lea e Ieova lo tatou Atua i o tatou lima o Oko le tupu o Vasana,", "So the LORD our God delivered into our hands Og also,"], ["ma lona nuu uma lava,", "the king of Bashan,"], ["ona tatou fafasi ai lea ia te i latou,", "and all his people:"], ["na le toe lava se toatasi ia te ia.", "and we smote him until none was left to him remaining."]]},
  {num:4,words:[["Na tatou aea foi ona aai uma lava i ia ona po,", "And we took all his cities at that time,"], ["e leai so latou aai na le aea e i tatou,", "there was not a city which we took not from them,"], ["o aai e onogafulu,", "threescore cities, all the region of Argob,"], ["o le itu uma o Arakopo na pule ai Oko i Vasana.", "the kingdom of Og in Bashan."]]},
  {num:5,words:[["O aai uma lava ia ua puipuia i pa maualuluga,", "All these cities were fenced with high walls,"], ["o puipui ua fai ma faamau faalava;", "gates, and bars;"], ["atoa ma faoa aai e tele lava.", "beside unwalled towns a great many."]]},
  {num:6,words:[["Ona tatou faaumatia lea i latou,", "And we utterly destroyed them,"], ["e pei ona tatou faia ia Sekono le tupu o Hesepona,", "as we did unto Sihon king of Heshbon,"], ["na tatou faaumatia o tane,", "utterly destroying the men, women,"], ["o fafine,", "and children,"], ["ma tama iti i aai uma lava.", "of every city."]]},
  {num:7,words:[["A o manu uma,", "But all the cattle,"], ["ma oloa o aai,", "and the spoil of the cities,"], ["ua tatou vetea mā tatou.", "we took for a prey to ourselves."]]},
  {num:8,words:[["O ia ona aso foi na tatou faoa ai le laueleele nai lima o tupu e toalua o sa Amorī, ua i le itu mai o Ioritana,", "And we took at that time out of the hand of the two kings of the Amorites the land that was on this side Jordan,"], ["e afua mai i le alia o Arinona, ua oo atu lava i le mauga o Heremoni,", "from the river of Arnon unto mount Hermon;"]]},
  {num:9,words:[["(na igoa Heremoni e tagata o Saitonu,", "(Which Hermon the Sidonians call Sirion;"], ["o Siriona, a ua igoa e sa Amorī,", "and the Amorites call it Shenir;"], ["o Senira);", ")"]]},
  {num:10,words:[["o aai uma lava i le eleele laugatasi,", "All the cities of the plain,"], ["ma Kiliata uma,", "and all Gilead,"], ["ma Vasana uma ua oo atu i Saleka ma Eterei,", "and all Bashan, unto Salchah and Edrei,"], ["o aai i nuu na pule ai Oko i Vasana.", "cities of the kingdom of Og in Bashan."]]},
  {num:11,words:[["Auā ua na o Oko le tupu o Vasana,", "For only Og king of Bashan remained of the remnant of giants;"], ["na toe i tagata maualuluga; faauta i lona moega,", "behold,"], ["o le moega uamea,", "his bedstead was a bedstead of iron;"], ["e le o loo i Rapa ea,", "is it not in Rabbath of the children of Ammon? nine cubits was the length thereof,"], ["o le aai o le fanauga a Amoni? E iva kupita o lona umi lea, e fa kupita o lona lautele lea,", "and four cubits the breadth of it,"], ["o le kupita o le tagata lea.", "after the cubit of a man."]]},
  {num:12,words:[["O le nuu lea sa fai mo i tatou i ia ona po,", "And this land,"], ["e pau mai i Aroeru e lata ane i le alia o Arinona,", "which we possessed at that time, from Aroer,"], ["ma le tasi itu o le mauga o Kiliata,", "which is by the river Arnon,"], ["ma ona aai ua ou foaiina atu i sa Reupenā,", "and half mount Gilead, and the cities thereof,"], ["ma sa Katō.", "gave I unto the Reubenites and to the Gadites."]]},
  {num:13,words:[["O le toe itu o Kiliata,", "And the rest of Gilead,"], ["ma Vasana uma,", "and all Bashan,"], ["na pule ai Oko,", "being the kingdom of Og,"], ["ua ou foaiina atu ai i le vaega o le itu aiga o Manase;", "gave I unto the half tribe of Manasseh;"], ["o le itu uma o Arakopo,", "all the region of Argob,"], ["o Vasana uma lava,", "with all Bashan,"], ["sa ta'ua o le nuu o tagata maualuluga.", "which was called the land of giants."]]},
  {num:14,words:[["O Iairo le atalii o Manase ua na faoa le itu uma o Arakopo, ua oo atu i le tuaoi o Kasuri,", "Jair the son of Manasseh took all the country of Argob unto the coasts of Geshuri and Maachathi;"], ["ma Maaka,", "and called them after his own name,"], ["ua na faaigoaina ai i lona lava igoa,", "Bashan-havoth-jair,"], ["o Vasanahavota-Iairo, ua oo i nei ona po.", "unto this day."]]},
  {num:15,words:[["Ua ou foaiina atu foi Kiliata ia Makiro;", "And I gave Gilead unto Machir."]]},
  {num:16,words:[["ua ou foaiina atu foi i sa Reupenā, ma sa Katō, e afua mai i Kiliata,", "And unto the Reubenites and unto the Gadites I gave from Gilead even unto the river Arnon half the valley,"], ["ua oo atu i le alia o Arinona, o i totonu lava o le alia,", "and the border even unto the river Jabbok,"], ["ma le tuaoi; ua oo atu lava i le alia o Iapoka, o le tuaoi lea o le fanauga a Amoni.", "which is the border of the children of Ammon;"]]},
  {num:17,words:[["O le eleele laugatasi foi,", "The plain also,"], ["ma Ioritana,", "and Jordan,"], ["ma ona itu,", "and the coast thereof,"], ["e afua mai i Kinereta,", "from Chinnereth even unto the sea of the plain,"], ["e pau mai i le sami o i le eleele laugatasi,", "even the salt sea,"], ["o le sami oona lea i lalo o Asetotapeseka i le itu i sasae.", "under Ashdoth-pisgah eastward."]]},
  {num:18,words:[["O ia ona po na ou fai atu ai ia te outou,", "And I commanded you at that time,"], ["ua faapea atu,", "saying,"], ["Ua foai mai ia te outou e Ieova lo outou Atua lenei nuu e fai mo outou;", "The LORD your God hath given you this land to possess it:"], ["o outou uma o e malolosi,", "ye shall pass over armed before your brethren the children of Israel,"], ["tou te o atu o sauni i le taua i luma o outou au uso le fanauga a Isaraelu.", "all that are meet for the war."]]},
  {num:19,words:[["A o a outou avā,", "But your wives,"], ["ma a outou tama iti,", "and your little ones,"], ["ma a outou manu,", "and your cattle,"], ["auā ua ou iloa ua tele a outou manu,", "(for I know that ye have much cattle,"], ["ia latou nonofo i o outou aai ua ou avatua ia te outou;", ") shall abide in your cities which I have given you;"]]},
  {num:20,words:[["seia avatua e Ieova le mapusaga i o outou uso,", "Until the LORD have given rest unto your brethren,"], ["e pei o outou na lava,", "as well as unto you,"], ["seia fai foi mo i latou le nuu o i ona tala atu o Ioritana, ua foaiina atu ia te i latou e Ieova lo outou Atua;", "and until they also possess the land which the LORD your God hath given them beyond Jordan:"], ["ona toe o mai ai lea o outou,", "and then shall ye return every man unto his possession,"], ["e taitasi i lona tofi ua ou avatua ia te outou.", "which I have given you."]]},
  {num:21,words:[["O ia ona po na ou fai atu ai ia Iosua,", "And I commanded Joshua at that time,"], ["ua faapea atu,", "saying,"], ["Na e iloa atu i ou lava mata i mea uma lava na faia e Ieova lo outou Atua i na tupu e toalua, e faapea foi ona faia e Ieova i malo uma lava,", "Thine eyes have seen all that the LORD your God hath done unto these two kings:"], ["o le a e alu atu i ai.", "so shall the LORD do unto all the kingdoms whither thou passest."]]},
  {num:22,words:[["Aua tou te matatau ia i latou, auā o Ieova lo outou Atua,", "Ye shall not fear them:"], ["o ia e tau mo outou.", "for the LORD your God he shall fight for you."]]},
  {num:23,words:[["O ia ona po na ou aioi atu ai ia Ieova,", "And I besought the LORD at that time,"], ["ua faapea atu,", "saying,"]]},
  {num:24,words:[["Le Alii e,", "O Lord GOD,"], ["Ieova,", "thou hast begun to shew thy servant thy greatness,"], ["ua e amataina ona faaalia mai i lau auauna o lou silisili ese ma lou aao malosi,", "and thy mighty hand:"], ["auā o ai se Atua o i le lagi,", "for what God is there in heaven or in earth,"], ["po o le lalolagi na te mafaia ona fai o mea e pei ona e faia,", "that can do according to thy works,"], ["e tusa foi ma lou malosi?", "and according to thy might?"]]},
  {num:25,words:[["Ou te aioi atu ia te oe se'i ou alu atu ou te matamata ai i le nuu lelei o i tala atu o Ioritana,", "I pray thee, let me go over,"], ["o lena mauga lelei,", "and see the good land that is beyond Jordan,"], ["ma Lepanona.", "that goodly mountain, and Lebanon."]]},
  {num:26,words:[["A ua toasa mai Ieova ia te au ona o outou,", "But the LORD was wroth with me for your sakes,"], ["ma ua na le faafofoga mai ia te au,", "and would not hear me:"], ["a ua fetalai mai Ieova ia te au,", "and the LORD said unto me,"], ["Soia,", "Let it suffice thee;"], ["aua lava e te toe fai mai se upu ia te au i lea mea.", "speak no more unto me of this matter."]]},
  {num:27,words:[["Alu ae ia oe i le tumutumu o Peseka,", "Get thee up into the top of Pisgah,"], ["ma e vaai i le itu i sisifo,", "and lift up thine eyes westward,"], ["ma le itu i matu,", "and northward,"], ["ma le itu i toga,", "and southward,"], ["ma le itu i sasae,", "and eastward,"], ["ma ia e iloa ai i ou mata;", "and behold it with thine eyes:"], ["auā e te le sopoia atu lena Ioritana.", "for thou shalt not go over this Jordan."]]},
  {num:28,words:[["A ia e poloai atu ia Iosua,", "But charge Joshua,"], ["ma e faamafanafana,", "and encourage him,"], ["ma faamalosi ia te ia,", "and strengthen him:"], ["auā o ia e alu atu lava i luma o le nuu nei,", "for he shall go over before this people,"], ["o ia na te tofia mo i latou le nuu e te vaaia.", "and he shall cause them to inherit the land which thou shalt see."]]},
  {num:29,words:[["Ona tatou nonofo ai lea i le vanu e feagai ma Petepeoro.", "So we abode in the valley over against Beth-peor."]]},
];
renderVerseSet(deu_ch_3_Verses, 'deu-ch3-verses');

var deu_ch_4_Verses = [
  {num:1,words:[["O lenei,", "Now therefore hearken,"], ["Isaraelu e,", "O Israel,"], ["faalogologo mai ia i tulafono ma faamasinoga ou te a'oa'o atu ai ia te outou tou te faia,", "unto the statutes and unto the judgments, which I teach you,"], ["ina ia outou ola ai,", "for to do them,"], ["ina ia outou o atu ai foi,", "that ye may live,"], ["ma fai mo outou le nuu ua foaiina atu ia te outou e Ieova le Atua o outou tamā.", "and go in and possess the land which the LORD God of your fathers giveth you."]]},
  {num:2,words:[["Aua tou te faaopoopo se upu i upu ou te fai atu ai ia te outou,", "Ye shall not add unto the word which I command you,"], ["aua foi tou te aveeseina ai se upu ;", "neither shall ye diminish ought from it,"], ["ina ia outou tausiusi i poloaiga a Ieova lo outou Atua ou te fai atu ai ia te outou.", "that ye may keep the commandments of the LORD your God which I command you."]]},
  {num:3,words:[["Ua outou iloa i o outou mata le mea na faia e Ieova ona o Paalapeoro,", "Your eyes have seen what the LORD did because of Baal-peor: for all the men that followed Baal-peor,"], ["auā o tagata uma lava na mulimuli atu ia Paalapeoro ua faaumatia i latou nai ia te oe e Ieova lou Atua.", "the LORD thy God hath destroyed them from among you."]]},
  {num:4,words:[["A o outou e na pipii atu ia Ieova lo outou Atua, o loo ola mai outou uma i le aso nei.", "But ye that did cleave unto the LORD your God are alive every one of you this day."]]},
  {num:5,words:[["Faauta,", "Behold,"], ["na ou a'oa'o atu ia te outou i tulafono ma faamasinoga e pei ona poloai mai ai ia te au e Ieova lo'u Atua,", "I have taught you statutes and judgments, even as the LORD my God commanded me,"], ["ina ia outou faia faapea i le nuu tou te o atu ai e fai mo outou.", "that ye should do so in the land whither ye go to possess it."]]},
  {num:6,words:[["O lenei,", "Keep therefore and do them;"], ["ia outou tausiusi i ai , ma ia outou faia,", "for this is your wisdom and your understanding in the sight of the nations,"], ["auā o le mea lea tou te popoto ai,", "which shall hear all these statutes,"], ["ma atamamai ai i luma o nuu e faalogologo i nei tulafono uma; ona faapea ane lea,", "and say,"], ["E moni lava o le nuu popoto ma le atamamai lenei nuu mamalu.", "Surely this great nation is a wise and understanding people."]]},
  {num:7,words:[["Auā o ifea se nuu mamalu ua latalata i ai lo latou atua,", "For what nation is there so great, who hath God so nigh unto them,"], ["e pei o Ieova lo tatou Atua ua latalata mai i mea uma lava ua tatou valaau atu ai ia te ia?", "as the LORD our God is in all things that we call upon him for?"]]},
  {num:8,words:[["O ifea foi se nuu mamalu e i ai tulafono ma faamasinoga tonu,", "And what nation is there so great, that hath statutes and judgments so righteous as all this law,"], ["e pei o lenei tulafono uma ua ou tuuina atu ia te outou i le aso nei?", "which I set before you this day?"]]},
  {num:9,words:[["Tau ina faaeteete oe ia te oe,", "Only take heed to thyself,"], ["ma ia e matuā faaeteete lava ia te oe,", "and keep thy soul diligently,"], ["ne'i galo ia te oe nei mea na iloa ai e ou mata,", "lest thou forget the things which thine eyes have seen,"], ["ne'i te'a ese ai lou loto i aso uma o lou olaga,", "and lest they depart from thy heart all the days of thy life:"], ["a ia e faailoa atu i lau fanau,", "but teach them thy sons,"], ["ma le fanau a lau fanau;", "and thy sons' sons;"]]},
  {num:10,words:[["faailoa atu le aso na e tu ai i luma o Ieova lou Atua i Horepa,", "Specially the day that thou stoodest before the LORD thy God in Horeb,"], ["ina o fetalai mai Ieova ia te au,", "when the LORD said unto me,"], ["Ina faapotopoto mai ia ia te au le nuu, ia latou faalogologo mai i a'u upu,", "Gather me the people together,"], ["ina ia a'oa'oina ai i latou,", "and I will make them hear my words,"], ["ina ia matatau mai ia te au i aso uma lava latou te ola ai i le fogāeleele,", "that they may learn to fear me all the days that they shall live upon the earth,"], ["ma ia latou a'oa'o ai i a latou fanau.", "and that they may teach their children."]]},
  {num:11,words:[["Ona outou faalatalata atu lea ma tutū i lalo o le mauga,", "And ye came near and stood under the mountain;"], ["na mu foi le mauga i le afi,", "and the mountain burned with fire unto the midst of heaven,"], ["ua oo lava i le lagi; sa i ai foi le pouliuli,", "with darkness,"], ["ma ao,", "clouds,"], ["ma le pogasi.", "and thick darkness."]]},
  {num:12,words:[["Ona fetalai mai lea o Ieova ia te outou mai totonu o le afi,", "And the LORD spake unto you out of the midst of the fire:"], ["ua outou faalogologo i le siufofoga,", "ye heard the voice of the words,"], ["a ua outou le iloa atu se mea e tino a'i mai,", "but saw no similitude;"], ["na o le siufofoga lava.", "only ye heard a voice."]]},
  {num:13,words:[["Ua na faaalia foi ia te outou lana feagaiga na ia poloai mai ai ia te outou tou te faia,", "And he declared unto you his covenant,"], ["o upu ia e sefulu;", "which he commanded you to perform, even ten commandments;"], ["na ia tusi ai foi i luga o papamaa e lua.", "and he wrote them upon two tables of stone."]]},
  {num:14,words:[["Na poloai mai foi Ieova ia te au i ia ona po,", "And the LORD commanded me at that time to teach you statutes and judgments,"], ["e a'oa'o atu ia te outou i tulafono ma faamasinoga tou te faia i le nuu tou te o atu i ai e fai mo outou.", "that ye might do them in the land whither ye go over to possess it."]]},
  {num:15,words:[["O lenei, ia matuā faaeteete outou ia te outou,", "Take ye therefore good heed unto yourselves;"], ["auā na outou le iloa lava se mea na tino a'i mai i le aso na fetalai mai ai Ieova ia te outou i Horepa ai totonu o le afi.", "for ye saw no manner of similitude on the day that the LORD spake unto you in Horeb out of the midst of the fire:"]]},
  {num:16,words:[["Ne'i leaga outou ia te outou ,", "Lest ye corrupt yourselves,"], ["ma outou faia mo outou se tupua ua ta,", "and make you a graven image,"], ["o le faatusa o se tupua e tasi, o le faatusa o se tane,", "the similitude of any figure,"], ["po o se fafine;", "the likeness of male or female,"]]},
  {num:17,words:[["o se faatusa o se tasi manu e tataa,", "The likeness of any beast that is on the earth,"], ["o se faatusa o se manu lele e lele i lugā,", "the likeness of any winged fowl that flieth in the air,"]]},
  {num:18,words:[["o se faatusa o se tasi mea e totolo i le eleele,", "The likeness of any thing that creepeth on the ground,"], ["po o se faatusa o se tasi i'a o i le sami i lalo o le laueleele;", "the likeness of any fish that is in the waters beneath the earth:"]]},
  {num:19,words:[["ne'i tepa ae foi ou mata i le lagi,", "And lest thou lift up thine eyes unto heaven,"], ["ma e iloa le la,", "and when thou seest the sun,"], ["ma le masina,", "and the moon,"], ["ma fetu,", "and the stars,"], ["o 'au uma o le lagi,", "even all the host of heaven,"], ["ne'i tosina ai oe e ifo i ai,", "shouldest be driven to worship them,"], ["ma auauna i ai,", "and serve them,"], ["o mea ia na tofia mai e Ieova lou Atua i nuu uma o le lalolagi.", "which the LORD thy God hath divided unto all nations under the whole heaven."]]},
  {num:20,words:[["Auā na ave outou e Ieova,", "But the LORD hath taken you,"], ["ma na aumaia outou ai le ogaumu e tunu ai uamea,", "and brought you forth out of the iron furnace,"], ["nai Aikupito lava,", "even out of Egypt,"], ["ina ia avea ma nuu e fai mona tofi,", "to be unto him a people of inheritance,"], ["pei ona fai i le aso nei.", "as ye are this day."]]},
  {num:21,words:[["Na toasa mai foi Ieova ia te au ona o a outou upu,", "Furthermore the LORD was angry with me for your sakes,"], ["ma na tauto ai ou te le sopoia atu Ioritana,", "and sware that I should not go over Jordan,"], ["ou te le alu atu foi i le nuu lelei,", "and that I should not go in unto that good land,"], ["o le a foai atu ia te oe e Ieova lou Atua e fai mou tofi.", "which the LORD thy God giveth thee for an inheritance:"]]},
  {num:22,words:[["Auā e oti a'u i le nuu nei,", "But I must die in this land,"], ["ou te le sopoia atu Ioritana;", "I must not go over Jordan:"], ["a o outou, tou te sopoia atu,", "but ye shall go over,"], ["ma fai mo outou lena nuu lelei.", "and possess that good land."]]},
  {num:23,words:[["Ia outou lava,", "Take heed unto yourselves, lest ye forget the covenant of the LORD your God,"], ["ne'i galo ia te outou le feagaiga a Ieova lo outou Atua na ia osia ma outou,", "which he made with you,"], ["ona outou fai lea mo outou se tupua ua ta,", "and make you a graven image,"], ["o le faatusa lava o se mea e tasi ua vaoia mai ai e Ieova lou Atua.", "or the likeness of any thing, which the LORD thy God hath forbidden thee."]]},
  {num:24,words:[["Auā o Ieova lou Atua o le afi maamaai ia,", "For the LORD thy God is a consuming fire,"], ["o le Atua fuā ia.", "even a jealous God."]]},
  {num:25,words:[["A oo ina fai o lau fanau,", "When thou shalt beget children,"], ["ma ni fanau a lau fanau,", "and children's children,"], ["a loa foi ona outou mau i le nuu,", "and ye shall have remained long in the land,"], ["a leaga outou ia te outou ,", "and shall corrupt yourselves,"], ["a outou faia se tupua ua ta,", "and make a graven image,"], ["o se faatusa o se mea e tasi,", "or the likeness of any thing,"], ["ma faia mea leaga i luma o Ieova lou Atua,", "and shall do evil in the sight of the LORD thy God,"], ["e faaonoono ai ia te ia;", "to provoke him to anger:"]]},
  {num:26,words:[["ou te valaau atu i le aso nei i le lagi, ma le lalolagi,", "I call heaven and earth to witness against you this day,"], ["e fai ma molimau ia te outou,", "that ye shall soon utterly perish from off the land whereunto ye go over Jordan to possess it;"], ["e vave ona matuā fano outou ai le nuu tou te sopoia atu ai Ioritana e fai mo outou;", "ye shall not prolong your days upon it,"], ["tou te le nofo tulu'i ai, a e matuā faaumatia outou.", "but shall utterly be destroyed."]]},
  {num:27,words:[["E faataapeape e Ieova ia te outou i nuu eseese,", "And the LORD shall scatter you among the nations, and ye shall be left few in number among the heathen,"], ["e toaitiiti foi ni o outou e totoe i nuu e ta'ita'iina ai outou e Ieova;", "whither the LORD shall lead you."]]},
  {num:28,words:[["tou te auauna ai i atua na faia e lima o tagata,", "And there ye shall serve gods,"], ["o laau ma maa,", "the work of men's hands,"], ["o e le vaai,", "wood and stone, which neither see,"], ["ma latou le faalogologo,", "nor hear,"], ["latou te le aai,", "nor eat,"], ["ma latou le sogisogi,", "nor smell."]]},
  {num:29,words:[["A e afai tou te toe saili ia Ieova lou Atua i lea mea,", "But if from thence thou shalt seek the LORD thy God,"], ["ona e maua lea o ia,", "thou shalt find him,"], ["pe afai e te saili ia te ia ma lou loto atoa ma lou agaga atoa.", "if thou seek him with all thy heart and with all thy soul."]]},
  {num:30,words:[["A oo ia te oe le puapuaga,", "When thou art in tribulation,"], ["a maua foi oe e ia mea uma lava i aso amuli,", "and all these things are come upon thee,"], ["afai e te toe foi atu ia Ieova lou Atua,", "even in the latter days, if thou turn to the LORD thy God,"], ["ma e faalogo i lona siufofoga,", "and shalt be obedient unto his voice;"]]},
  {num:31,words:[["(auā o Ieova lou Atua, o le Atua alofa ia,", "(For the LORD thy God is a merciful God;"], [") na te le tuuna oe,", ") he will not forsake thee,"], ["na te le faaumatia oe,", "neither destroy thee,"], ["e le galo foi ia te ia le feagaiga ma ou tamā, na ia tauto ai ia te i latou.", "nor forget the covenant of thy fathers which he sware unto them."]]},
  {num:32,words:[["Auā ia e suesue i aso anamua na muamua ia te oe,", "For ask now of the days that are past,"], ["talu le aso na faia ai tagata e le Atua i le lalolagi;", "which were before thee,"], ["ia e suesue foi, ia amata i le tasi tuluiga o le lagi,", "since the day that God created man upon the earth,"], ["e oo atu i le tasi tuluiga o le lagi,", "and ask from the one side of heaven unto the other,"], ["pe ai se mea e pei o lenei mea tele,", "whether there hath been any such thing as this great thing is,"], ["pe na faalogoina e se tasi se mea la te tutusa?", "or hath been heard like it?"]]},
  {num:33,words:[["Pe na faalogologo se nuu i le siufofoga o le Atua ua tŭlei mai i totonu o le afi,", "Did ever people hear the voice of God speaking out of the midst of the fire,"], ["faapei ona e faalogologo i ai,", "as thou hast heard,"], ["a e ola mai pea ?", "and live?"]]},
  {num:34,words:[["Pe na sauni ea e le Atua ona afio atu,", "Or hath God assayed to go and take him a nation from the midst of another nation,"], ["ma ave mona le tasi nuu ai totonu o le tasi nuu,", "by temptations,"], ["i tofotofoga,", "by signs,"], ["ma faailoga,", "and by wonders,"], ["ma vavega, ma le taua,", "and by war,"], ["ma le aao malosi,", "and by a mighty hand,"], ["ma le aao faaloaloa,", "and by a stretched out arm,"], ["atoa ma mea matautia tele lava,", "and by great terrors,"], ["faapei o mea uma na faia e Ieova lo outou Atua ia te outou i o outou luma i Aikupito?", "according to all that the LORD your God did for you in Egypt before your eyes?"]]},
  {num:35,words:[["Ua faailoaina atu ia te oe ina ia e iloa,", "Unto thee it was shewed,"], ["o Ieova o ia lava le Atua,", "that thou mightest know that the LORD he is God;"], ["e leai se tasi na o ia lava.", "there is none else beside him."]]},
  {num:36,words:[["Ua na tŭlei mai lona siufofoga mai le lagi ia lagona e oe,", "Out of heaven he made thee to hear his voice,"], ["ina ia a'oa'o mai o ia ia te oe;", "that he might instruct thee:"], ["na ia faailoa mai foi ia te oe lana afi tele i le lalolagi,", "and upon earth he shewed thee his great fire;"], ["na e faalogologo foi i ana afioga ai totonu o le afi.", "and thou heardest his words out of the midst of the fire."]]},
  {num:37,words:[["Na ia alofaina ou tamā,", "And because he loved thy fathers,"], ["o le mea lea na ia filifilia ai a latou fanau, ina ua mavae atu i latou,", "therefore he chose their seed after them,"], ["ua na aumaia foi oe i ona luma i lona mana tele nai Aikupito;", "and brought thee out in his sight with his mighty power out of Egypt;"]]},
  {num:38,words:[["ina ia tulia nai ou luma o nuu e sili ona malolosi ma le toatele ia te oe,", "To drive out nations from before thee greater and mightier than thou art,"], ["ina ia faaoo ia te oe,", "to bring thee in,"], ["ma ia avatu lo latou laueleele e fai mou tofi,", "to give thee their land for an inheritance,"], ["faapei ona fai i le aso nei.", "as it is this day."]]},
  {num:39,words:[["Ia e iloa foi i le aso nei,", "Know therefore this day,"], ["ma ia mafaufau ai lou loto,", "and consider it in thine heart,"], ["o Ieova o ia lava le Atua i le lagi i luga,", "that the LORD he is God in heaven above,"], ["atoa ma le lalolagi nei,", "and upon the earth beneath:"], ["e leai lava se tasi.", "there is none else."]]},
  {num:40,words:[["O lenei,", "Thou shalt keep therefore his statutes, and his commandments,"], ["ia e tausiusi i ana tulafono ma ana poloaiga ou te fai atu ai ia te oe i le aso nei,", "which I command thee this day, that it may go well with thee,"], ["ina ia manuia ai oe ma au fanau pe a mavae atu oe,", "and with thy children after thee, and that thou mayest prolong thy days upon the earth,"], ["ina ia e nofo tulu'i ai i le laueleele ua foai mai ia te oe e Ieova lou Atua i aso uma lava.", "which the LORD thy God giveth thee, for ever."]]},
  {num:41,words:[["Ona vavaeeseina lea e Mose o aai e tolu i le itu mai o Ioritana i le mea e alu ae ai le la;", "Then Moses severed three cities on this side Jordan toward the sunrising;"]]},
  {num:42,words:[["ina ia sola i ai o le fasioti tagata,", "That the slayer might flee thither,"], ["o le na te fasioti i lē la te tuaoi ma le le iloa,", "which should kill his neighbour unawares,"], ["e lei muai ita foi i ai; a sola foi o ia i se tasi o ia aai,", "and hated him not in times past;"], ["ona ola ai lea o ia.", "and that fleeing unto one of these cities he might live:"]]},
  {num:43,words:[["O aai ia ,", "Namely,"], ["o Peseri i le vao i le eleele laugatasi,", "Bezer in the wilderness,"], ["o sa Reupenā;", "in the plain country,"], ["ma Ramota i Kiliata,", "of the Reubenites; and Ramoth in Gilead,"], ["o sa Katō;", "of the Gadites;"], ["ma Koleni o i Vasana,", "and Golan in Bashan,"], ["o sa Manasē.", "of the Manassites."]]},
  {num:44,words:[["O le tulafono lenei sa tuuina atu e Mose i le fanauga a Isaraelu;", "And this is the law which Moses set before the children of Israel:"]]},
  {num:45,words:[["o mau lava ia,", "These are the testimonies, and the statutes,"], ["ma tulafono,", "and the judgments,"], ["ma faamasinoga na fai atu ai Mose i le fanauga a Isaraelu ina ua latou o mai nai Aikupito,", "which Moses spake unto the children of Israel, after they came forth out of Egypt,"]]},
  {num:46,words:[["i le itu mai o Ioritana i le vanu e feagai ma Petepeoro,", "On this side Jordan, in the valley over against Beth-peor,"], ["i le laueleele o Sekono le tupu o sa Amorī,", "in the land of Sihon king of the Amorites,"], ["sa nofo i Hesepona,", "who dwelt at Heshbon,"], ["o ia na fasia e Mose ma le fanauga a Isaraelu ina ua latou o mai mai Aikupito.", "whom Moses and the children of Israel smote, after they were come forth out of Egypt:"]]},
  {num:47,words:[["Ua latou fai mo latou lona laueleele,", "And they possessed his land,"], ["ma le laueleele o Oko le tupu o Vasana,", "and the land of Og king of Bashan, two kings of the Amorites,"], ["o tupu e toalua o sa Amorī i le itu mai o Ioritana i le mea e alu ae ai le la;", "which were on this side Jordan toward the sunrising;"]]},
  {num:48,words:[["e gata mai i Aroeru i le auvai o le alia o Arinona,", "From Aroer,"], ["e gata mai i le mauga o Seona,", "which is by the bank of the river Arnon, even unto mount Sion,"], ["o Heremoni lea;", "which is Hermon,"]]},
  {num:49,words:[["ma le eleele laugatasi uma i le itu mai o Ioritana i sasae,", "And all the plain on this side Jordan eastward, even unto the sea of the plain,"], ["e oo lava i le sami o i le eleele laugatasi i lalo o Asetotapeseka.", "under the springs of Pisgah."]]},
];
renderVerseSet(deu_ch_4_Verses, 'deu-ch4-verses');

var deu_ch_5_Verses = [
  {num:1,words:[["Ona valaau atu lea o Mose ia Isaraelu uma lava,", "And Moses called all Israel,"], ["ua faapea atu ia te i latou,", "and said unto them, Hear,"], ["Isaraelu e,", "O Israel,"], ["ia e faalogo mai i tulafono ma faamasinoga ou te fai atu ai ia te outou i le aso nei,", "the statutes and judgments which I speak in your ears this day,"], ["ma ia outou a'oa'o ai,", "that ye may learn them, and keep,"], ["ma tausiusi i ai ina ia faia.", "and do them."]]},
  {num:2,words:[["O Ieova lo tatou Atua na ia osia le feagaiga ma i tatou i Horepa.", "The LORD our God made a covenant with us in Horeb."]]},
  {num:3,words:[["E le o tatou tamā na osi ai e Ieova lenei feagaiga ma i latou,", "The LORD made not this covenant with our fathers,"], ["a o i tatou lava,", "but with us, even us,"], ["o i tatou atoa uma o ola mai iinei i le aso nei.", "who are all of us here alive this day."]]},
  {num:4,words:[["Na fetalai mai Ieova ia te outou faafeagai lava i le mauga ai totonu o le afi.", "The LORD talked with you face to face in the mount out of the midst of the fire,"]]},
  {num:5,words:[["(Na ou tu i ia ona po i le va o Ieova ma outou,", "(I stood between the LORD and you at that time,"], ["e faaali atu ia te outou le afioga a Ieova;", "to shew you the word of the LORD:"], ["auā ua outou fefefe ona o le afi,", "for ye were afraid by reason of the fire,"], ["e lei o ae foi outou i le mauga;", "and went not up into the mount;"], [") na ia faapea mai,", ") saying,"]]},
  {num:6,words:[["O a'u o Ieova lou Atua,", "I am the LORD thy God,"], ["o le na aumaia oe nai le nuu o Aikupito,", "which brought thee out of the land of Egypt,"], ["o le mea sa nofo pologa ai.", "from the house of bondage."]]},
  {num:7,words:[["Aua ne'i e fai mo oe ni atua ese i o'u luma.", "Thou shalt have none other gods before me."]]},
  {num:8,words:[["Aua e te fai mo oe se tupua ua ta,", "Thou shalt not make thee any graven image,"], ["o se faatusa lava o se mea o i le lagi i luga,", "or any likeness of any thing that is in heaven above,"], ["po o i le fanua i lalo,", "or that is in the earth beneath,"], ["po o i le sami o i lalo o le fanua;", "or that is in the waters beneath the earth:"]]},
  {num:9,words:[["aua e te ifo i ai, aua foi e te auauna i ai;", "Thou shalt not bow down thyself unto them,"], ["auā o a'u o Ieova lou Atua,", "nor serve them:"], ["o le Atua fuā,", "for I the LORD thy God am a jealous God,"], ["o lē taui atu i fanau o le amioletonu a o latou mātua, e oo i le tupulaga e tolu ma le fa o e 'ino'ino mai ia te au;", "visiting the iniquity of the fathers upon the children unto the third and fourth generation of them that hate me,"]]},
  {num:10,words:[["a ou te alofa i afe o tupulaga o e alofa mai ia te au, ma tausi mai i a'u poloaiga.", "And shewing mercy unto thousands of them that love me and keep my commandments."]]},
  {num:11,words:[["Aua e te ta'u fua le suafa o Ieova lou Atua;", "Thou shalt not take the name of the LORD thy God in vain:"], ["auā e le faasaoina e Ieova o le ta'u fua i lona suafa.", "for the LORD will not hold him guiltless that taketh his name in vain."]]},
  {num:12,words:[["Ia e tausi le aso sapati ina ia faapaiaina;", "Keep the sabbath day to sanctify it,"], ["faapei ona poloai mai ai o Ieova lou Atua ia te oe.", "as the LORD thy God hath commanded thee."]]},
  {num:13,words:[["O aso e ono e te galue ai,", "Six days thou shalt labour,"], ["ma fai ai au galuega uma lava;", "and do all thy work:"]]},
  {num:14,words:[["a o le aso fitu o le sapati lea ia Ieova lou Atua;", "But the seventh day is the sabbath of the LORD thy God:"], ["aua e te fai ai se galuega e tasi,", "in it thou shalt not do any work,"], ["o oe,", "thou,"], ["ma lou atalii,", "nor thy son,"], ["ma lou afafine,", "nor thy daughter,"], ["o lou auauna tane,", "nor thy manservant,"], ["ma lau auauna fafine, ma lau povi,", "nor thy maidservant,"], ["ma lau asini,", "nor thine ox,"], ["po o se tasi o au manu,", "nor thine ass,"], ["ma le tagata ese o loo mau ma oe,", "nor any of thy cattle,"], ["ina ia malolo o lau auauna tane,", "nor thy stranger that is within thy gates;"], ["ma lau auauna fafine pei o oe lava.", "that thy manservant and thy maidservant may rest as well as thou."]]},
  {num:15,words:[["Ia e manatua foi,", "And remember that thou wast a servant in the land of Egypt,"], ["na fai oe ma auauna i le nuu o Aikupito, a ua aumaia oe e Ieova lou Atua ai lea mea i le aao malosi ma le aao faaloaloa;", "and that the LORD thy God brought thee out thence through a mighty hand and by a stretched out arm:"], ["o le mea lea ua poloai mai ai Ieova lou Atua ia te oe e te faia le aso sapati.", "therefore the LORD thy God commanded thee to keep the sabbath day."]]},
  {num:16,words:[["Ia e ava i lou tamā ma lou tinā,", "Honour thy father and thy mother,"], ["pei ona poloai mai ai o Ieova lou Atua ia te oe,", "as the LORD thy God hath commanded thee;"], ["ina ia faalevaleva ai ou aso,", "that thy days may be prolonged, and that it may go well with thee,"], ["ina ia manuia ai foi oe i le nuu o le a faoiina mai e Ieova lou Atua ia te oe.", "in the land which the LORD thy God giveth thee."]]},
  {num:17,words:[["Aua e te fasioti tagata.", "Thou shalt not kill."]]},
  {num:18,words:[["Aua foi e te mulilua.", "Neither shalt thou commit adultery."]]},
  {num:19,words:[["Aua foi e te gaoi.", "Neither shalt thou steal."]]},
  {num:20,words:[["Aua foi e te mōlimau pepelo i se tasi.", "Neither shalt thou bear false witness against thy neighbour."]]},
  {num:21,words:[["Aua foi e te manao i le avā a le lua te tuaoi,", "Neither shalt thou desire thy neighbour's wife,"], ["aua foi e te manao i le fale o le lua te tuaoi,", "neither shalt thou covet thy neighbour's house,"], ["o lona fanua,", "his field,"], ["po o lana auauna tane,", "or his manservant,"], ["po o lana auauna fafine,", "or his maidservant,"], ["o lana povi,", "his ox,"], ["po o lana asini,", "or his ass,"], ["po o se tasi mea a le lua te tuaoi.", "or any thing that is thy neighbour's."]]},
  {num:22,words:[["O upu lava ia na fetalai mai ai Ieova i lo outou faapotopotoga uma lava i le mauga,", "These words the LORD spake unto all your assembly in the mount out of the midst of the fire,"], ["ai totonu o le afi,", "of the cloud,"], ["ma le ao, ma le pogisa,", "and of the thick darkness,"], ["ua leo tele mai na ia le faaopoopo i ai se upu ;", "with a great voice:"], ["ua na tusi mai ai foi i papamaa e lua,", "and he added no more. And he wrote them in two tables of stone,"], ["ona au mai ai lea ia te au.", "and delivered them unto me."]]},
  {num:23,words:[["Na outou faalogologo i le leo ai totonu o le pouliuli,", "And it came to pass,"], ["ua mu foi le mauga i le afi,", "when ye heard the voice out of the midst of the darkness,"], ["ona faalatalata mai ai lea ia te au o outou,", "(for the mountain did burn with fire, ) that ye came near unto me,"], ["o matai uma o outou itu aiga,", "even all the heads of your tribes,"], ["ma o outou toeaina;", "and your elders;"]]},
  {num:24,words:[["ua outou faapea mai,", "And ye said,"], ["Faauta,", "Behold,"], ["ua faaalia mai ia te i matou e Ieova lo tatou Atua o lona pupula ma lona silisili ese,", "the LORD our God hath shewed us his glory and his greatness,"], ["o lona siufofoga foi ua matou faalogologo i ai ai totonu o le afi;", "and we have heard his voice out of the midst of the fire:"], ["o le aso nei ua matou iloa ai ua fetalai mai le Atua i tagata,", "we have seen this day that God doth talk with man,"], ["a e ola pea i latou.", "and he liveth."]]},
  {num:25,words:[["O lenei,", "Now therefore why should we die? for this great fire will consume us:"], ["se a ea le mea a matou oti ai? auā e faaumatia i matou i lena afi tele, afai matou te toe faalogologo i le siufofoga o Ieova lo tatou Atua,", "if we hear the voice of the LORD our God any more,"], ["ona matou oti ai lea;", "then we shall die."]]},
  {num:26,words:[["auā po o ai se tasi tagata na ia faalogologo faapei o i matou i le siufofoga o le Atua soifua ua fetalai mai ai totonu o le afi,", "For who is there of all flesh, that hath heard the voice of the living God speaking out of the midst of the fire,"], ["a e ola pea ia?", "as we have, and lived?"]]},
  {num:27,words:[["Ina e faalatalata atu ia,", "Go thou near,"], ["ma ia e faalogologo i mea uma e fetalai mai ai Ieova lo tatou Atua,", "and hear all that the LORD our God shall say:"], ["ma ia e ta'u mai ia te i matou mea uma lava e fetalaia mai e Ieova lo tatou Atua ia te oe,", "and speak thou unto us all that the LORD our God shall speak unto thee;"], ["ona matou faalogologo atu lea i ai,", "and we will hear it,"], ["ma matou faia.", "and do it."]]},
  {num:28,words:[["Na faafofoga mai foi Ieova i a outou upu sa outou fai mai ai ia te au;", "And the LORD heard the voice of your words, when ye spake unto me;"], ["ona fetalai mai lea o Ieova ia te au,", "and the LORD said unto me,"], ["Ua ou faalogo i upu a lenei nuu sa latou fai atu ai ia te oe,", "I have heard the voice of the words of this people,"], ["ua lelei upu uma lava na latou fai atu ai.", "which they have spoken unto thee: they have well said all that they have spoken."]]},
  {num:29,words:[["E! ana ia i latou lena loto e matatau mai ai ia te au,", "O that there were such an heart in them,"], ["ma tausiusi i a'u poloaiga uma i aso uma lava,", "that they would fear me,"], ["ina ia manuia ai i latou,", "and keep all my commandments always, that it might be well with them,"], ["atoa ma a latou fanau e faavavau.", "and with their children for ever!"]]},
  {num:30,words:[["Alu ia, ina fai atu ia te i latou,", "Go say to them,"], ["Ia outou toe foi atu i o outou fale ie.", "Get you into your tents again."]]},
  {num:31,words:[["A o oe,", "But as for thee,"], ["ia e tu mai iinei ia te au,", "stand thou here by me,"], ["ou te fai atu foi ia te oe i poloaiga uma,", "and I will speak unto thee all the commandments, and the statutes,"], ["ma tulafono,", "and the judgments,"], ["ma faamasinoga e te a'oa'o atu ai ia te i latou,", "which thou shalt teach them,"], ["ia latou faia i le nuu ou te avatu ia te i latou e fai mo latou.", "that they may do them in the land which I give them to possess it."]]},
  {num:32,words:[["Lenei la, ia outou anaana ia faia,", "Ye shall observe to do therefore as the LORD your God hath commanded you:"], ["faapei ona poloai mai ai o Ieova lo outou Atua ia te outou, aua tou te afe i le itu taumatau, po o le itu tauagavale.", "ye shall not turn aside to the right hand or to the left."]]},
  {num:33,words:[["Ia outou savavali i le ala uma lava na poloai mai ai Ieova lo outou Atua ia te outou,", "Ye shall walk in all the ways which the LORD your God hath commanded you,"], ["ina ia outou ola ai,", "that ye may live,"], ["ma ia manuia ai outou,", "and that it may be well with you,"], ["ma ia outou nofo tulu'i ai i le nuu o le a fai mo outou.", "and that ye may prolong your days in the land which ye shall possess."]]},
];
renderVerseSet(deu_ch_5_Verses, 'deu-ch5-verses');

var deu_ch_6_Verses = [
  {num:1,words:[["O poloaiga ia,", "Now these are the commandments,"], ["o tulafono,", "the statutes,"], ["ma faamasinoga na fetalai mai ai Ieova lo outou Atua ia a'oa'o atu ai ia te outou,", "and the judgments, which the LORD your God commanded to teach you,"], ["ina ia outou faia i le nuu tou te o atu i ai e fai mo outou;", "that ye might do them in the land whither ye go to possess it:"]]},
  {num:2,words:[["ina ia e mata'u ia Ieova lou Atua,", "That thou mightest fear the LORD thy God,"], ["e te tausiusi ai i ana tulafono ma ana poloaiga uma ou te fai atu ai ia te oe,", "to keep all his statutes and his commandments, which I command thee,"], ["o oe,", "thou,"], ["ma lou atalii,", "and thy son,"], ["ma le atalii o lou atalii i aso uma o lou olaga,", "and thy son's son, all the days of thy life;"], ["ina ia faalevalevaina ai ou aso.", "and that thy days may be prolonged."]]},
  {num:3,words:[["O lenei,", "Hear therefore,"], ["Isaraelu e,", "O Israel,"], ["ia e faalogologo mai,", "and observe to do it;"], ["ma ia e tausi i ai ia faia, ina ia manuia ai oe,", "that it may be well with thee,"], ["ma ia matuā faatoateleina ai outou,", "and that ye may increase mightily,"], ["faapei ona fetalai mai ai ia te oe o Ieova le Atua o ou tamā,", "as the LORD God of thy fathers hath promised thee,"], ["i le nuu o loo tafe ai le suāsusu ma le meli.", "in the land that floweth with milk and honey."]]},
  {num:4,words:[["Isaraelu e,", "Hear,"], ["faalogologo mai ia, o Ieova lo tatou Atua,", "O Israel:"], ["o Ieova e toatasi lava ia.", "The LORD our God is one LORD:"]]},
  {num:5,words:[["Ia e alofa atu ia Ieova lou Atua ma lou loto atoa,", "And thou shalt love the LORD thy God with all thine heart,"], ["ma lou agaga atoa,", "and with all thy soul,"], ["ma lou malosi atoa.", "and with all thy might."]]},
  {num:6,words:[["Ia i ai foi i lou loto o upu nei ou te fai atu ai ia te oe i le aso nei.", "And these words, which I command thee this day, shall be in thine heart:"]]},
  {num:7,words:[["Ia e matuā a'oa'o soo ai i lau fanau,", "And thou shalt teach them diligently unto thy children,"], ["ma ia e tautalatala a'i,", "and shalt talk of them when thou sittest in thine house,"], ["pe a ē nofo i lou fale, pe a ē savali foi i le ala,", "and when thou walkest by the way,"], ["pe a ē taoto,", "and when thou liest down,"], ["pe a ē tulai foi.", "and when thou risest up."]]},
  {num:8,words:[["Ia e fusi ai e fai ma faailoga i lou lima,", "And thou shalt bind them for a sign upon thine hand,"], ["e avea foi ma pale i le va o ou mata.", "and they shall be as frontlets between thine eyes."]]},
  {num:9,words:[["Ia e tusi ai foi i pou o lou fale,", "And thou shalt write them upon the posts of thy house,"], ["atoa ma ou puipui.", "and on thy gates."]]},
  {num:10,words:[["A faaooina oe e Ieova lou Atua i le nuu na ia tauto ai i ou tamā,", "And it shall be,"], ["o Aperaamo,", "when the LORD thy God shall have brought thee into the land which he sware unto thy fathers,"], ["o Isaako,", "to Abraham,"], ["ma Iakopo,", "to Isaac,"], ["e avatu ia te oe,", "and to Jacob,"], ["o aai tetele ma le lelei,", "to give thee great and goodly cities,"], ["e te lei faia,", "which thou buildedst not,"]]},
  {num:11,words:[["o fale foi e tutumu i mea lelei uma na e le faatutumuina;", "And houses full of all good things,"], ["o vaieli foi e te lei elia,", "which thou filledst not, and wells digged,"], ["o tovine ma olive e te lei totoina;", "which thou diggedst not,"], ["a e 'ai ai,", "vineyards and olive trees, which thou plantedst not;"], ["ma e ma'ona ai,", "when thou shalt have eaten and be full;"]]},
  {num:12,words:[["ia oe,", "Then beware lest thou forget the LORD,"], ["ne'i galo ia te oe o Ieova na na aumaia oe nai le nuu o Aikupito,", "which brought thee forth out of the land of Egypt,"], ["o le mea sa nofo pologa ai.", "from the house of bondage."]]},
  {num:13,words:[["Ia e mata'u ia Ieova lou Atua,", "Thou shalt fear the LORD thy God,"], ["ma ia e auauna ia te ia;", "and serve him,"], ["o lona suafa foi e te tauto i ai.", "and shalt swear by his name."]]},
  {num:14,words:[["Aua tou te mulimuli atu i atua ese,", "Ye shall not go after other gods,"], ["o atua o nuu e vagavagaia outou,", "of the gods of the people which are round about you;"]]},
  {num:15,words:[["(auā o Ieova lou Atua o ia te oe, o le Atua fuā ia,", "(For the LORD thy God is a jealous God among you) lest the anger of the LORD thy God be kindled against thee,"], [") ne'i tupu le toasa o Ieova lou Atua ia te oe, ona faaumatia ai lea o oe ai le fogāeleele.", "and destroy thee from off the face of the earth."]]},
  {num:16,words:[["Aua tou te tofotofo ia Ieova lo outou Atua,", "Ye shall not tempt the LORD your God,"], ["faapei ona outou tofotofo ia te ia i Mase.", "as ye tempted him in Massah."]]},
  {num:17,words:[["Ia outou matuā tausiusi i poloaiga a Ieova lo outou Atua,", "Ye shall diligently keep the commandments of the LORD your God,"], ["ma ana mau,", "and his testimonies,"], ["ma ana tulafono,", "and his statutes,"], ["na ia poloai mai ai ia te oe.", "which he hath commanded thee."]]},
  {num:18,words:[["Ia e fai foi le amiotonu ma le lelei i luma o Ieova,", "And thou shalt do that which is right and good in the sight of the LORD:"], ["ina ia manuia ai oe, ma ia e oo atu,", "that it may be well with thee,"], ["ma ia fai mo oe le nuu lelei na tauto ai Ieova i ou tamā,", "and that thou mayest go in and possess the good land which the LORD sware unto thy fathers,"]]},
  {num:19,words:[["na te tulia ou fili uma lava ai ou luma,", "To cast out all thine enemies from before thee,"], ["faapei ona fetalai mai ai o Ieova.", "as the LORD hath spoken."]]},
  {num:20,words:[["A fesili mai lou atalii ia te oe i se aso,", "And when thy son asketh thee in time to come,"], ["o loo faapea mai,", "saying,"], ["Pe ni a ea mau,", "What mean the testimonies,"], ["ma tulafono,", "and the statutes,"], ["ma faamasinoga,", "and the judgments,"], ["na poloai mai ai Ieova lo tatou Atua ia te outou?", "which the LORD our God hath commanded you?"]]},
  {num:21,words:[["Ona e fai atu ai lea i lou atalii,", "Then thou shalt say unto thy son,"], ["Sa matou nofo pologa ia Farao i Aikupito,", "We were Pharaoh's bondmen in Egypt;"], ["a ua aumaia i matou e Ieova ai Aikupito i le aao malosi;", "and the LORD brought us out of Egypt with a mighty hand:"]]},
  {num:22,words:[["na tuuina atu foi e Ieova o faailoga ma vavega tetele na leaga ai Aikupito,", "And the LORD shewed signs and wonders, great and sore,"], ["ma Farao,", "upon Egypt,"], ["atoa ma lona aiga uma,", "upon Pharaoh,"], ["i o matou luma;", "and upon all his household, before our eyes:"]]},
  {num:23,words:[["na ia au mai ai foi i matou,", "And he brought us out from thence,"], ["ina ia faaooina mai i matou,", "that he might bring us in,"], ["ia foaiina mai ia te i tatou le nuu na ia tauto ai i o tatou tamā.", "to give us the land which he sware unto our fathers."]]},
  {num:24,words:[["Na poloai mai foi Ieova ia te i tatou ia faia noi tulafono uma lava,", "And the LORD commanded us to do all these statutes,"], ["ia matatau ia Ieova lo tatou Atua,", "to fear the LORD our God,"], ["ina ia manuia ai tatou i aso uma,", "for our good always,"], ["ina ia na faaolaina i tatou,", "that he might preserve us alive,"], ["pei ona fai i le aso nei.", "as it is at this day."]]},
  {num:25,words:[["E avea foi ma amiotonu ia te i tatou,", "And it shall be our righteousness,"], ["pe afai tatou te anaana ia faia ia poloaiga uma i luma o Ieova lo tatou Atua,", "if we observe to do all these commandments before the LORD our God,"], ["faapei ona ia poloai mai ai ia i tatou.", "as he hath commanded us."]]},
];
renderVerseSet(deu_ch_6_Verses, 'deu-ch6-verses');

var deu_ch_7_Verses = [
  {num:1,words:[["A Faaooina oe e Ieova lou Atua i le nuu o le a e alu i ai e fai mo oe,", "When the LORD thy God shall bring thee into the land whither thou goest to possess it,"], ["a tulia foi e ia o nuu e tele i ou luma,", "and hath cast out many nations before thee,"], ["o sa Hetī,", "the Hittites,"], ["ma sa Kirekasē,", "and the Girgashites,"], ["ma sa Amorī,", "and the Amorites,"], ["ma sa Kananā,", "and the Canaanites,"], ["ma sa Perisē,", "and the Perizzites,"], ["ma sa Hivī,", "and the Hivites,"], ["atoa ma sa Iepusē,", "and the Jebusites,"], ["o nuu e fitu e sili ona toatele ma le malolosi ia te oe;", "seven nations greater and mightier than thou;"]]},
  {num:2,words:[["a tuuina mai i latou ia te oe e Ieova lou Atua e te fasia i latou,", "And when the LORD thy God shall deliver them before thee;"], ["ia e matuā faaumatia lava i latou,", "thou shalt smite them,"], ["aua e te osi se feagaiga ma i latou,", "and utterly destroy them; thou shalt make no covenant with them,"], ["aua foi e te alofa ia te i latou.", "nor shew mercy unto them:"]]},
  {num:3,words:[["Aua le fetaiai gafa ma i latou,", "Neither shalt thou make marriages with them;"], ["aua le avatu lou afafine mā lona atalii,", "thy daughter thou shalt not give unto his son,"], ["aua foi ne'i e au mai lona afafine mā lou atalii;", "nor his daughter shalt thou take unto thy son."]]},
  {num:4,words:[["auā e faaliliueseina e ia lou atalii,", "For they will turn away thy son from following me,"], ["ia le mulimuli mai ia te au,", "that they may serve other gods:"], ["a e auauna i atua ese; ona tupu ai lea o le toasa o Ieova ia te outou,", "so will the anger of the LORD be kindled against you,"], ["ma vave faaumatia ai oe.", "and destroy thee suddenly."]]},
  {num:5,words:[["A ia faapea ona fai e outou ia te i latou,", "But thus shall ye deal with them;"], ["ia outou sofaia o latou fata faitaulaga,", "ye shall destroy their altars,"], ["ia outou tu'ipalaina o latou tupua,", "and break down their images,"], ["ma vavae i lalo o latou tupua o Asaira,", "and cut down their groves,"], ["o latou tupua foi ua ta ia outou susunu i le afi;", "and burn their graven images with fire."]]},
  {num:6,words:[["auā o oe o lo nuu paia mo Ieova lou Atua,", "For thou art an holy people unto the LORD thy God:"], ["na filifilia oe e Ieova lou Atua ina ia avea ma nuu mona,", "the LORD thy God hath chosen thee to be a special people unto himself,"], ["o le oloa tāua e sili i nuu uma lava o i le fogāeleele.", "above all people that are upon the face of the earth."]]},
  {num:7,words:[["E le ona ua sili ona toatele outou i nuu uma na manao ai Ieova ia te outou,", "The LORD did not set his love upon you,"], ["ma na filifilia outou,", "nor choose you, because ye were more in number than any people;"], ["auā na sili ona toaitiiti outou i nuu uma lava;", "for ye were the fewest of all people:"]]},
  {num:8,words:[["a e peitai ona ua alofa lava Ieova ia te outou,", "But because the LORD loved you,"], ["ona o lona tausi foi o le tautoga na ia tauto ai i o outou tamā,", "and because he would keep the oath which he had sworn unto your fathers,"], ["ua au mai ai outou e Ieova i le aao malosi,", "hath the LORD brought you out with a mighty hand,"], ["na ia faaolaina foi oe ai le mea sa nofo pologa ai,", "and redeemed you out of the house of bondmen,"], ["ai le lima o Farao le tupu o Aikupito.", "from the hand of Pharaoh king of Egypt."]]},
  {num:9,words:[["Ia e iloa foi o Ieova lou Atua o le Atua lava ia,", "Know therefore that the LORD thy God,"], ["o le Atua faamaoni,", "he is God,"], ["o le na te tausi i le feagaiga atoa ma le alofa i e alolofa atu ia te ia ma tausiusi i ana poloaiga,", "the faithful God,"], ["e oo lava i le afe o tupulaga;", "which keepeth covenant and mercy with them that love him and keep his commandments to a thousand generations;"]]},
  {num:10,words:[["a e tauia e ia o e 'ino'ino ia te ia i o latou lava luma,", "And repayeth them that hate him to their face,"], ["ia faaumatia i latou;", "to destroy them:"], ["e le faatuai o ia i lē 'ino'ino ia te ia,", "he will not be slack to him that hateth him,"], ["a e taui atu ia te ia i ona lava luma.", "he will repay him to his face."]]},
  {num:11,words:[["O lenei,", "Thou shalt therefore keep the commandments,"], ["ia e tausi i poloaiga,", "and the statutes,"], ["ma tulafono,", "and the judgments, which I command thee this day,"], ["ma faamasinoga ou te fai atu ai ia te oe i le aso nei ia faia.", "to do them."]]},
  {num:12,words:[["Afai foi tou te faalogo i ia faamasinoga ma tausi i ai ia faia,", "Wherefore it shall come to pass, if ye hearken to these judgments,"], ["ona tausi lea e Ieova lou Atua o le feagaiga ma le alofa ia te oe na ia tauto ai i ou tamā;", "and keep, and do them, that the LORD thy God shall keep unto thee the covenant and the mercy which he sware unto thy fathers:"]]},
  {num:13,words:[["e alofa mai foi o ia ia te oe,", "And he will love thee,"], ["ma faamanuia ia te oe,", "and bless thee,"], ["ma faatoateleina oe;", "and multiply thee:"], ["e faamanuia foi e ia i lau fanau,", "he will also bless the fruit of thy womb,"], ["ma le fua o lou laueleele,", "and the fruit of thy land, thy corn,"], ["o lau saito,", "and thy wine,"], ["ma lau uaina,", "and thine oil,"], ["ma lau suāuu,", "the increase of thy kine,"], ["o tama a au povi,", "and the flocks of thy sheep,"], ["ma au lafu mamoe i le laueleele na na tauto ai i ou tamā e foai atu ia te oe.", "in the land which he sware unto thy fathers to give thee."]]},
  {num:14,words:[["E sili lou manuia i nuu uma lava;", "Thou shalt be blessed above all people: there shall not be male or female barren among you,"], ["e leai se tane e pa po o se fafine pa ia te oe atoa ma au manu.", "or among your cattle."]]},
  {num:15,words:[["E ave ese e Ieova o ma'i uma lava ia te oe,", "And the LORD will take away from thee all sickness, and will put none of the evil diseases of Egypt,"], ["na te le tuuina mai ia te oe se tasi ma'i o ma'i leaga o Aikupito na e iloa,", "which thou knowest,"], ["a e tuuina atu ia te i latou uma o e 'ino'ino ia te oe.", "upon thee; but will lay them upon all them that hate thee."]]},
  {num:16,words:[["Ia e faaumatia nuu uma lava ua tuuina mai e Ieova lou Atua ia te oe;", "And thou shalt consume all the people which the LORD thy God shall deliver thee;"], ["aua ne'i e alofa ia te i latou,", "thine eye shall have no pity upon them:"], ["aua ne'i e auauna foi i o latou atua;", "neither shalt thou serve their gods;"], ["auā e avea lea mea ma mailei ia te oe.", "for that will be a snare unto thee."]]},
  {num:17,words:[["Afai e te faapea ifo i lou loto,", "If thou shalt say in thine heart,"], ["O nuu ia e sili ona toatele ia te au,", "These nations are more than I;"], ["ou te mafaia faapefea ona tulia o i latou?", "how can I dispossess them?"]]},
  {num:18,words:[["Aua lava e te mata'u ia te i latou;", "Thou shalt not be afraid of them: but shalt well remember what the LORD thy God did unto Pharaoh,"], ["ia e matuā manatua mea na faia e Ieova lou Atua ia Farao ma Aikupito uma lava;", "and unto all Egypt;"]]},
  {num:19,words:[["o tofotofoga tetele sa vaai atu i ai ou mata,", "The great temptations which thine eyes saw,"], ["ma faailoga,", "and the signs,"], ["ma vavega,", "and the wonders,"], ["ma le aao malosi,", "and the mighty hand,"], ["ma le aao faaloaloaina,", "and the stretched out arm,"], ["na au mai ai oe e Ieova lou Atua;", "whereby the LORD thy God brought thee out:"], ["e faapea lava ona faia e Ieova lou Atua i nuu uma lava e te mata'u ai.", "so shall the LORD thy God do unto all the people of whom thou art afraid."]]},
  {num:20,words:[["E auina atu foi le lagomumu ia te i latou e Ieova lou Atua,", "Moreover the LORD thy God will send the hornet among them,"], ["seia faaumatia ai e o totoe,", "until they that are left, and hide themselves from thee,"], ["ma ua lalafi nai ou luma.", "be destroyed."]]},
  {num:21,words:[["Aua lava e te atuatuvale ona o i latou,", "Thou shalt not be affrighted at them:"], ["auā o Ieova lou Atua o ia te oe,", "for the LORD thy God is among you,"], ["o le Atua silisili ia ma le matautia.", "a mighty God and terrible."]]},
  {num:22,words:[["E tulia auauai e Ieova lou Atua ia nuu ai ou luma,", "And the LORD thy God will put out those nations before thee by little and little:"], ["e te le vave faaumatia i latou,", "thou mayest not consume them at once,"], ["ne'i tupu tele ai manu feai e tigaina ai oe.", "lest the beasts of the field increase upon thee."]]},
  {num:23,words:[["A e tuuina mai i latou e Ieova lou Atua i ou luma,", "But the LORD thy God shall deliver them unto thee,"], ["ma faaumatia i latou i le malaia tele,", "and shall destroy them with a mighty destruction,"], ["seia matuā faaumatia i latou.", "until they be destroyed."]]},
  {num:24,words:[["Na te tuuina mai foi o latou tupu i lou lima,", "And he shall deliver their kings into thine hand,"], ["e te tineia foi o latou igoa ai le lalolagi;", "and thou shalt destroy their name from under heaven: there shall no man be able to stand before thee,"], ["e leai lava se tagata e tu mai e tetee ia te oe seia oo ina faaumatia i latou e oe.", "until thou have destroyed them."]]},
  {num:25,words:[["O tupua ua ta o latou atua ia e susunu i le afi;", "The graven images of their gods shall ye burn with fire:"], ["aua e te manao i le ario ma le auro o i ai,", "thou shalt not desire the silver or gold that is on them,"], ["aua foi e te ave mā oe,", "nor take it unto thee,"], ["ne'i maileia ai oe;", "lest thou be snared therein:"], ["auā o le mea e inosia lea e Ieova lou Atua.", "for it is an abomination to the LORD thy God."]]},
  {num:26,words:[["Aua e te avatu i lou fale se mea e inosia,", "Neither shalt thou bring an abomination into thine house,"], ["ne'i fetuuina oe pei o lea mea;", "lest thou be a cursed thing like it:"], ["ia e matuā 'ino'ino i ai,", "but thou shalt utterly detest it,"], ["ma ia matuā inosia e oe,", "and thou shalt utterly abhor it;"], ["auā o le mea fetuuina lava lea.", "for it is a cursed thing."]]},
];
renderVerseSet(deu_ch_7_Verses, 'deu-ch7-verses');

var deu_ch_8_Verses = [
  {num:1,words:[["O poloaiga uma lava ou te fai atu ai ia te oe i le aso nei ia outou tausi i ai ia faia,", "All the commandments which I command thee this day shall ye observe to do,"], ["ina ia outou ola ai,", "that ye may live,"], ["ma ia faatoateleina ai outou,", "and multiply,"], ["ma ia outou o atu ma fai mo outou le nuu na tauto ai Ieova i o outou tamā.", "and go in and possess the land which the LORD sware unto your fathers."]]},
  {num:2,words:[["Ia e manatua le ala uma lava na ta'ita'iina mai ai oe e Ieova lou Atua i ia tausaga e fagafulu i le vao,", "And thou shalt remember all the way which the LORD thy God led thee these forty years in the wilderness,"], ["ina ia na faatigaina oe,", "to humble thee,"], ["ma tofotofo ai ia te oe,", "and to prove thee, to know what was in thine heart,"], ["e iloa ai mea o i lou loto,", "whether thou wouldest keep his commandments,"], ["pe e te tausiusi i ana poloaiga pe leai.", "or no."]]},
  {num:3,words:[["Na ia faatigaina foi oe,", "And he humbled thee,"], ["ma faalaina oe,", "and suffered thee to hunger,"], ["ua na fafaga ia te oe i le manai,", "and fed thee with manna,"], ["o le mea na e le iloa,", "which thou knewest not,"], ["na le iloa foi e ou tamā,", "neither did thy fathers know;"], ["ina ia na faailoa atu ia te oe e le na o mea e 'ai e ola ai tagata,", "that he might make thee know that man doth not live by bread only,"], ["a o mea uma e tŭlei mai i le fofoga o Ieova e ola ai tagata.", "but by every word that proceedeth out of the mouth of the LORD doth man live."]]},
  {num:4,words:[["Na le pala ou ofu na e ofu ai,", "Thy raiment waxed not old upon thee, neither did thy foot swell,"], ["o ou vae foi na le fulafula i ia tausaga e fagafulu.", "these forty years."]]},
  {num:5,words:[["E te iloa foi i lou loto e faapei o se tagata ona aoai i lona atalii,", "Thou shalt also consider in thine heart, that,"], ["e faapea lava ona aoai o Ieova lou Atua ia te oe.", "as a man chasteneth his son, so the LORD thy God chasteneth thee."]]},
  {num:6,words:[["O lenei,", "Therefore thou shalt keep the commandments of the LORD thy God,"], ["ia e tausiusi i poloaiga a Ieova lou Atua, ina ia e savali i ona ala,", "to walk in his ways,"], ["ma ia mata'u ia te ia.", "and to fear him."]]},
  {num:7,words:[["Auā o le a faaooina oe e Ieova lou Atua i le nuu lelei,", "For the LORD thy God bringeth thee into a good land,"], ["o le nuu o vaitafe, o vaipuna,", "a land of brooks of water,"], ["atoa ma vai tetele e puna mai i vanu ma mauga;", "of fountains and depths that spring out of valleys and hills;"]]},
  {num:8,words:[["o le nuu o saito,", "A land of wheat,"], ["ma karite,", "and barley,"], ["ma vine,", "and vines, and fig trees,"], ["ma mati,", "and pomegranates;"], ["ma rimoni;", "a land of oil olive,"], ["o le nuu o i ai le suāuu olive ma le meli.", "and honey;"]]},
  {num:9,words:[["O le nuu e te 'ai ai i mea e 'ai ma le le oge lava,", "A land wherein thou shalt eat bread without scarceness,"], ["e te le mativa ai i se mea e tasi;", "thou shalt not lack any thing in it;"], ["o le nuu o uamea ona maa,", "a land whose stones are iron,"], ["o ona mauga foi e te eli ai le 'apa memea.", "and out of whose hills thou mayest dig brass."]]},
  {num:10,words:[["A ē 'ai, ma ma'ona ai,", "When thou hast eaten and art full,"], ["ia e faamanu atu ai ia Ieova lou Atua ona o le nuu lelei ua ia avatu ai ia te oe.", "then thou shalt bless the LORD thy God for the good land which he hath given thee."]]},
  {num:11,words:[["Ia oe,", "Beware that thou forget not the LORD thy God,"], ["ne'i galo ia te oe o Ieova lou Atua,", "in not keeping his commandments,"], ["i lou le tausi i ana poloaiga, ma ana faamasinoga,", "and his judgments,"], ["ma ana tulafono,", "and his statutes,"], ["ou te fai atu ai ia te oe i le aso nei;", "which I command thee this day:"]]},
  {num:12,words:[["ne'i e 'ai,", "Lest when thou hast eaten and art full,"], ["ma e ma'ona, ma e faia fale lelei,", "and hast built goodly houses,"], ["ma nofo ai;", "and dwelt therein;"]]},
  {num:13,words:[["e tupu tele foi lau lafu povi ma lau lafu mamoe,", "And when thy herds and thy flocks multiply,"], ["e faateleina foi au ario ma au auro,", "and thy silver and thy gold is multiplied,"], ["e faateleina foi au mea uma;", "and all that thou hast is multiplied;"]]},
  {num:14,words:[["ona faamaualugaina ai lea o lou loto,", "Then thine heart be lifted up,"], ["ma e faagalogalo ia Ieova lou Atua o le na aumaia oe nai le nuu o Aikupito,", "and thou forget the LORD thy God, which brought thee forth out of the land of Egypt,"], ["o le mea sa nofo pologa ai;", "from the house of bondage;"]]},
  {num:15,words:[["o le na ta'ita'i ia te oe i le vao e tele ma le matautia,", "Who led thee through that great and terrible wilderness,"], ["e i ai gata uogo ma akarava,", "wherein were fiery serpents,"], ["o le nuu naumati foi,", "and scorpions, and drought,"], ["e le o i ai se vai,", "where there was no water;"], ["a ua faapunaina e ia le vai mo oe nai le papa alā;", "who brought thee forth water out of the rock of flint;"]]},
  {num:16,words:[["na ia fafaga ia te oe i le manai i le vao,", "Who fed thee in the wilderness with manna,"], ["o le mea na le iloa e ou tamā,", "which thy fathers knew not,"], ["ina ia na faatigaina oe,", "that he might humble thee,"], ["ina ia na tofotofo foi ia te oe,", "and that he might prove thee,"], ["e faamanuia ia te oe i ou tausaga amuli;", "to do thee good at thy latter end;"]]},
  {num:17,words:[["ne'i e faapea ifo i lou loto,", "And thou say in thine heart,"], ["O lo'u malosi ma le malosi o lo'u lima ua ou maua mai ai lenei oloa.", "My power and the might of mine hand hath gotten me this wealth."]]},
  {num:18,words:[["A ia e manatu ia Ieova lou Atua,", "But thou shalt remember the LORD thy God:"], ["auā o ia na te avatua ia te oe le malosi e maua mai ai oloa,", "for it is he that giveth thee power to get wealth,"], ["ina ia faatumauina ai e ia lana feagaiga na ia tauto ai i ou tamā,", "that he may establish his covenant which he sware unto thy fathers,"], ["pei ona fai i le aso nei.", "as it is this day."]]},
  {num:19,words:[["Afai foi e galo ia te oe Ieova lou Atua,", "And it shall be,"], ["ma e mulimuli atu i atua ese,", "if thou do at all forget the LORD thy God,"], ["ma e auauna ia i latou,", "and walk after other gods,"], ["ma e ifo ia te i latou,", "and serve them,"], ["ou te matuā fai atu ia te outou i le aso nei,", "and worship them,"], ["e faaumatia lava outou.", "I testify against you this day that ye shall surely perish."]]},
  {num:20,words:[["Faapei o nuu e faaumatia e Ieova ai o outou luma,", "As the nations which the LORD destroyeth before your face,"], ["e faapea lava outou ona faaumatia;", "so shall ye perish;"], ["auā ua outou le mafafai ona faalogo i le siufofoga o Ieova lo outou Atua.", "because ye would not be obedient unto the voice of the LORD your God."]]},
];
renderVerseSet(deu_ch_8_Verses, 'deu-ch8-verses');

var deu_ch_9_Verses = [
  {num:1,words:[["Isaraelu e,", "Hear,"], ["faalogologo mai ia,", "O Israel:"], ["o le a e sopoia atu Ioritana i ona po nei,", "Thou art to pass over Jordan this day,"], ["ina ia e oo atu e fai mo oe o nuu e sili ona toatele ma le malolosi ia te oe,", "to go in to possess nations greater and mightier than thyself,"], ["o aai tetele ua puipuia i pa e oo i le lagi,", "cities great and fenced up to heaven,"]]},
  {num:2,words:[["o le nuu malolosi ma le maualuluga,", "A people great and tall,"], ["o atalii o Anaki ua e iloa,", "the children of the Anakims,"], ["ma ua e faalogo ai,", "whom thou knowest,"], ["ua faapea ,", "and of whom thou hast heard say,"], ["Po o ai se na te tu atu i luma o atalii o Anaki?", "Who can stand before the children of Anak!"]]},
  {num:3,words:[["Ia e iloa foi i le aso nei,", "Understand therefore this day,"], ["o Ieova lou Atua, o ia na te sopomua atu ia te oe,", "that the LORD thy God is he which goeth over before thee;"], ["o le afi maamaai o ia,", "as a consuming fire he shall destroy them,"], ["na te faaumatia i latou,", "and he shall bring them down before thy face:"], ["na te faatoilaloina foi i latou i ou luma;", "so shalt thou drive them out,"], ["e te tulia foi i latou, ma vave faaumatia i latou,", "and destroy them quickly,"], ["faapei ona fetalai mai o Ieova ia te oe.", "as the LORD hath said unto thee."]]},
  {num:4,words:[["A tulia i latou e Ieova lou Atua ai ou luma,", "Speak not thou in thine heart,"], ["aua e te fai ifo i lou loto,", "after that the LORD thy God hath cast them out from before thee,"], ["e faapea,", "saying,"], ["O la'u amiotonu ua faaooina mai ai a'u e Ieova e fai mo'u lenei nuu;", "For my righteousness the LORD hath brought me in to possess this land:"], ["a o le amio leaga a ia nuu e tulia ai i latou e Ieova ai ou luma.", "but for the wickedness of these nations the LORD doth drive them out from before thee."]]},
  {num:5,words:[["E le ona o lau amiotonu ma le tonu o lou loto e te alu atu ai e fai mo oe lo latou nuu;", "Not for thy righteousness,"], ["a o le amio leaga a ia nuu e tulia ai i latou e Ieova lou Atua ai ou luma,", "or for the uprightness of thine heart, dost thou go to possess their land:"], ["ma ia na faataunuu ai le fetalaiga na tauto ai Ieova i ou tamā,", "but for the wickedness of these nations the LORD thy God doth drive them out from before thee,"], ["o Aperaamo,", "and that he may perform the word which the LORD sware unto thy fathers,"], ["o Isaako,", "Abraham, Isaac,"], ["ma Iakopo.", "and Jacob."]]},
  {num:6,words:[["Ia e iloa foi e le o lau amiotonu e foaiina atu ai e Ieova lou Atua ia te oe lena nuu lelei e fai mo oe;", "Understand therefore, that the LORD thy God giveth thee not this good land to possess it for thy righteousness;"], ["auā o oe o le nuu e maaa lava ua.", "for thou art a stiffnecked people."]]},
  {num:7,words:[["Ia e manatua,", "Remember,"], ["aua ne'i galo ia te oe o mea na e faatupuina ai le toasa o Ieova lou Atua i le vao;", "and forget not,"], ["e afua mai i le aso na e tuua ai le nuu o Aikupito,", "how thou provokedst the LORD thy God to wrath in the wilderness: from the day that thou didst depart out of the land of Egypt,"], ["e oo lava i lo outou o mai i le mea nei,", "until ye came unto this place,"], ["ua outou fou vale lava ia Ieova.", "ye have been rebellious against the LORD."]]},
  {num:8,words:[["O i Horepa foi na outou faatupuina le toasa o Ieova, ona toasa ai lea o Ieova ia te outou,", "Also in Horeb ye provoked the LORD to wrath,"], ["na fai a faaumatia outou e ia.", "so that the LORD was angry with you to have destroyed you."]]},
  {num:9,words:[["Na ou alu ae i le mauga e talia papamaa,", "When I was gone up into the mount to receive the tables of stone,"], ["o papa o i ai le feagaiga na osia e Ieova ma outou;", "even the tables of the covenant which the LORD made with you,"], ["ona ou nofo lea i le mauga e fagafulu o ao ma le fagafulu o po, ou te lei 'ai ai sina mea e 'ai,", "then I abode in the mount forty days and forty nights,"], ["ou te lei inu foi sina vai.", "I neither did eat bread nor drink water:"]]},
  {num:10,words:[["Ona tuu mai lea e Ieova ia te au o papamaa e lua sa tusia e le aao o le Atua,", "And the LORD delivered unto me two tables of stone written with the finger of God; and on them was written according to all the words,"], ["na i ai upu uma lava sa fetalai mai e Ieova ia te outou i le mauga mai totonu o le afi i le aso na fai ai le faapotopotoga.", "which the LORD spake with you in the mount out of the midst of the fire in the day of the assembly."]]},
  {num:11,words:[["Ua oo i le gataaga o le fagafulu o ao ma le fagafulu o po,", "And it came to pass at the end of forty days and forty nights,"], ["ona tuu mai ai lea e Ieova ia te au o papamaa e lua,", "that the LORD gave me the two tables of stone,"], ["o papa o i ai le feagaiga.", "even the tables of the covenant."]]},
  {num:12,words:[["Ona fetalai mai lea o Ieova ia te au,", "And the LORD said unto me,"], ["Tu ia i luga,", "Arise,"], ["ia vave ona e alu i lalo ai le mea nei,", "get thee down quickly from hence;"], ["auā o lou nuu na e aumaia nai Aikupito ua leaga lava i latou;", "for thy people which thou hast brought forth out of Egypt have corrupted themselves;"], ["ua vave ona latou o ese nai le ala na ou poloai atu ia te i latou;", "they are quickly turned aside out of the way which I commanded them;"], ["ua latou faia mo i latou le tupua uamea.", "they have made them a molten image."]]},
  {num:13,words:[["Ua fetalai mai foi Ieova ia te au,", "Furthermore the LORD spake unto me,"], ["ua faapea mai,", "saying,"], ["Ua ou iloa lenei nuu,", "I have seen this people, and,"], ["faauta foi,", "behold,"], ["o le nuu e maaa ua.", "it is a stiffnecked people:"]]},
  {num:14,words:[["Tuu mai ia o a'u,", "Let me alone,"], ["seia ou faaumatia i latou,", "that I may destroy them,"], ["ma soloiesea lo latou igoa ai le lalolagi,", "and blot out their name from under heaven:"], ["ou te faia foi oe ma tupuga o le nuu e malosi ma le toatele e sili ia te i latou.", "and I will make of thee a nation mightier and greater than they."]]},
  {num:15,words:[["Ona ou liliu lea,", "So I turned and came down from the mount,"], ["ma ou alu ifo nai le mauga, ua mu foi le mauga i le afi;", "and the mount burned with fire:"], ["sa i o'u lima e lua o papamaa e lua o le feagaiga.", "and the two tables of the covenant were in my two hands."]]},
  {num:16,words:[["Na ou vaai atu,", "And I looked,"], ["faauta foi,", "and,"], ["ua outou agasala ia Ieova lo outou Atua,", "behold, ye had sinned against the LORD your God,"], ["ua outou faia mo outou le tamai povi uamea;", "and had made you a molten calf:"], ["ua outou vave o ese i le ala na poloai ai Ieova ia te outou.", "ye had turned aside quickly out of the way which the LORD had commanded you."]]},
  {num:17,words:[["Ona ou umia lea o papamaa e lua,", "And I took the two tables,"], ["ma ou lafotuina ai e o'u lima e lua,", "and cast them out of my two hands,"], ["ma ou nutimomoia ai i o outou luma.", "and brake them before your eyes."]]},
  {num:18,words:[["Ona ou faapaū lea i luma o Ieova,", "And I fell down before the LORD,"], ["faapei ona muai faia ,", "as at the first,"], ["e fagafulu o ao ma le fagafulu o po,", "forty days and forty nights:"], ["ou te lei 'ai ai sina mea e 'ai,", "I did neither eat bread, nor drink water,"], ["ou te lei inu foi sina vai,", "because of all your sins which ye sinned,"], ["ona o a outou agasala uma lava na outou agasala ai,", "in doing wickedly in the sight of the LORD,"], ["ina ua faia mea leaga i luma o Ieova e faaonoono ia te ia.", "to provoke him to anger."]]},
  {num:19,words:[["Auā na ou fefe i le toatamai ma le toasa tele sa toasa ai Ieova ia te outou ia faaumatia ai outou;", "For I was afraid of the anger and hot displeasure,"], ["a ua faafofoga mai Ieova ia te au i lea foi aso.", "wherewith the LORD was wroth against you to destroy you. But the LORD hearkened unto me at that time also."]]},
  {num:20,words:[["Na toasa tele foi Ieova ia Arona, na fai a fano ai o ia,", "And the LORD was very angry with Aaron to have destroyed him:"], ["ona ou faatoga atu foi lea i lea aso mo Arona.", "and I prayed for Aaron also the same time."]]},
  {num:21,words:[["Ona ou tago lea i le mea sa outou agasala ai,", "And I took your sin,"], ["o le tamai povi na outou faia,", "the calf which ye had made,"], ["na ou susunuina i le afi,", "and burnt it with fire, and stamped it,"], ["ma a'u tu'ininiia,", "and ground it very small,"], ["ma a'u matuā oloina ua ninii e pei o le efuefu,", "even until it was as small as dust:"], ["na ou sasaa foi ona efuefu i le vaitafe e tafe ifo i le mauga.", "and I cast the dust thereof into the brook that descended out of the mount."]]},
  {num:22,words:[["Na outou faatupuina foi le toasa o Ieova i Tapara,", "And at Taberah,"], ["ma Mase,", "and at Massah, and at Kibroth-hattaavah,"], ["atoa ma Kiperota-atava.", "ye provoked the LORD to wrath."]]},
  {num:23,words:[["Na aauina atu foi outou e Ieova nai Katesapanea,", "Likewise when the LORD sent you from Kadesh-barnea,"], ["ua faapea mai,", "saying,"], ["Ia outou o ae e fai mo outou le nuu ua ou avatu ai ia te outou. Ona outou fouvale ai lea i le afioga a Ieova lo outou Atua,", "Go up and possess the land which I have given you; then ye rebelled against the commandment of the LORD your God,"], ["ua outou le faatuatua ia te ia,", "and ye believed him not,"], ["ma outou le faalogo i lona siufofoga.", "nor hearkened to his voice."]]},
  {num:24,words:[["Ua outou fouvale ia Ieova talu le aso na ou faatoa iloa ai outou.", "Ye have been rebellious against the LORD from the day that I knew you."]]},
  {num:25,words:[["Na ou faapaū i luma o Ieova i ao e fagafulu ma le fagafulu o po faapei ona ou muai faapaū ai;", "Thus I fell down before the LORD forty days and forty nights, as I fell down at the first;"], ["auā na fetalai mai Ieova o le a na faaumatia outou.", "because the LORD had said he would destroy you."]]},
  {num:26,words:[["Na ou aioi atu ai ia Ieova,", "I prayed therefore unto the LORD,"], ["ua faapea atu,", "and said,"], ["Le Alii e,", "O Lord GOD,"], ["Ieova,", "destroy not thy people and thine inheritance,"], ["aua e te faaumatia lou nuu ma lou tofi na e laveaiina i lou mana,", "which thou hast redeemed through thy greatness,"], ["ua e aumaia foi nai Aikupito i le aao malosi.", "which thou hast brought forth out of Egypt with a mighty hand."]]},
  {num:27,words:[["Ia e manatua au auauna o Aperaamo,", "Remember thy servants,"], ["o Isaako,", "Abraham,"], ["ma Iakopo;", "Isaac, and Jacob;"], ["aua e te silasila i le faalogogata o lenei nuu,", "look not unto the stubbornness of this people,"], ["ma a latou amio leaga,", "nor to their wickedness,"], ["ma a latou agasala;", "nor to their sin:"]]},
  {num:28,words:[["ne'i faapea mai le nuu na e au mai ai i matou,", "Lest the land whence thou broughtest us out say,"], ["Auā ua le mafaia e Ieova ona faaooina i latou i le nuu na ia folafolaina ai ia te i latou,", "Because the LORD was not able to bring them into the land which he promised them,"], ["auā foi ua 'ino'ino o ia ia te i latou,", "and because he hated them,"], ["o le mea lea ua ia avatu ai i latou i le vao e fasioti ai ia te i latou.", "he hath brought them out to slay them in the wilderness."]]},
  {num:29,words:[["A o lou nuu lava i latou ma lou tofi,", "Yet they are thy people and thine inheritance,"], ["o e na e aumaia i lou mana tele ma lou aao faaloaloa.", "which thou broughtest out by thy mighty power and by thy stretched out arm."]]},
];
renderVerseSet(deu_ch_9_Verses, 'deu-ch9-verses');

var deu_ch_10_Verses = [
  {num:1,words:[["O ona po ia na fetalai mai ai Ieova ia te au,", "At that time the LORD said unto me,"], ["Ia e ta mai ni papamaa se lua pei o papa muamua,", "Hew thee two tables of stone like unto the first,"], ["ma ia e alu ae ia te au i le mauga;", "and come up unto me into the mount,"], ["ia e faia foi se atolaau.", "and make thee an ark of wood."]]},
  {num:2,words:[["Ou te tusi foi i ia papa o upu sa i papa muamua na e nutimomoia,", "And I will write on the tables the words that were in the first tables which thou brakest,"], ["e te tuu ai foi i le atolaau.", "and thou shalt put them in the ark."]]},
  {num:3,words:[["Ona ou faia lea o le atolaau i le laau o le setima,", "And I made an ark of shittim wood,"], ["na ou ta foi o papamaa e lua pei o papa muamua,", "and hewed two tables of stone like unto the first,"], ["ona ou alu ae ai lea i le mauga,", "and went up into the mount,"], ["na i ai foi papa e lua i lo'u lima.", "having the two tables in mine hand."]]},
  {num:4,words:[["Ona tusi lea e ia i papa pei o upu na muai tusia,", "And he wrote on the tables,"], ["o upu e sefulu na fetalai mai ai Ieova ia te outou i le mauga,", "according to the first writing,"], ["mai totonu o le afi,", "the ten commandments,"], ["i le aso na fai ai le faapotopotoga,", "which the LORD spake unto you in the mount out of the midst of the fire in the day of the assembly:"], ["ona au mai ai lea e Ieova ia te au.", "and the LORD gave them unto me."]]},
  {num:5,words:[["Ona ou liliu lea,", "And I turned myself and came down from the mount,"], ["ma ou alu ifo nai le mauga,", "and put the tables in the ark which I had made;"], ["ua ou tuu foi papa i le atolaau na ou faia, o loo i ai lava,", "and there they be,"], ["faapei ona poloai mai ai o Ieova ia te au.", "as the LORD commanded me."]]},
  {num:6,words:[["Ona o atu ai lea o le fanauga a Isaraelu nai Perota o i Peneakana i Mosera;", "And the children of Israel took their journey from Beeroth of the children of Jaakan to Mosera:"], ["ua oti ai Arona,", "there Aaron died,"], ["ua tanumia ai foi;", "and there he was buried;"], ["ona fai ai lea ma ositaulaga o Eleasaro lona atalii e sui a'i o ia.", "and Eleazar his son ministered in the priest's office in his stead."]]},
  {num:7,words:[["Ua latou o atu i lea mea i Kikata,", "From thence they journeyed unto Gudgodah;"], ["na o atu foi na Kikata i Iatepata,", "and from Gudgodah to Jotbath,"], ["o le nuu lea o vaitafe.", "a land of rivers of waters."]]},
  {num:8,words:[["O ona poi a na vavaeeseina ai e Ieova o le itu aiga o Levi,", "At that time the LORD separated the tribe of Levi,"], ["ia latou tauave le atolaau o le feagaiga a Ieova,", "to bear the ark of the covenant of the LORD,"], ["ia latou tutū i luma o Ieova ia auauna ia te ia,", "to stand before the LORD to minister unto him,"], ["ma ia latou faamanuia atu i tagata i lona suafa,", "and to bless in his name,"], ["ua oo mai i le aso nei.", "unto this day."]]},
  {num:9,words:[["O le mea lea e le maua ai e Levi se fanua po o se tofi faatasi ma ona uso;", "Wherefore Levi hath no part nor inheritance with his brethren;"], ["o Ieova o lona tofi ia,", "the LORD is his inheritance,"], ["faapei ona fetalai mai ai o Ieova lou Atua ia te ia.", "according as the LORD thy God promised him."]]},
  {num:10,words:[["Na ou i ai pea i le mauga i ao e fagafulu ma po e fagafulu,", "And I stayed in the mount,"], ["pei o ona aso muamua;", "according to the first time,"], ["na faafofoga mai Ieova ia te au i ona po ia foi,", "forty days and forty nights; and the LORD hearkened unto me at that time also,"], ["i le ua le finagalo Ieova e faauma ia te oe.", "and the LORD would not destroy thee."]]},
  {num:11,words:[["Ona fetalai mai lea o Ieova ia te au,", "And the LORD said unto me,"], ["Tu ia i luga,", "Arise,"], ["ina e alu ia e muamua i le nuu,", "take thy journey before the people,"], ["ia latou oo atu,", "that they may go in and possess the land,"], ["ma ia fai mo latou le nuu na ou tauto ai i o latou tamā e foai atu ia te i latou.", "which I sware unto their fathers to give unto them."]]},
  {num:12,words:[["O lenei,", "And now,"], ["Isaraelu e,", "Israel,"], ["se a se mea e finagalo i ai Ieova lou Atua ia te oe,", "what doth the LORD thy God require of thee,"], ["na ona ia e mata'u ia Ieova lou Atua,", "but to fear the LORD thy God,"], ["ina ia e savali i ona ala uma lava,", "to walk in all his ways,"], ["ma ia e alofa atu ia te ia,", "and to love him,"], ["ma ia e auauna ia Ieova lou Atua ma lou loto atoa ma lou agaga atoa,", "and to serve the LORD thy God with all thy heart and with all thy soul,"]]},
  {num:13,words:[["ina ia e tausiusi i poloaiga a Ieova ma ana tulafono ou te fai atu ai ia te oe i le aso nei,", "To keep the commandments of the LORD, and his statutes,"], ["ina ia manuia ai oe?", "which I command thee this day for thy good?"]]},
  {num:14,words:[["Faauta,", "Behold,"], ["o ia Ieova lou Atua le lagi ma le lagi o lagi,", "the heaven and the heaven of heavens is the LORD'S thy God,"], ["o le lalolagi foi,", "the earth also,"], ["ma mea uma lava o i ai.", "with all that therein is."]]},
  {num:15,words:[["A ua fiafia Ieova i ou tamā, ua alofa ia te i latou,", "Only the LORD had a delight in thy fathers to love them,"], ["ua ia filifilia foi a latou fanau ina ua mavae atu i latou,", "and he chose their seed after them,"], ["o outou lava ia,", "even you above all people,"], ["a e tuua nuu uma, pei ona fai i le aso nei.", "as it is this day."]]},
  {num:16,words:[["O lenei, ia outou peritomeina le pa'u o outou loto,", "Circumcise therefore the foreskin of your heart,"], ["aua ne'i toe maaa o outou ua.", "and be no more stiffnecked."]]},
  {num:17,words:[["Auā o Ieova lo outou Atua o le Atua o atua ia,", "For the LORD your God is God of gods,"], ["o le Alii o alii,", "and Lord of lords, a great God,"], ["o le Atua silisili,", "a mighty,"], ["e mamana o ia ma le matautia,", "and a terrible, which regardeth not persons,"], ["o le na te le faailogaina tagata,", "nor taketh reward:"]]},
  {num:18,words:[["e le talia foi e ia se taui;", "He doth execute the judgment of the fatherless and widow,"], ["o le na te faamasinoina mo le ua mātuaoti ma le fafine ua oti lana tane; o le alofa atu i le tagata ese,", "and loveth the stranger,"], ["ua avatu ai ia te ia le mea e 'ai atoa ma ofu.", "in giving him food and raiment."]]},
  {num:19,words:[["O lenei foi, ia outou alolofa atu i le tagata ese;", "Love ye therefore the stranger:"], ["auā foi sa tagata ese outou i le nuu o Aikupito.", "for ye were strangers in the land of Egypt."]]},
  {num:20,words:[["Ia e mata'u ia Ieova lou Atua,", "Thou shalt fear the LORD thy God;"], ["ia e auauna ia te ia,", "him shalt thou serve,"], ["ia e pipii foi ia te ia,", "and to him shalt thou cleave,"], ["ma ia e tauto i lona suafa.", "and swear by his name."]]},
  {num:21,words:[["O ia lava lē e te viia,", "He is thy praise,"], ["o ia foi o lou Atua,", "and he is thy God, that hath done for thee these great and terrible things,"], ["o le na faia mo oe nā mea tetele ma le matautia na vaai i ai ou mata.", "which thine eyes have seen."]]},
  {num:22,words:[["Na o ifo i Aikupito ou tamā na o le toafitugafulu i latou;", "Thy fathers went down into Egypt with threescore and ten persons;"], ["a o nei ona po ua faatoateleina oe e Ieova lou Atua e pei o fetu o le lagi ona tele.", "and now the LORD thy God hath made thee as the stars of heaven for multitude."]]},
];
renderVerseSet(deu_ch_10_Verses, 'deu-ch10-verses');

var deu_ch_11_Verses = [
  {num:1,words:[["O lenei ia e alofa atu ia Ieova lou Atua ma ia e tausiusi i ana sauniga ma ana tulafono ma ana faamasinoga ma ana poloaiga i aso uma lava.", "Therefore thou shalt love the LORD thy God, and keep his charge, and his statutes, and his judgments, and his commandments, alway."]]},
  {num:2,words:[["Ia outou iloa foi i le aso nei,", "And know ye this day: for I speak not with your children which have not known,"], ["auā ou te le fai atu i a outou fanau o e na le iloa,", "and which have not seen the chastisement of the LORD your God,"], ["ma ua le vaai atu i le aoaiga a Ieova lo outou Atua o lona silisili,", "his greatness,"], ["ma lona aao malosi,", "his mighty hand, and his stretched out arm,"]]},
  {num:3,words:[["ma lona aao faaloaloa,", "And his miracles,"], ["ma ona vavega ma ana galuega na ia faia i Aikupito ia Farao le tupu o Aikupito,", "and his acts, which he did in the midst of Egypt unto Pharaoh the king of Egypt,"], ["atoa ma lona nuu uma;", "and unto all his land;"]]},
  {num:4,words:[["ma mea na faia e ia i le itu taua a Aikupito,", "And what he did unto the army of Egypt,"], ["i a latou solofanua ma o latou kariota,", "unto their horses,"], ["na ia faalofia ifo i latou i le suāsami o le sami Ulaula ina o latou tuliloa ia te outou;", "and to their chariots; how he made the water of the Red sea to overflow them as they pursued after you,"], ["ua faaumatia foi i latou e Ieova na oo mai i nei ona po;", "and how the LORD hath destroyed them unto this day;"]]},
  {num:5,words:[["ma mea na ia faia ia te outou i le vao ua oo i lo outou o mai i le mea nei;", "And what he did unto you in the wilderness, until ye came into this place;"]]},
  {num:6,words:[["atoa ma mea na ia faia ia Tatano ma Apiramo o atalii o Eliapo,", "And what he did unto Dathan and Abiram,"], ["o le atalii o Reupena,", "the sons of Eliab, the son of Reuben:"], ["ina ua faamaga le gutu o le eleele,", "how the earth opened her mouth,"], ["ma folo ifo ia te i latou,", "and swallowed them up,"], ["ma o latou aiga,", "and their households,"], ["ma o latou fale ie,", "and their tents, and all the substance that was in their possession,"], ["atoa ma a latou mea uma i luma o Isaraelu uma lava;", "in the midst of all Israel:"]]},
  {num:7,words:[["a ua vaai atu o outou lava mata i mea tetele uma ua faia e Ieova.", "But your eyes have seen all the great acts of the LORD which he did."]]},
  {num:8,words:[["Lenei la,", "Therefore shall ye keep all the commandments which I command you this day,"], ["ia outou tausiusi i poloaiga uma lava ou te fai atu ai ia te outou i le aso nei,", "that ye may be strong,"], ["ina ia outou malolosi ai, tou te oo atu ai,", "and go in and possess the land,"], ["ma fai mo outou le nuu o le a outou o atu i ai e fai mo outou;", "whither ye go to possess it;"]]},
  {num:9,words:[["ina ia outou nofo tulu'i i le laueleele na tauto ai Ieova i o outou tamā e foaiina atu ia te i latou ma a latou fanau,", "And that ye may prolong your days in the land, which the LORD sware unto your fathers to give unto them and to their seed,"], ["o le nuu o tafe ai le suāsusu ma le meli.", "a land that floweth with milk and honey."]]},
  {num:10,words:[["Auā o le nuu a ē alu i ai e fai mo oe,", "For the land,"], ["e le pei o le nuu o Aikupito na outou o mai ai,", "whither thou goest in to possess it, is not as the land of Egypt,"], ["na e luluina ai lau saito,", "from whence ye came out,"], ["ma faasūsūina ai i lou vae,", "where thou sowedst thy seed, and wateredst it with thy foot,"], ["pei o se fanua a laau iti e 'aina;", "as a garden of herbs:"]]},
  {num:11,words:[["a o le nuu a outou o atu i ai e fai mo outou,", "But the land, whither ye go to possess it,"], ["o le nuu lea o mauga ma vanu e inu lava i le suāua mai le lagi.", "is a land of hills and valleys, and drinketh water of the rain of heaven:"]]},
  {num:12,words:[["O le nuu e tausia e Ieova lou Atua e le aunoa ona silasila i ai o Ieova lou Atua,", "A land which the LORD thy God careth for: the eyes of the LORD thy God are always upon it,"], ["e afua mai i le amataga o le tausaga e oo atu lava i le gataaga o le tausaga.", "from the beginning of the year even unto the end of the year."]]},
  {num:13,words:[["Afai foi tou te matuā faalogo i a'u poloaiga ou te fai atu ai ia te outou i le aso nei,", "And it shall come to pass,"], ["ia outou alofa atu ia Ieova lo outou Atua,", "if ye shall hearken diligently unto my commandments which I command you this day, to love the LORD your God,"], ["ma auauna ia te ia ma o outou loto atoa ma o outou agaga atoa,", "and to serve him with all your heart and with all your soul,"]]},
  {num:14,words:[["ona ou foaiina atu lea o le ua i lo outou nuu i ona tausaga,", "That I will give you the rain of your land in his due season,"], ["o le uaga muamua ma le uaga mulimuli,", "the first rain and the latter rain,"], ["e te faapotopoto ai foi lau saito,", "that thou mayest gather in thy corn,"], ["ma lau uaina,", "and thy wine,"], ["ma lau suāuu.", "and thine oil."]]},
  {num:15,words:[["Ou te tuuina atu foi laau iti i lou laueleele mā au manu; e te 'ai foi,", "And I will send grass in thy fields for thy cattle,"], ["ma e ma'ona ai.", "that thou mayest eat and be full."]]},
  {num:16,words:[["Ia outou,", "Take heed to yourselves,"], ["ne'i pelogia o outou loto,", "that your heart be not deceived,"], ["tou te o ese ai ma auauna i atua ese,", "and ye turn aside, and serve other gods,"], ["ma ifo i ai;", "and worship them;"]]},
  {num:17,words:[["ona tupu ai lea o le toasa o Ieova ia te outou,", "And then the LORD'S wrath be kindled against you,"], ["ona pupuni ai lea e ia o le lagi,", "and he shut up the heaven,"], ["ina ia leai ni ua,", "that there be no rain,"], ["ia le fua mai foi le laueleele ni ona fua;", "and that the land yield not her fruit;"], ["ona outou vave fano ai lea ma te'a i le nuu lelei o le a foai mai e Ieova ia te outou.", "and lest ye perish quickly from off the good land which the LORD giveth you."]]},
  {num:18,words:[["O lenei ia outou tuu nei upu i o outou loto ma o outou manatu,", "Therefore shall ye lay up these my words in your heart and in your soul,"], ["ia fusi foi e fai ma faailoga i o outou lima,", "and bind them for a sign upon your hand,"], ["e avea foi ma pale i le va o outou mata.", "that they may be as frontlets between your eyes."]]},
  {num:19,words:[["Ia outou a'oa'o atu ai i a outou fanau,", "And ye shall teach them your children,"], ["ma tautalatala a'i pe a e nofo i lou fale,", "speaking of them when thou sittest in thine house,"], ["pe a e savali foi i le ala,", "and when thou walkest by the way,"], ["pe a e taoto,", "when thou liest down,"], ["pe a e tulai foi.", "and when thou risest up."]]},
  {num:20,words:[["Ia e tusi ai foi i pou o lou fale atoa ma puipui;", "And thou shalt write them upon the door posts of thine house, and upon thy gates:"]]},
  {num:21,words:[["ina ia faateleina ai o outou aso ma aso o a outou fanau i le laueleele na tauto ai Ieova i o outou tamā,", "That your days may be multiplied,"], ["e avatu ia te i latou,", "and the days of your children, in the land which the LORD sware unto your fathers to give them,"], ["ia pei o aso e i ai le lagi i luga o le lalolagi.", "as the days of heaven upon the earth."]]},
  {num:22,words:[["Auā afai tou te matuā tausiusi i nei poloaiga uma lava ou te fai atu ai ia te outou ia faia,", "For if ye shall diligently keep all these commandments which I command you,"], ["ia outou alofa atu ia Ieova lo outou Atua,", "to do them,"], ["ia savavali i ona ala uma lava,", "to love the LORD your God, to walk in all his ways,"], ["ma ia pipii atu ia te ia;", "and to cleave unto him;"]]},
  {num:23,words:[["ona tulia lea e Ieova o ia nuu uma lava ai o outou luma,", "Then will the LORD drive out all these nations from before you,"], ["tou te fai ai foi mo outou o nuu e sili ona toatele ma le malolosi ia te outou.", "and ye shall possess greater nations and mightier than yourselves."]]},
  {num:24,words:[["E fai mo outou o mea uma lava e solia e o outou alofivae;", "Every place whereon the soles of your feet shall tread shall be your's:"], ["e gata mai i le vao e oo i Lepanona,", "from the wilderness and Lebanon,"], ["'e gata mai foi i le vaitafe o le vaitafe o Eufirate e oo atu i le sami tupito,", "from the river, the river Euphrates,"], ["a avea ia ma o outou tuaoi.", "even unto the uttermost sea shall your coast be."]]},
  {num:25,words:[["E le tu mai se tagata e tetee ia te outou,", "There shall no man be able to stand before you:"], ["o Ieova lo outou Atua na te tuuina atu le mata'u ma le fefe ona o outou i le nuu uma lava o le a savavali i ai outou,", "for the LORD your God shall lay the fear of you and the dread of you upon all the land that ye shall tread upon,"], ["faapei ona fetalai mai o ia ia te outou.", "as he hath said unto you."]]},
  {num:26,words:[["Faauta mai,", "Behold,"], ["ou te tuuina atu i o outou luma i le aso nei le manuia ma le malaia;", "I set before you this day a blessing and a curse;"]]},
  {num:27,words:[["o le manuia pe afai tou te faalogo i poloaiga a Ieova lo outou Atua,", "A blessing, if ye obey the commandments of the LORD your God,"], ["ou te fai atu ai ia te outou i le aso nei;", "which I command you this day:"]]},
  {num:28,words:[["a o le malaia pe afai tou te le faalogo i poloaiga a Ieova lo outou Atua,", "And a curse, if ye will not obey the commandments of the LORD your God,"], ["a e o ese i le ala ou te fai atu ai ia te outou i le aso nei,", "but turn aside out of the way which I command you this day,"], ["tou te mulimuli ai i atua ese ua outou le iloa.", "to go after other gods, which ye have not known."]]},
  {num:29,words:[["A iu ina faaooina atu oo e Ieova lou Atua i le nuu o le a e alu i ai e fai mo oe,", "And it shall come to pass,"], ["ona e tuuina lea o le manuia i le mauga o Keresema,", "when the LORD thy God hath brought thee in unto the land whither thou goest to possess it, that thou shalt put the blessing upon mount Gerizim,"], ["ma le malaia i le mauga o Evalu.", "and the curse upon mount Ebal."]]},
  {num:30,words:[["E le o i ai ea ia mauga i tala atu o Ioritana i le itu e alu ifo ai le la,", "Are they not on the other side Jordan, by the way where the sun goeth down,"], ["i le nuu o sa Kananā e o nonofo i le eleele laugatasi e fesagai ma Kilikala,", "in the land of the Canaanites,"], ["e latalata ane i aluna o Morē?", "which dwell in the champaign over against Gilgal, beside the plains of Moreh?"]]},
  {num:31,words:[["Auā a outou sopoia atu Ioritana e oo atu e fai mo outou le nuu o le a foai mai ia te outou e Ieova lo outou Atua,", "For ye shall pass over Jordan to go in to possess the land which the LORD your God giveth you,"], ["e faia foi mo outou,", "and ye shall possess it,"], ["ma outou nonofo ai,", "and dwell therein."]]},
  {num:32,words:[["ia outou tausiusi ia faia o tulafono uma, ma faamasinoga ou te tuuina atu i o outou luma i le aso nei.", "And ye shall observe to do all the statutes and judgments which I set before you this day."]]},
];
renderVerseSet(deu_ch_11_Verses, 'deu-ch11-verses');

var deu_ch_12_Verses = [
  {num:1,words:[["O tulafono ia ma faamasinoga tou te tausiusi i ai ia faia i le nuu o le a foaiina mai ia te oe e Ieova le Atua o ou tamā,", "These are the statutes and judgments,"], ["ina ia fai mo outou,", "which ye shall observe to do in the land, which the LORD God of thy fathers giveth thee to possess it,"], ["i aso uma tou te ola ai i le fogaeleele.", "all the days that ye live upon the earth."]]},
  {num:2,words:[["Ia outou matuā faaumatia mea uma lava na auauna a'i i o latou atua o nuu o le a fai mo outou,", "Ye shall utterly destroy all the places, wherein the nations which ye shall possess served their gods,"], ["i luga i mauga maualuluga ma mauga iti,", "upon the high mountains,"], ["o i lalo ifo foi o laau lauolaola uma.", "and upon the hills, and under every green tree:"]]},
  {num:3,words:[["Ia outou sofaia o latou fata faitaulaga,", "And ye shall overthrow their altars,"], ["ia outou nutipalaina foi o latou tupua,", "and break their pillars,"], ["ma susunu i le afi o latou tupua o Asaira;", "and burn their groves with fire;"], ["ia outou vavae i lalo foi o tupua ua ta o latou atua,", "and ye shall hew down the graven images of their gods,"], ["ia outou tineia foi o latou igoa ai lea lava mea.", "and destroy the names of them out of that place."]]},
  {num:4,words:[["Aua lava tou te faapea ona fai ia Ieova lo outou Atua.", "Ye shall not do so unto the LORD your God."]]},
  {num:5,words:[["A o le mea e filifilia e Ieova lo outou Atua ai o outou itu aiga uma lava e tuu ai lona suafa,", "But unto the place which the LORD your God shall choose out of all your tribes to put his name there, even unto his habitation shall ye seek,"], ["o lona afioaga lava ia outou sailiili i ai ma e alu atu i ai.", "and thither thou shalt come:"]]},
  {num:6,words:[["Ia outou ave i ai a outou taulaga mu,", "And thither ye shall bring your burnt offerings,"], ["ma a outou taulaga,", "and your sacrifices,"], ["ma le mea e sefulu a'i a outou mea,", "and your tithes,"], ["ma taulaga sii a o outou lima,", "and heave offerings of your hand,"], ["ma mea ua outou tauto ai,", "and your vows,"], ["ma a outou taulaga tou te loto ina fai,", "and your freewill offerings,"], ["atoa ma uluai tama a outou povi ma a outou mamoe.", "and the firstlings of your herds and of your flocks:"]]},
  {num:7,words:[["Tou te aai ai i lea mea i luma o Ieova lo outou Atua,", "And there ye shall eat before the LORD your God,"], ["tou te olioli foi i mea uma lava e faia i o outou lima,", "and ye shall rejoice in all that ye put your hand unto,"], ["o outou atoa ma o outou aiga,", "ye and your households,"], ["o mea ua faamanuia ai oe e Ieova lou Atua.", "wherein the LORD thy God hath blessed thee."]]},
  {num:8,words:[["Tou te le faia e pei o mea uma ua fai e i tatou iinei i le aso nei,", "Ye shall not do after all the things that we do here this day,"], ["o loo taitasi le tagata ma fai mea uma ua tonu i lona manatu.", "every man whatsoever is right in his own eyes."]]},
  {num:9,words:[["Auā ona po nei ua le oo lava outou i le malologa ma le tofi ua foaiina ia te outou e Ieova lo outou Atua.", "For ye are not as yet come to the rest and to the inheritance, which the LORD your God giveth you."]]},
  {num:10,words:[["A e tou te sopoia atu Ioritana,", "But when ye go over Jordan,"], ["ma outou nonofo i le nuu ua foaiina mai e Ieova lo outou Atua e fai mo outou tofi;", "and dwell in the land which the LORD your God giveth you to inherit,"], ["na te avatua foi le mapusaga ia te outou ai o outou fili uma lava i itu uma,", "and when he giveth you rest from all your enemies round about,"], ["ma outou nonofo ai ma le filemu.", "so that ye dwell in safety;"]]},
  {num:11,words:[["O le mea foi e filifilia e Ieova lo outou Atua e tuu ai lona suafa,", "Then there shall be a place which the LORD your God shall choose to cause his name to dwell there;"], ["o le mea lea tou te ave i ai mea uma lava ou te fai atu ai ia te outou;", "thither shall ye bring all that I command you;"], ["o a outou taulaga mu,", "your burnt offerings,"], ["ma a outou taulaga, ma mea e sefulu a'i a outou mea,", "and your sacrifices,"], ["ma taulaga sii a o outou lima,", "your tithes,"], ["ma mea uma e sili ua outou tauto ai,", "and the heave offering of your hand,"], ["ua outou tauto ai ia Ieova;", "and all your choice vows which ye vow unto the LORD:"]]},
  {num:12,words:[["tou te olioli foi i luma o Ieova lo outou Atua,", "And ye shall rejoice before the LORD your God,"], ["o outou,", "ye,"], ["ma o outou atalii,", "and your sons,"], ["ma o outou afafine,", "and your daughters,"], ["ma a outou auauna tane,", "and your menservants,"], ["ma a outou auauna fafine,", "and your maidservants,"], ["ma le sa Levī o i a outou aai,", "and the Levite that is within your gates;"], ["auā e leai sona fanua po o sona tofi faatasi ma outou.", "forasmuch as he hath no part nor inheritance with you."]]},
  {num:13,words:[["Ia oe, ne'i e fai au taulaga mu i mea uma e te vaai i ai;", "Take heed to thyself that thou offer not thy burnt offerings in every place that thou seest:"]]},
  {num:14,words:[["a e tau lava o le mea e filifilia e Ieova i se tasi o outou itu aiga,", "But in the place which the LORD shall choose in one of thy tribes,"], ["e te fai ai au taulaga mu,", "there thou shalt offer thy burnt offerings,"], ["e te fai ai foi mea uma lava ou te fai atu ai ia te oe.", "and there thou shalt do all that I command thee."]]},
  {num:15,words:[["A e peitai o mea uma e te manao i ai,", "Notwithstanding thou mayest kill and eat flesh in all thy gates,"], ["ia e fasia,", "whatsoever thy soul lusteth after,"], ["ma e 'ai i manu,", "according to the blessing of the LORD thy God which he hath given thee:"], ["e tusa ma le manuia mai ia Ieova lou Atua ua ia foaiina mai ia te oe i au aai uma;", "the unclean and the clean may eat thereof,"], ["o le ua leaga ma le ua mamā la te aai ai,", "as of the roebuck,"], ["e pei ona ' aina o le sevi ma le aila.", "and as of the hart."]]},
  {num:16,words:[["A o le toto, aua tou te aai ai;", "Only ye shall not eat the blood;"], ["tou te sasaaina lea i le eleele e pei o le suāvai.", "ye shall pour it upon the earth as water."]]},
  {num:17,words:[["E te le 'ai lava i au aai o mea e sefulu a'i lau saito,", "Thou mayest not eat within thy gates the tithe of thy corn,"], ["ma lau uaina, ma lau suāuu,", "or of thy wine,"], ["po o uluai tama a au povi,", "or of thy oil,"], ["ma au mamoe,", "or the firstlings of thy herds or of thy flock,"], ["ma au mea uma ua e tauto ai,", "nor any of thy vows which thou vowest,"], ["ua e tauto ai lava, ma au taulaga e te loto ina fai,", "nor thy freewill offerings,"], ["ma taulaga sii a lou lima;", "or heave offering of thine hand:"]]},
  {num:18,words:[["auā o mea nā e te 'ai ai i luma o Ieova lou Atua i le mea e filifilia e Ieova lou Atua,", "But thou must eat them before the LORD thy God in the place which the LORD thy God shall choose,"], ["o oe,", "thou,"], ["ma lou atalii,", "and thy son,"], ["ma lou afafine,", "and thy daughter,"], ["ma lau auauna tane, ma lau auauna fafine,", "and thy manservant,"], ["ma le sa Levī o i lau aai;", "and thy maidservant,"], ["e te olioli foi i luma o Ieova lou Atua,", "and the Levite that is within thy gates:"], ["i mea uma lava e te faia i ou lima.", "and thou shalt rejoice before the LORD thy God in all that thou puttest thine hands unto."]]},
  {num:19,words:[["Ia oe, ne'i e tuulafoai le sa Levī i ou aso uma e te mau ai i lou fanua.", "Take heed to thyself that thou forsake not the Levite as long as thou livest upon the earth."]]},
  {num:20,words:[["A faalauteleina e Ieova lou Atua lou laueleele,", "When the LORD thy God shall enlarge thy border,"], ["e faapei ona ia fetalaia mai ia te oe,", "as he hath promised thee,"], ["ma e fai ane,", "and thou shalt say,"], ["Ou te 'ai manu;", "I will eat flesh,"], ["auā e manao lou loto e 'ai manu;", "because thy soul longeth to eat flesh;"], ["ona e ai ai lea i manu,", "thou mayest eat flesh,"], ["i mea uma e manao i ai lou loto.", "whatsoever thy soul lusteth after."]]},
  {num:21,words:[["A vava mamao ma oe le mea ua filifilia e Ieova lou Atua e tuu ai lona suafa,", "If the place which the LORD thy God hath chosen to put his name there be too far from thee,"], ["ona e fasi ai lea ni au povi ma ni au mamoe,", "then thou shalt kill of thy herd and of thy flock,"], ["ua foaiina mai e Ieova lou Atua ia te oe,", "which the LORD hath given thee,"], ["e faapei ona ou fai atu ai ia te oe,", "as I have commanded thee,"], ["e te 'ai foi i au aai i mea uma e manao i ai lou loto.", "and thou shalt eat in thy gates whatsoever thy soul lusteth after."]]},
  {num:22,words:[["E pei ona 'aina o le sevi ma le aila,", "Even as the roebuck and the hart is eaten,"], ["e faapea ona e 'ai ai o na mea;", "so thou shalt eat them:"], ["o le ua leaga atoa ma le ua mamā la te aai ai.", "the unclean and the clean shall eat of them alike."]]},
  {num:23,words:[["A o le toto,", "Only be sure that thou eat not the blood:"], ["aua lava e te 'ai ai; auā o le toto o le ola lava lea;", "for the blood is the life;"], ["aua e te 'ai le ola faatasi ma le tino.", "and thou mayest not eat the life with the flesh."]]},
  {num:24,words:[["Aua e te 'ai ai;", "Thou shalt not eat it;"], ["e te sasaaina lea i le eleele e pei o le suāvai.", "thou shalt pour it upon the earth as water."]]},
  {num:25,words:[["E te le 'ai ai lava;", "Thou shalt not eat it;"], ["ina ia manuia ai oe ma au fanau pe a mavae atu oe,", "that it may go well with thee, and with thy children after thee,"], ["pe a e faia le mea tonu i luma o Ieova.", "when thou shalt do that which is right in the sight of the LORD."]]},
  {num:26,words:[["A o au mea paia o ia te oe,", "Only thy holy things which thou hast,"], ["ma au mea ua e tauto ai,", "and thy vows,"], ["ia e ave,", "thou shalt take,"], ["ma e alu i le mea e filifilia e Ieova.", "and go unto the place which the LORD shall choose:"]]},
  {num:27,words:[["Ia e osia au taulaga mu,", "And thou shalt offer thy burnt offerings,"], ["o tufaaga ma le toto,", "the flesh and the blood,"], ["i luga o le fata faitaulaga o Ieova lou Atua;", "upon the altar of the LORD thy God:"], ["o le toto foi o au taulaga ia e sasaa i luga o le fata faitaulaga o Ieova lou Atua,", "and the blood of thy sacrifices shall be poured out upon the altar of the LORD thy God,"], ["a o tufaaga e te 'ai ai.", "and thou shalt eat the flesh."]]},
  {num:28,words:[["Ia e anaana mai,", "Observe and hear all these words which I command thee,"], ["ma e faalogo mai i nei upu uma ou te fai atu ai ia te oe,", "that it may go well with thee,"], ["ina ia manuia ai oe ma au fanau pe a mavae atu oe, e oo i le faavavau,", "and with thy children after thee for ever,"], ["pe a e faia le mea lelei ma le tonu i luma o Ieova lou Atua.", "when thou doest that which is good and right in the sight of the LORD thy God."]]},
  {num:29,words:[["A faaumatia i ou luma e Ieova lou Atua o ia nuu e te alu i ai e fai mou,", "When the LORD thy God shall cut off the nations from before thee,"], ["a e fai mou lava,", "whither thou goest to possess them, and thou succeedest them,"], ["ma e nofo i o latou nuu;", "and dwellest in their land;"]]},
  {num:30,words:[["ia oe,", "Take heed to thyself that thou be not snared by following them,"], ["ne'i maileia oe i lou mulimuli atu ia te i latou,", "after that they be destroyed from before thee;"], ["pe a faaumatia i latou i ou luma; aua foi ne'i e saili atu i o latou atua,", "and that thou enquire not after their gods,"], ["o loo faapea ane,", "saying,"], ["Pe faapefea ona auauna nuu nei i o latou atua? ou te faia faapea lava e a'u.", "How did these nations serve their gods? even so will I do likewise."]]},
  {num:31,words:[["Aua lava ne'i e faia faapea ia Ieova lou Atua;", "Thou shalt not do so unto the LORD thy God:"], ["auā o mea uma e inosia e Ieova,", "for every abomination to the LORD,"], ["o loo inosia lava e ia,", "which he hateth,"], ["ua latou faia i o latou atua;", "have they done unto their gods;"], ["auā ua latou susunu i le afi o latou atalii ma o latou afafine e fai ma taulaga i o latou atua.", "for even their sons and their daughters they have burnt in the fire to their gods."]]},
  {num:32,words:[["O mea uma lava ou te fai atu ai ia te outou,", "What thing soever I command you,"], ["ia outou tausiusi i ai e fai;", "observe to do it:"], ["aua ne'i e faaopoopo i ai se mea ,", "thou shalt not add thereto,"], ["aua foi ne'i e ave ese ai se mea.", "nor diminish from it."]]},
];
renderVerseSet(deu_ch_12_Verses, 'deu-ch12-verses');

var deu_ch_13_Verses = [
  {num:1,words:[["Afai e tu mai ia te oe se perofeta,", "If there arise among you a prophet,"], ["po o se faimiti,", "or a dreamer of dreams,"], ["na te tuu atu foi ia te oe se faailoga po o se vavega,", "and giveth thee a sign or a wonder,"]]},
  {num:2,words:[["a taunuu foi lea faailoga po o lea vavega,", "And the sign or the wonder come to pass,"], ["na ia fai atu ai ia te oe,", "whereof he spake unto thee,"], ["o loo faapea,", "saying,"], ["Ina tatou mulimuli atu ia i atua ese,", "Let us go after other gods,"], ["o e na outou le iloa,", "which thou hast not known,"], ["ma ia tatou auauna i ai;", "and let us serve them;"]]},
  {num:3,words:[["aua ne'i e faalogo i upu a lea perofeta,", "Thou shalt not hearken unto the words of that prophet,"], ["po o lena faimiti;", "or that dreamer of dreams:"], ["auā e tofotofoina ai outou e Ieova lo outou Atua,", "for the LORD your God proveth you,"], ["ina ia silafia pe tou te alofa atu ia Ieova lo outou Atua ma o outou loto atoa ma o outou agaga atoa.", "to know whether ye love the LORD your God with all your heart and with all your soul."]]},
  {num:4,words:[["Tou te mulimuli atu ia Ieova lo outou Atua,", "Ye shall walk after the LORD your God,"], ["ma outou matatau ia te ia,", "and fear him,"], ["ma tausiusi i ana poloaiga,", "and keep his commandments,"], ["tou te faalogo foi i lona siufofoga,", "and obey his voice,"], ["ma outou auauna ia te ia,", "and ye shall serve him,"], ["ma pipii atu ia te ia.", "and cleave unto him."]]},
  {num:5,words:[["A o lena perofeta,", "And that prophet,"], ["po o lena faimiti,", "or that dreamer of dreams,"], ["e fasiotia o ia;", "shall be put to death;"], ["auā ua ia tautala ia tea ese outou ia Ieova lo outou Atua,", "because he hath spoken to turn you away from the LORD your God,"], ["o le na aumaia outou ai le nuu o Aikupito,", "which brought you out of the land of Egypt,"], ["ma na laveaiina oe ai le mea sa nofo pologa ai,", "and redeemed you out of the house of bondage,"], ["ina ia tuleia ai oe nai le ala na fetalai mai ai Ieova lou Atua ia e savali i ai. Ona e tuueseina ai lea o le leaga ia te oe.", "to thrust thee out of the way which the LORD thy God commanded thee to walk in. So shalt thou put the evil away from the midst of thee."]]},
  {num:6,words:[["Afai e faoso lemu ia te oe lou uso,", "If thy brother,"], ["le tama a lou tinā,", "the son of thy mother,"], ["po o lou atalii,", "or thy son,"], ["po o lou afafine,", "or thy daughter,"], ["po o lau avā pele,", "or the wife of thy bosom,"], ["po o lau uo e pele ia te oe,", "or thy friend,"], ["o loo faapea mai,", "which is as thine own soul, entice thee secretly,"], ["Ina tatou o ia,", "saying,"], ["ma auauna i atua ese,", "Let us go and serve other gods,"], ["na e le iloa,", "which thou hast not known,"], ["o oe,", "thou,"], ["ma ou tamā;", "nor thy fathers;"]]},
  {num:7,words:[["o atua o nuu e vagavagai ai outou,", "Namely,"], ["po o e felatai ma oe,", "of the gods of the people which are round about you,"], ["po o e vava mamao ma oe,", "nigh unto thee, or far off from thee,"], ["e gata mai i le tasi itu lalolagi e oo atu i le tasi itu lalolagi;", "from the one end of the earth even unto the other end of the earth;"]]},
  {num:8,words:[["aua e te gauai ia te ia,", "Thou shalt not consent unto him,"], ["aua foi e te faalogo ia te ia;", "nor hearken unto him;"], ["aua ne'i e alofa ia te ia,", "neither shall thine eye pity him,"], ["aua ne'i e faasao ia te ia,", "neither shalt thou spare,"], ["aua foi ne'i e ufiufi ia te ia;", "neither shalt thou conceal him:"]]},
  {num:9,words:[["a ia e matuā fasioti ia te ia;", "But thou shalt surely kill him;"], ["ia muamua ona oo o lou lima ia te ia e fasioti ia te ia,", "thine hand shall be first upon him to put him to death,"], ["a e mulimuli ona oo o lima o le nuu uma lava.", "and afterwards the hand of all the people."]]},
  {num:10,words:[["Ia e fetogi ia te ia i maa seia oti,", "And thou shalt stone him with stones,"], ["auā na ia saili e faateaina oe ia Ieova lou Atua,", "that he die;"], ["o le na aumaia oe ai le nuu o Aikupito,", "because he hath sought to thrust thee away from the LORD thy God, which brought thee out of the land of Egypt,"], ["o le mea sa nofo pologa ai.", "from the house of bondage."]]},
  {num:11,words:[["E faalogologo ai foi Isaraelu uma lava,", "And all Israel shall hear,"], ["ma matatau ai,", "and fear,"], ["ma latou le toe faia se mea leaga faapena i o outou nuu.", "and shall do no more any such wickedness as this is among you."]]},
  {num:12,words:[["Afai e te faalogo ane i se upu i se tasi o au aai,", "If thou shalt hear say in one of thy cities,"], ["e foaiina mai e Ieova lou Atua ia te oe e nofo ai,", "which the LORD thy God hath given thee to dwell there,"], ["o loo faapea mai,", "saying,"]]},
  {num:13,words:[["Ua o atu tagata,", "Certain men,"], ["o tagata ulavavale,", "the children of Belial,"], ["ai lo outou nuu,", "are gone out from among you,"], ["ua latou faateaina e ua nonofo i lo latou aai, o loo faapea ane,", "and have withdrawn the inhabitants of their city,"], ["Ina tatou o ia,", "saying,"], ["ma tatou auauna i atua ese,", "Let us go and serve other gods,"], ["na outou le iloa;", "which ye have not known;"]]},
  {num:14,words:[["ona e sailiili lea,", "Then shalt thou enquire,"], ["ma e suesue,", "and make search,"], ["ma e matuā fesili atu;", "and ask diligently;"], ["faauta foi,", "and, behold,"], ["afai ua moni le tala ,", "if it be truth,"], ["ua mautinoa le mea,", "and the thing certain,"], ["ua faia lava lena mea inosia ia te outou;", "that such abomination is wrought among you;"]]},
  {num:15,words:[["ia e matuā fasia o e ua nonofo i lea aai i le pelu,", "Thou shalt surely smite the inhabitants of that city with the edge of the sword, destroying it utterly,"], ["ia e faaumatia ai lava i le pelu o mea uma lava o i ai,", "and all that is therein,"], ["atoa ma manu o i ai.", "and the cattle thereof, with the edge of the sword."]]},
  {num:16,words:[["O le oloa uma foi ua i ai ia e faapotopotoina i totonu o lona malae;", "And thou shalt gather all the spoil of it into the midst of the street thereof,"], ["e te susunu foi i le afi o le aai,", "and shalt burn with fire the city,"], ["atoa ma le oloa uma ua i ai,", "and all the spoil thereof every whit,"], ["ia uma lava ia Ieova lou Atua;", "for the LORD thy God:"], ["e fai foi ia ma faupuegā maa e faavavau lava;", "and it shall be an heap for ever;"], ["e le toe faia lava.", "it shall not be built again."]]},
  {num:17,words:[["Aua ne'i tago atu lou lima i se tasi o ia mea ua faatoina;", "And there shall cleave nought of the cursed thing to thine hand:"], ["ina ia liliu ese Ieova i le tele o lona toasa,", "that the LORD may turn from the fierceness of his anger,"], ["ma alofa atu ia te oe,", "and shew thee mercy,"], ["ma faapelepele ia te oe,", "and have compassion upon thee,"], ["ma ia faatoateleina oe,", "and multiply thee,"], ["e pei ona ia tauto ai i ou tamā;", "as he hath sworn unto thy fathers;"]]},
  {num:18,words:[["pe a e faalogo i le siufofoga o Ieova lou Atua,", "When thou shalt hearken to the voice of the LORD thy God,"], ["ia tausi i ana poloaiga uma, ou te fai atu ai ia te oe i le aso nei,", "to keep all his commandments which I command thee this day,"], ["ina ia e fai le mea tonu i luma o Ieova lou Atua.", "to do that which is right in the eyes of the LORD thy God."]]},
];
renderVerseSet(deu_ch_13_Verses, 'deu-ch13-verses');

var deu_ch_14_Verses = [
  {num:1,words:[["O fanau outou a Ieova lo outou Atua;", "Ye are the children of the LORD your God:"], ["aua tou te selei o outou tino ,", "ye shall not cut yourselves,"], ["aua foi tou te sele mamā o outou muaulu mo tagata oti.", "nor make any baldness between your eyes for the dead."]]},
  {num:2,words:[["Auā o le nuu paia lava oe mo Ieova lou Atua,", "For thou art an holy people unto the LORD thy God,"], ["ua filifilia foi oe e Ieova ina ia avea oe mona nuu,", "and the LORD hath chosen thee to be a peculiar people unto himself,"], ["o le oloa tāua e sili i nuu uma lava o i le fogāeleele.", "above all the nations that are upon the earth."]]},
  {num:3,words:[["Aua e te 'aina se mea inosia e tasi.", "Thou shalt not eat any abominable thing."]]},
  {num:4,words:[["O manu vaefa nei tou te aai ai;", "These are the beasts which ye shall eat:"], ["o le povi,", "the ox,"], ["ma le mamoe,", "the sheep,"], ["ma le 'oti,", "and the goat,"]]},
  {num:5,words:[["o le aila,", "The hart,"], ["ma le sevi,", "and the roebuck,"], ["o le imura,", "and the fallow deer,"], ["ma le ako,", "and the wild goat,"], ["ma le tisona,", "and the pygarg,"], ["ma le teō,", "and the wild ox,"], ["ma le somera;", "and the chamois."]]},
  {num:6,words:[["o manu vaefa uma foi e magalua le atigivae,", "And every beast that parteth the hoof,"], ["ma tosiluaina atigivae i itu e lua,", "and cleaveth the cleft into two claws,"], ["o le e toe 'ai i lana mama i manu vaefa,", "and cheweth the cud among the beasts,"], ["o mea ia tou te aai ai.", "that ye shall eat."]]},
  {num:7,words:[["A e peitai o mea nei tou te le aai ai i manu ua toe aai i a latou mama,", "Nevertheless these ye shall not eat of them that chew the cud,"], ["ma manu e magalua atigivae ua tosiluaina;", "or of them that divide the cloven hoof;"], ["o le kamela,", "as the camel,"], ["ma le anapata,", "and the hare,"], ["ma le sefanai;", "and the coney:"], ["auā latou te toe aai a latou mama,", "for they chew the cud,"], ["a e le magalua o latou atigivae;", "but divide not the hoof;"], ["e leaga ia ia te outou.", "therefore they are unclean unto you."]]},
  {num:8,words:[["O le puaa foi,", "And the swine,"], ["auā e magalua ona atigivae,", "because it divideth the hoof,"], ["a e le toe 'ai i lana mama,", "yet cheweth not the cud,"], ["e leaga ia ia te outou;", "it is unclean unto you:"], ["aua tou te aai i o latou tino,", "ye shall not eat of their flesh,"], ["aua foi tou te papai atu i o latou tino ua mate.", "nor touch their dead carcase."]]},
  {num:9,words:[["O mea nei tou te aai ai i mea uma o i le vai;", "These ye shall eat of all that are in the waters:"], ["o mea uma e fai 'apa'apa ma una tou te aai ai;", "all that have fins and scales shall ye eat:"]]},
  {num:10,words:[["a o mea uma ua le fai ni 'apa'apa ma ni una, aua tou te aai ai;", "And whatsoever hath not fins and scales ye may not eat;"], ["e leaga ia ia te outou.", "it is unclean unto you."]]},
  {num:11,words:[["O manu felelei uma e mamā tou te aai ai.", "Of all clean birds ye shall eat."]]},
  {num:12,words:[["A o mea nei aua tou te aai ai;", "But these are they of which ye shall not eat:"], ["o le aeto,", "the eagle,"], ["ma le perese,", "and the ossifrage,"], ["ma le oseni,", "and the ospray,"]]},
  {num:13,words:[["o le rae,", "And the glede,"], ["ma le aia, ma le taie,", "and the kite,"], ["ma manu e uiga faatasi i ai;", "and the vulture after his kind,"]]},
  {num:14,words:[["ma oreva uma, ma manu e uiga faatasi i ai;", "And every raven after his kind,"]]},
  {num:15,words:[["o le iaena,", "And the owl,"], ["ma le teemesa,", "and the night hawk,"], ["ma le saape, ma le nesa,", "and the cuckow,"], ["ma manu e uiga faatasi i ai;", "and the hawk after his kind,"]]},
  {num:16,words:[["o le kusa,", "The little owl, and the great owl,"], ["ma le inesope,", "and the swan,"]]},
  {num:17,words:[["ma le tanisamiti,", "And the pelican,"], ["o le kati, ma le raama,", "and the gier eagle,"], ["ma le saleka,", "and the cormorant,"]]},
  {num:18,words:[["ma le kasita,", "And the stork,"], ["ma le matuu,", "and the heron after her kind,"], ["ma manu e uiga faatasi i ai; ma le tukapiti,", "and the lapwing,"], ["ma le pe'a;", "and the bat."]]},
  {num:19,words:[["o mea uma foi e fetolofi felelei e leaga ia ia te outou;", "And every creeping thing that flieth is unclean unto you:"], ["e le 'aina i latou.", "they shall not be eaten."]]},
  {num:20,words:[["O manu felelei uma e mamā tou te aai ai.", "But of all clean fowls ye may eat."]]},
  {num:21,words:[["Aua tou te aai i se mea ua mate fua;", "Ye shall not eat of any thing that dieth of itself:"], ["a ia e avatua i le tagata e āumau i au aai,", "thou shalt give it unto the stranger that is in thy gates,"], ["na te 'ai ai;", "that he may eat it;"], ["pe faatauina atu e oe i se tagata ese;", "or thou mayest sell it unto an alien:"], ["auā o le nuu paia lava oe mo Ieova lou Atua. Aua ne'i e tunu se tamai 'oti i le suāsusu a lona tinā.", "for thou art an holy people unto the LORD thy God. Thou shalt not seethe a kid in his mother's milk."]]},
  {num:22,words:[["Ia e matuā avatua le mea e sefulu a'i i mea uma e maua i au fua,", "Thou shalt truly tithe all the increase of thy seed,"], ["e tutupu i le fanua i lea tausaga ma lea tausaga.", "that the field bringeth forth year by year."]]},
  {num:23,words:[["O le mea foi e filifilia e ia e tuu ai lona suafa e te 'ai ai i luma o Ieova lou Atua le mea e sefulu a'i lau saito,", "And thou shalt eat before the LORD thy God,"], ["ma lau uaina,", "in the place which he shall choose to place his name there, the tithe of thy corn,"], ["ma lau suāuu,", "of thy wine,"], ["ma uluai tama a au povi ma au mamoe;", "and of thine oil, and the firstlings of thy herds and of thy flocks;"], ["ina ia a'oa'oina ai oe ia mata'u ia Ieova lou Atua i aso uma lava.", "that thou mayest learn to fear the LORD thy God always."]]},
  {num:24,words:[["A e afai e mamao lava le ala ia te oe,", "And if the way be too long for thee,"], ["ma e le lavā foi ona ave ai;", "so that thou art not able to carry it;"], ["afai foi e vava mamao ma oe le mea e filifilia e Ieova lou Atua e tuu ai lona suafa,", "or if the place be too far from thee, which the LORD thy God shall choose to set his name there,"], ["pe a faamanuia oe e Ieova lou Atua;", "when the LORD thy God hath blessed thee:"]]},
  {num:25,words:[["ona e faatau mai ai lea o tupe,", "Then shalt thou turn it into money,"], ["ma fusi tupe ma ave i lou lima,", "and bind up the money in thine hand,"], ["ma e alu atu i le mea ua filifilia e Ieova lou Atua.", "and shalt go unto the place which the LORD thy God shall choose:"]]},
  {num:26,words:[["E te faatau mai foi i ia tupe o mea uma lava e manao ai lou loto,", "And thou shalt bestow that money for whatsoever thy soul lusteth after,"], ["o se povi,", "for oxen,"], ["po o se mamoe,", "or for sheep,"], ["po o se uaina,", "or for wine,"], ["po o se 'ava,", "or for strong drink,"], ["atoa ma mea uma lava e manao i ai lou loto;", "or for whatsoever thy soul desireth:"], ["ona e 'ai lea i lea mea i luma o Ieova lou Atua,", "and thou shalt eat there before the LORD thy God,"], ["e te olioli foi,", "and thou shalt rejoice,"], ["o oe,", "thou,"], ["atoa ma lou aiga.", "and thine household,"]]},
  {num:27,words:[["O le sa Levī foi o i lau aai,", "And the Levite that is within thy gates;"], ["aua e te tuulafoai ia te ia;", "thou shalt not forsake him;"], ["auā e leai sona fanua po o sona tofi faatasi ma oe.", "for he hath no part nor inheritance with thee."]]},
  {num:28,words:[["A mavae tausaga e tolu e te ave lona sefulu uma lava o au mea ua maua mai i lea tausaga,", "At the end of three years thou shalt bring forth all the tithe of thine increase the same year,"], ["ma e faaputu ai i lau aai;", "and shalt lay it up within thy gates:"]]},
  {num:29,words:[["o le sa Levī (auā e leai sona fanua po o sona tofi faatasi ma oe,", "And the Levite,"], [") o le tagata ese foi ma le ua āumatuā,", "(because he hath no part nor inheritance with thee, ) and the stranger,"], ["ma le fafine ua oti lana tane,", "and the fatherless,"], ["o i lau aai,", "and the widow,"], ["latou te o ane,", "which are within thy gates,"], ["ma latou aai ai ia maoona;", "shall come, and shall eat and be satisfied;"], ["ina ia faamanuia ai oe e Ieova lou Atua i galuega uma lava a ou lima e te faia.", "that the LORD thy God may bless thee in all the work of thine hand which thou doest."]]},
];
renderVerseSet(deu_ch_14_Verses, 'deu-ch14-verses');

var deu_ch_15_Verses = [
  {num:1,words:[["A oo i le tausaga e fitu e te fai ai se faasaolotoga.", "At the end of every seven years thou shalt make a release."]]},
  {num:2,words:[["O le uiga foi o le faasaolotoga lenei;", "And this is the manner of the release:"], ["e taitasi le tagata e avatu mea ua aitalafu mai ai lē la te tuaoi na te tuu fua atu i ai ;", "Every creditor that lendeth ought unto his neighbour shall release it;"], ["aua ne'i faau atu o ia, ia toe au mai e lē la te tuaoi,", "he shall not exact it of his neighbour,"], ["po o lona uso;", "or of his brother;"], ["auā e ta'ua lea o le faasaolotoga a Ieova.", "because it is called the LORD'S release."]]},
  {num:3,words:[["O se tagata ese e te faau i ai ,", "Of a foreigner thou mayest exact it again:"], ["a o lau mea ua i lou uso e te tuu fua atu i ai ;", "but that which is thine with thy brother thine hand shall release;"]]},
  {num:4,words:[["ina ia leai se tagata ia te oe e mativa;", "Save when there shall be no poor among you;"], ["auā e matuā faamanuia e Ieova le nuu ua foaiina mai e Ieova lou Atua ia te oe e fai mou tofi e te maua lava;", "for the LORD shall greatly bless thee in the land which the LORD thy God giveth thee for an inheritance to possess it:"]]},
  {num:5,words:[["afai lava e te matuā faalogo i le siufofoga o Ieova lou Atua,", "Only if thou carefully hearken unto the voice of the LORD thy God,"], ["ia e anaana e fai i nei poloaiga uma lava ou te fai atu ai ia te oe i le aso nei.", "to observe to do all these commandments which I command thee this day."]]},
  {num:6,words:[["Auā ua faamanuia oe e Ieova lou Atua,", "For the LORD thy God blesseth thee,"], ["e pei ona ia fetalai mai ai ia te oe;", "as he promised thee:"], ["e te avatu foi mea i nuu e tele,", "and thou shalt lend unto many nations,"], ["a e te le nono atu;", "but thou shalt not borrow;"], ["e te pule foi i nuu e tele,", "and thou shalt reign over many nations,"], ["a e le pule mai i latou ia te oe.", "but they shall not reign over thee."]]},
  {num:7,words:[["Afai e ia te oe se tagata mativa o sou uso o i ai i se tasi o au aai i lou nuu ua foaiina mai e Ieova lou Atua ia te oe,", "If there be among you a poor man of one of thy brethren within any of thy gates in thy land which the LORD thy God giveth thee,"], ["aua ne'i e faamaaa atu lou loto,", "thou shalt not harden thine heart,"], ["pe uu mau lou lima i lou uso mativa;", "nor shut thine hand from thy poor brother:"]]},
  {num:8,words:[["a ia e matuā faamafola atu lou lima ia te ia,", "But thou shalt open thine hand wide unto him,"], ["ma e matuā avatu lava i ai o mea ia tusa ma lona mativa,", "and shalt surely lend him sufficient for his need,"], ["ua mativa ai o ia.", "in that which he wanteth."]]},
  {num:9,words:[["Ia oe,", "Beware that there be not a thought in thy wicked heart,"], ["ne'i ai se upu i lou loto leaga,", "saying,"], ["o loo faapea ifo,", "The seventh year,"], ["Ua lata mai lona fitu o tausaga,", "the year of release,"], ["o le tausaga o le faasaolotoga lea;", "is at hand;"], ["ona e mataoge lea i lou uso mativa,", "and thine eye be evil against thy poor brother,"], ["ma e le avatu ia te ia sina mea ,", "and thou givest him nought;"], ["ona valaau ai lea o ia ia Ieova ona o oe,", "and he cry unto the LORD against thee,"], ["ona fai ai lea ia te oe ma agasala.", "and it be sin unto thee."]]},
  {num:10,words:[["E te matuā avatu lava ia te ia,", "Thou shalt surely give him,"], ["aua foi le avatu ia te ia ma le tiga o lou loto;", "and thine heart shall not be grieved when thou givest unto him:"], ["auā ona o lenei mea o faamanuia ai oe e Ieova lou Atua i au galuega uma,", "because that for this thing the LORD thy God shall bless thee in all thy works,"], ["ma mea uma lava e tago i ai ou lima.", "and in all that thou puttest thine hand unto."]]},
  {num:11,words:[["Auā o le aunoa ona i ai i le nuu o le tagata mativa;", "For the poor shall never cease out of the land:"], ["o le mea lea ou te fai atu ai ia te oe,", "therefore I command thee,"], ["o loo faapea atu,", "saying, Thou shalt open thine hand wide unto thy brother,"], ["Ia e matuā faamafola atu lou lima i lou uso,", "to thy poor,"], ["i le ua tigaina,", "and to thy needy,"], ["ma le ua mativa e ia te oe i lou nuu.", "in thy land."]]},
  {num:12,words:[["Afai e faatauina mai ia te oe lou uso,", "And if thy brother,"], ["o se Eperu o le tane,", "an Hebrew man,"], ["po o se Eperu o le fafine,", "or an Hebrew woman,"], ["a auauna o ia ia te oe i tausaga e ono;", "be sold unto thee,"], ["a oo i lona fitu o tausaga e te tuu faasaolotoina atu o ia e oe;", "and serve thee six years;"], [".", "then in the seventh year thou shalt let him go free from thee."]]},
  {num:13,words:[["Pe a e tuu faasaolotoina atu o ia e oe,", "And when thou sendest him out free from thee,"], ["aua e te tuuina atu o ia ma le leai o sana mea;", "thou shalt not let him go away empty:"]]},
  {num:14,words:[["a ia e matuā foaiina atu ia te ia ni au mamoe,", "Thou shalt furnish him liberally out of thy flock,"], ["ma ni mea mai le mea e soli ai lau saito,", "and out of thy floor,"], ["ma lau tuugāuaina;", "and out of thy winepress:"], ["o mea ua faamanuia ai oe e Ieova lou Atua e te foaiina atu ai ia te ia.", "of that wherewith the LORD thy God hath blessed thee thou shalt give unto him."]]},
  {num:15,words:[["Ia e manatua foi na fai oe ma auauna i le nuu o Aikupito,", "And thou shalt remember that thou wast a bondman in the land of Egypt,"], ["na laveaiina foi oe e Ieova lou Atua;", "and the LORD thy God redeemed thee:"], ["o le mea lea ou te fai atu ai lenei mea ia te oe i le aso nei.", "therefore I command thee this thing to day."]]},
  {num:16,words:[["Pe afai foi e fai mai o ia ia te oe,", "And it shall be,"], ["Ou te le alu ese ia te oe;", "if he say unto thee,"], ["auā ua alofa o ia ia te oe ma lou aiga,", "I will not go away from thee; because he loveth thee and thine house,"], ["auā foi ua lelei ia te ia ina faatasi ma oe;", "because he is well with thee;"]]},
  {num:17,words:[["ona e tago lea i se au,", "Then thou shalt take an aul,"], ["ma tui ai lona taliga i le puipui o le faitotoa,", "and thrust it through his ear unto the door,"], ["ona avea ai lea o ia ma auauna ia te oe e faavavau. E faapea foi ona e faia i lau auauna fafine.", "and he shall be thy servant for ever. And also unto thy maidservant thou shalt do likewise."]]},
  {num:18,words:[["Aua ne'i faafaigata ia te oe pe a e tuu faasaolotoina atu o ia e oe,", "It shall not seem hard unto thee,"], ["auā ua tusa o ia ia te oe ma ni auauna tauia se toalua,", "when thou sendest him away free from thee;"], ["i lona auauna ia te oe i tausaga e ono;", "for he hath been worth a double hired servant to thee, in serving thee six years:"], ["e faamanuia foi oe e Ieova lou Atua i mea uma lava e te faia.", "and the LORD thy God shall bless thee in all that thou doest."]]},
  {num:19,words:[["O uluai tama uma lava,", "All the firstling males that come of thy herd and of thy flock thou shalt sanctify unto the LORD thy God:"], ["o poa e fanau mai i au povi ma au mamoe e te faasaina mo Ieova lou Atua; aua ne'i ai sau galuega e fai i le uluai tama a lau povi,", "thou shalt do no work with the firstling of thy bullock,"], ["aua foi e te seleina fulufulu o se uluai tama a au mamoe.", "nor shear the firstling of thy sheep."]]},
  {num:20,words:[["E te 'ai ai i luma o Ieova lou Atua i lea tausaga ma lea tausaga i le mea e filifilia e Ieova,", "Thou shalt eat it before the LORD thy God year by year in the place which the LORD shall choose,"], ["o oe atoa ma lou aiga.", "thou and thy household."]]},
  {num:21,words:[["Afai foi o i ai se mea e pona ai,", "And if there be any blemish therein,"], ["e pipili,", "as if it be lame,"], ["pe tauaso,", "or blind,"], ["po o se mea e ponā ua leaga,", "or have any ill blemish,"], ["aua lava e te faitaulaga ai ia Ieova lou Atua.", "thou shalt not sacrifice it unto the LORD thy God."]]},
  {num:22,words:[["E te 'ai ai i lau aai;", "Thou shalt eat it within thy gates:"], ["o le ua leaga ma le ua mamā la te aai ai ,", "the unclean and the clean person shall eat it alike, as the roebuck,"], ["e pei o le sevi ma le aila.", "and as the hart."]]},
  {num:23,words:[["A o le toto, aua e te 'ai ai;", "Only thou shalt not eat the blood thereof;"], ["e te sasaaina lea i le eleele e pei o le suāvai.", "thou shalt pour it upon the ground as water."]]},
];
renderVerseSet(deu_ch_15_Verses, 'deu-ch15-verses');

var deu_ch_16_Verses = [
  {num:1,words:[["Ia e tausia le masina o Apipa,", "Observe the month of Abib,"], ["ia e fai ai le paseka ia Ieova lou Atua;", "and keep the passover unto the LORD thy God:"], ["auā o le masina o Apipa na au mai ai oe e Ieova lou Atua i le po nai Aikupito.", "for in the month of Abib the LORD thy God brought thee forth out of Egypt by night."]]},
  {num:2,words:[["Ia e fasia le paseka ia Ieova lou Atua,", "Thou shalt therefore sacrifice the passover unto the LORD thy God,"], ["o mamoe ma povi,", "of the flock and the herd,"], ["i le mea e filifilia e Ieova e tuu ai lona suafa.", "in the place which the LORD shall choose to place his name there."]]},
  {num:3,words:[["Aua e te 'ai ai faatasi ma areto e faafefeteina;", "Thou shalt eat no leavened bread with it;"], ["o aso e fitu e te 'ai ai faatasi ma areto e le faafefeteina,", "seven days shalt thou eat unleavened bread therewith,"], ["o le areto o le tiga;", "even the bread of affliction;"], ["auā na faataalise ona e sau nai le nuu o Aikupito;", "for thou camest forth out of the land of Egypt in haste:"], ["ina ia e manatua le aso na e sau ai nai le nuu o Aikupito i aso uma o lou olaga.", "that thou mayest remember the day when thou camest forth out of the land of Egypt all the days of thy life."]]},
  {num:4,words:[["Aua foi ne'i iloa ia te oe sina mea e faafefeteina i lou nuu uma lava i ona aso e fitu;", "And there shall be no leavened bread seen with thee in all thy coast seven days; neither shall there any thing of the flesh,"], ["aua foi ne'i faatotoe e oo i le taeao sina tufaaga o mea na e fai taulaga ai i le afiafi o le aso muamua.", "which thou sacrificedst the first day at even, remain all night until the morning."]]},
  {num:5,words:[["E le mafai ona e fasia le paseka i se tasi o au aai ua foaiina mai e Ieova lou Atua ia te oe;", "Thou mayest not sacrifice the passover within any of thy gates, which the LORD thy God giveth thee:"]]},
  {num:6,words:[["tau lava o le mea e filifilia e Ieova lou Atua e tuu ai lona suafa,", "But at the place which the LORD thy God shall choose to place his name in,"], ["o le mea lea e te fasi ai le paseka i le afiafi,", "there thou shalt sacrifice the passover at even,"], ["i le goto o le la,", "at the going down of the sun,"], ["i ona po na e sau ai nai Aikupito.", "at the season that thou camest forth out of Egypt."]]},
  {num:7,words:[["Ia e tunu foi,", "And thou shalt roast and eat it in the place which the LORD thy God shall choose:"], ["ma e 'ai ai i le mea e filifilia e Ieova lou Atua; a oo i le taeao ona e liliu lea,", "and thou shalt turn in the morning,"], ["ma alu atu i ou fale ie.", "and go unto thy tents."]]},
  {num:8,words:[["O aso e ono e te 'ai ai areto e le faafefeteina;", "Six days thou shalt eat unleavened bread:"], ["a o le aso fitu e fai ai le faapotopotoga ia Ieova lou Atua;", "and on the seventh day shall be a solemn assembly to the LORD thy God:"], ["aua e te faia ni galuega.", "thou shalt do no work therein."]]},
  {num:9,words:[["Ia e faitauina ni vaiasosa e fitu;", "Seven weeks shalt thou number unto thee:"], ["e afua ona e faitau o nā vaiasosa e fitu ina ua faatoa tuu atu le selesaito i le saito o tu.", "begin to number the seven weeks from such time as thou beginnest to put the sickle to the corn."]]},
  {num:10,words:[["Ona e fai ai lea o le tausamiga o vaiasosa ia Ieova lou Atua,", "And thou shalt keep the feast of weeks unto the LORD thy God with a tribute of a freewill offering of thine hand,"], ["o le taulaga e te loto ina fai, e te avatua,", "which thou shalt give unto the LORD thy God,"], ["e pei ona faamanuia oe e Ieova lou Atua;", "according as the LORD thy God hath blessed thee:"]]},
  {num:11,words:[["e te olioli foi i luma o Ieova lou Atua,", "And thou shalt rejoice before the LORD thy God,"], ["i le mea e filifilia e Ieova lou Atua e tuu ai lona suafa,", "thou,"], ["o oe,", "and thy son,"], ["ma lou atalii,", "and thy daughter,"], ["ma lou afafine,", "and thy manservant,"], ["ma lau auauna tane,", "and thy maidservant,"], ["ma lau auauna fafine,", "and the Levite that is within thy gates,"], ["ma le sa Levī o i lau aai,", "and the stranger,"], ["o le tagata ese foi,", "and the fatherless,"], ["ma le ua āumatuā,", "and the widow,"], ["ma le fafine ua oti lana tane,", "that are among you,"], ["o ia te oe.", "in the place which the LORD thy God hath chosen to place his name there."]]},
  {num:12,words:[["Ia e manatua foi na fai oe ma auauna i Aikupito;", "And thou shalt remember that thou wast a bondman in Egypt:"], ["ia e anaana foi e fai nei tulafono.", "and thou shalt observe and do these statutes."]]},
  {num:13,words:[["Ia e fai le tausamiga o fale apitaga i ona aso e fitu,", "Thou shalt observe the feast of tabernacles seven days,"], ["pe a uma ona faaputuina o au saito ma lau uaina;", "after that thou hast gathered in thy corn and thy wine:"]]},
  {num:14,words:[["e te olioli foi i lau tausamiga,", "And thou shalt rejoice in thy feast,"], ["o oe,", "thou,"], ["ma lou atalii,", "and thy son,"], ["ma lou afafine,", "and thy daughter,"], ["ma lau auauna tane,", "and thy manservant, and thy maidservant,"], ["ma lau auauna fafine,", "and the Levite,"], ["ma le sa Levī,", "the stranger,"], ["ma le tagata ese,", "and the fatherless,"], ["ma le ua āumatuā,", "and the widow,"], ["ma le fafine na oti lana tane o i lau aai.", "that are within thy gates."]]},
  {num:15,words:[["O aso e fitu e te fai ai le tausamiga ia Ieova lou Atua i le mea e filifilia e Ieova;", "Seven days shalt thou keep a solemn feast unto the LORD thy God in the place which the LORD shall choose:"], ["auā e faamanuia oe e Ieova lou Atua i au mea uma e maua mai,", "because the LORD thy God shall bless thee in all thine increase,"], ["ma mea uma e faia i ou lima,", "and in all the works of thine hands,"], ["e te olioli ai lava.", "therefore thou shalt surely rejoice."]]},
  {num:16,words:[["E ta'i atu tolu i le tausaga ona iloa o tane uma lava o ia te oe i luma o Ieova lou Atua i le mea e filifilia e ia;", "Three times in a year shall all thy males appear before the LORD thy God in the place which he shall choose;"], ["o le tausamiga o areto e le faafefeteina,", "in the feast of unleavened bread,"], ["ma le tausamiga o vaiasosa,", "and in the feast of weeks,"], ["i le ma le tausamiga o fale apitaga;", "and in the feast of tabernacles:"], ["aua foi ne'i iloa se isi i luma o Ieova ua leai sana mea.", "and they shall not appear before the LORD empty:"]]},
  {num:17,words:[["E taitasi le tagata e tusa ma mea ua ia te ia,", "Every man shall give as he is able,"], ["e tusa ma le manuia ua foaiina mai e Ieova lou Atua ia te oe.", "according to the blessing of the LORD thy God which he hath given thee."]]},
  {num:18,words:[["Ia e tofia mo oe nisi e fai ma faamasino ma faipule i au aai uma,", "Judges and officers shalt thou make thee in all thy gates,"], ["ua foaiina mai e Ieova lou Atua ia te oe,", "which the LORD thy God giveth thee,"], ["i ou itu aiga;", "throughout thy tribes:"], ["latou te faamasino foi i le nuu ma le faamasinoga tonu.", "and they shall judge the people with just judgment."]]},
  {num:19,words:[["Aua e te faapioina le faamasinoga;", "Thou shalt not wrest judgment;"], ["aua e te faailogaina se tasi,", "thou shalt not respect persons,"], ["aua foi e te talia se mea alofa;", "neither take a gift:"], ["auā o le mea alofa e faatauaso a'i mata o e popoto,", "for a gift doth blind the eyes of the wise,"], ["e faaseseina ai foi o upu a e amiotonu.", "and pervert the words of the righteous."]]},
  {num:20,words:[["Ia e tausisi lava i le mea e matuā tonu,", "That which is altogether just shalt thou follow,"], ["ina ia e ola ai,", "that thou mayest live,"], ["ma e fai mou le nuu ua foaiina mai e Ieova lou Atua ia te oe.", "and inherit the land which the LORD thy God giveth thee."]]},
  {num:21,words:[["Aua e te faatuina se tupua o Asaira, so se tasi laau e lata ane i le fata faitaulaga a Ieova lou Atua,", "Thou shalt not plant thee a grove of any trees near unto the altar of the LORD thy God,"], ["e te faia mo oe.", "which thou shalt make thee."]]},
  {num:22,words:[["Aua foi e te faatuina mo oe se tupua,", "Neither shalt thou set thee up any image;"], ["o le mea e inosia e Ieova lou Atua.", "which the LORD thy God hateth."]]},
];
renderVerseSet(deu_ch_16_Verses, 'deu-ch16-verses');

var deu_ch_17_Verses = [
  {num:1,words:[["Aua e te fai taulaga ia Ieova lou Atua i se povi po o se mamoe ua i ai se mea e ponā,", "Thou shalt not sacrifice unto the LORD thy God any bullock, or sheep,"], ["po o se tasi mea leaga;", "wherein is blemish,"], ["auā o le mea lea e inosia e Ieova lou Atua.", "or any evilfavouredness: for that is an abomination unto the LORD thy God."]]},
  {num:2,words:[["Afai ua iloa o ia te oe,", "If there be found among you,"], ["i se tasi o au aai ua foaiina mai e Ieova lou Atua ia te oe,", "within any of thy gates which the LORD thy God giveth thee,"], ["o se tane po o se fafine,", "man or woman,"], ["ua na faia se mea leaga i luma o Ieova lou Atua,", "that hath wrought wickedness in the sight of the LORD thy God,"], ["e soli ai lana feagaiga;", "in transgressing his covenant,"]]},
  {num:3,words:[["po ua alu o ia ma auauna i atua ese,", "And hath gone and served other gods,"], ["ma ifo i ai,", "and worshipped them,"], ["o le la,", "either the sun,"], ["po o le masina,", "or moon,"], ["po o se tasi i 'au o le lagi,", "or any of the host of heaven,"], ["ua ou le poloai atu ai;", "which I have not commanded;"]]},
  {num:4,words:[["ona ta'u mai ai lea ia te oe,", "And it be told thee,"], ["ma e faalogo ai ,", "and thou hast heard of it, and enquired diligently,"], ["ma e matuā sue atu ai;", "and,"], ["faauta foi,", "behold,"], ["ua moni ua mautinoa le mea,", "it be true, and the thing certain,"], ["ua faia lava lena mea inosia i Isaraelu;", "that such abomination is wrought in Israel:"]]},
  {num:5,words:[["ona e aveina atu lea i ou faitotoa o lea tane po o lea fafine ua na faia lena mea leaga,", "Then shalt thou bring forth that man or that woman, which have committed that wicked thing,"], ["ma ia e fetogi i maa o lea tane po o lea fafine,", "unto thy gates, even that man or that woman,"], ["ia oti.", "and shalt stone them with stones, till they die."]]},
  {num:6,words:[["O mau a e molimau e toalua,", "At the mouth of two witnesses,"], ["po o molimau e toatolu,", "or three witnesses,"], ["o le ua tatau i ai le oti ia fasiotia ai o ia;", "shall he that is worthy of death be put to death;"], ["o le mau a le molimau e toatasi aua le fasiotia ai o ia.", "but at the mouth of one witness he shall not be put to death."]]},
  {num:7,words:[["Ia muamua ona oo o lima o e molimau ia te ia e fasioti ai;", "The hands of the witnesses shall be first upon him to put him to death,"], ["a e mulimuli ane o lima o le nuu uma lava. Ona e tuueseina ai lea o le leaga ia te oe.", "and afterward the hands of all the people. So thou shalt put the evil away from among you."]]},
  {num:8,words:[["Afai foi e faigata ia te oe se mea e faamasino ai i le toto ma le toto,", "If there arise a matter too hard for thee in judgment,"], ["o le mea e faamasinoina ma le mea e faamasinoina,", "between blood and blood,"], ["o le ta ma le ta,", "between plea and plea, and between stroke and stroke,"], ["o mea e fefinaua'i ai i au aai;", "being matters of controversy within thy gates:"], ["ona e tulai lea,", "then shalt thou arise,"], ["ma e alu ae i le mea e filifilia e Ieova lou Atua mona;", "and get thee up into the place which the LORD thy God shall choose;"]]},
  {num:9,words:[["e te alu foi i faitaulaga,", "And thou shalt come unto the priests the Levites,"], ["o sa Levī,", "and unto the judge that shall be in those days,"], ["ma le faamasino e i ai i ia ona po, e te fesili foi i ai ;", "and enquire;"], ["ona latou faailoa mai lea ia te oe le tonu o le mea e faamasinoina;", "and they shall shew thee the sentence of judgment:"]]},
  {num:10,words:[["ona e faia lea o le mea e pei ona latou faailoa mai ia te oe i lea mea e filifilia e Ieova;", "And thou shalt do according to the sentence, which they of that place which the LORD shall choose shall shew thee;"], ["ia e anaana foi e fai e tusa ma mea uma lava latou te a'oa'o mai ai ia te oe;", "and thou shalt observe to do according to all that they inform thee:"]]},
  {num:11,words:[["e tusa ma le tuulafono latou te a'oa'o mai ai ia te oe,", "According to the sentence of the law which they shall teach thee,"], ["e tusa foi ma le faamasinoga latou te fai mai ai ia te oe,", "and according to the judgment which they shall tell thee,"], ["ia e faia lava;", "thou shalt do:"], ["aua ne'i e alu ese i le upu latou te faailoa mai ai ia te oe,", "thou shalt not decline from the sentence which they shall shew thee,"], ["i le itu taumatau,", "to the right hand,"], ["po o le itu tauagavale.", "nor to the left."]]},
  {num:12,words:[["O le tagata foi na te faia se mea ma le faamaualuga,", "And the man that will do presumptuously,"], ["ma le le fia faalogo i le faitaulaga e tu i lea mea e auauna ia Ieova lou Atua,", "and will not hearken unto the priest that standeth to minister there before the LORD thy God,"], ["po o le faamasino,", "or unto the judge,"], ["ia oti lava lea tagata;", "even that man shall die:"], ["ona e tuueseina ai lea o le leaga ia Isaraelu.", "and thou shalt put away the evil from Israel."]]},
  {num:13,words:[["Ona faalogo ai lea o le nuu uma lava,", "And all the people shall hear,"], ["ma matatau ai,", "and fear,"], ["ma latou le toe faamaualuga.", "and do no more presumptuously."]]},
  {num:14,words:[["Pe a e oo atu foi i le nuu e foaiina mai e Ieova lou Atua ia te oe,", "When thou art come unto the land which the LORD thy God giveth thee,"], ["ma e fai mou,", "and shalt possess it,"], ["ma e mau ai,", "and shalt dwell therein,"], ["ma e faapea ane,", "and shalt say,"], ["Ou te faia se tupu mo'u,", "I will set a king over me,"], ["e pei o nuu uma lava e vagavagai mai ia te au;", "like as all the nations that are about me;"]]},
  {num:15,words:[["ia e matuā tofia mo oe se tupu e filifilia e Ieova lou Atua;", "Thou shalt in any wise set him king over thee,"], ["o sou uso e te tofia e fai ma tupu ia te oe;", "whom the LORD thy God shall choose:"], ["e le mafai ona e tofia mo oe se tagata ese,", "one from among thy brethren shalt thou set king over thee: thou mayest not set a stranger over thee,"], ["e le o sou uso ia.", "which is not thy brother."]]},
  {num:16,words:[["A e aua lava ne'i faateleina e ia solofanua mona,", "But he shall not multiply horses to himself,"], ["pe toe faafoi atu le nuu i Aikupito,", "nor cause the people to return to Egypt,"], ["ina ia faateleina ai e ia o solofanua;", "to the end that he should multiply horses:"], ["auā ua fetalai mai Ieova ia te outou,", "forasmuch as the LORD hath said unto you,"], ["Aua tou te toe foi atu i lea lava ala.", "Ye shall henceforth return no more that way."]]},
  {num:17,words:[["Aua foi ne'i faatoateleina e ia o avā māna,", "Neither shall he multiply wives to himself,"], ["ne'i liliueseina ai lona loto;", "that his heart turn not away:"], ["aua foi ne'i faateleina naua e ia o ario ma auro mo ia.", "neither shall he greatly multiply to himself silver and gold."]]},
  {num:18,words:[["A oo foi ina nofo o ia i le nofoalii o lona malo,", "And it shall be, when he sitteth upon the throne of his kingdom,"], ["na te tusia māna se tusi o lenei tulafono i se tusi ai lena tusi o i luma o le au faitaulaga o sa Levī;", "that he shall write him a copy of this law in a book out of that which is before the priests the Levites:"]]},
  {num:19,words:[["ia i ai foi lea ia te ia,", "And it shall be with him,"], ["na te faitau ai foi i aso uma lava o lona olaga;", "and he shall read therein all the days of his life:"], ["ina ia a'oa'oina ai o ia ia mata'u ia Ieova lona Atua,", "that he may learn to fear the LORD his God,"], ["ma ia tausi i upu uma lava a lenei tulafono ma nei sauniga,", "to keep all the words of this law and these statutes,"], ["na te faia;", "to do them:"]]},
  {num:20,words:[["ina ne'i faamaualugaina lona loto i ona uso,", "That his heart be not lifted up above his brethren,"], ["ina ne'i te'a ese foi i le poloaiga,", "and that he turn not aside from the commandment,"], ["i le itu taumatau po o le itu tauagavale;", "to the right hand,"], ["ina ia tulu'i ai ona aso i lona malo,", "or to the left: to the end that he may prolong his days in his kingdom,"], ["o ia,", "he,"], ["ma ona atalii,", "and his children,"], ["ia Isaraelu.", "in the midst of Israel."]]},
];
renderVerseSet(deu_ch_17_Verses, 'deu-ch17-verses');

var deu_ch_18_Verses = [
  {num:1,words:[["O le au faitaulaga o sa Levī,", "The priests the Levites,"], ["ma le itu aiga uma o Levi,", "and all the tribe of Levi,"], ["e leai so latou fanua po o se tofi faatasi ma Isaraelu; o taulaga e fai i le afi ia Ieova,", "shall have no part nor inheritance with Israel:"], ["o lona tofi lea,", "they shall eat the offerings of the LORD made by fire,"], ["latou te aai ai.", "and his inheritance."]]},
  {num:2,words:[["E leai foi sona tofi faatasi ma ona uso;", "Therefore shall they have no inheritance among their brethren:"], ["o Ieova o lona tofi o ia,", "the LORD is their inheritance,"], ["e pei ona fetalai mai ai o ia ia te ia.", "as he hath said unto them."]]},
  {num:3,words:[["O mea nei e tatau ona maua e le au faitaulaga mai le nuu,", "And this shall be the priest's due from the people,"], ["mai ia i latou o e fai taulaga,", "from them that offer a sacrifice,"], ["po o se povi po o se mamoe;", "whether it be ox or sheep;"], ["ia latou avatu i le faitaulaga o le alagālima,", "and they shall give unto the priest the shoulder,"], ["ma alafau e lua,", "and the two cheeks,"], ["ma le puta.", "and the maw."]]},
  {num:4,words:[["O le faapolopolo o lau saito,", "The firstfruit also of thy corn,"], ["o lau uaina,", "of thy wine,"], ["ma lau suāuu, atoa ma selega muamua o fulufulu o au mamoe,", "and of thine oil,"], ["ia e avatua,", "and the first of the fleece of thy sheep,"], ["ia mea ia te ia.", "shalt thou give him."]]},
  {num:5,words:[["Auā ua filifilia o ia e Ieova lou Atua mai ou itu aiga uma,", "For the LORD thy God hath chosen him out of all thy tribes,"], ["e tu ma auauna i le suafa o Ieova,", "to stand to minister in the name of the LORD,"], ["o ia ma ona atalii i aso uma lava.", "him and his sons for ever."]]},
  {num:6,words:[["Afai foi e sau se sa Levī ai se tasi o au aai i Isaraelu uma,", "And if a Levite come from any of thy gates out of all Israel,"], ["sa āumau ai o ia;", "where he sojourned,"], ["a sau ma le manao atoatoa o lona loto i le mea e filifilia e Ieova;", "and come with all the desire of his mind unto the place which the LORD shall choose;"]]},
  {num:7,words:[["ona auauna lea o ia i le suafa o Ieova lona Atua,", "Then he shall minister in the name of the LORD his God,"], ["e pei o ona uso uma o sa Levī,", "as all his brethren the Levites do,"], ["o e tutū i lea mea i luma o Ieova.", "which stand there before the LORD."]]},
  {num:8,words:[["E tutusa tufaaga latou te aai ai,", "They shall have like portions to eat,"], ["a e ese lava le faatau o mea sa i ona tamā.", "beside that which cometh of the sale of his patrimony."]]},
  {num:9,words:[["A ē oo atu i le nuu ua foaiina mai e Ieova lou Atua ia te oe,", "When thou art come into the land which the LORD thy God giveth thee,"], ["aua ne'i e faaa'oa'o ona fai e pei o mea inosia a ia nuu.", "thou shalt not learn to do after the abominations of those nations."]]},
  {num:10,words:[["Aua ne'i iloa ia te oe se tasi na te faaui ane lona atalii po o lona afafine i le afi,", "There shall not be found among you any one that maketh his son or his daughter to pass through the fire,"], ["o se fai togafiti faataulāitu,", "or that useth divination,"], ["o se iite i ao o le lagi,", "or an observer of times,"], ["po o se saili faailoga,", "or an enchanter,"], ["po o se taulāitu,", "or a witch,"]]},
  {num:11,words:[["po o se 'apele,", "Or a charmer,"], ["po o se fesili atu i aitu,", "or a consulter with familiar spirits,"], ["po o se ua i ai le aitu vavalo,", "or a wizard,"], ["po o se saili atu i e ua oti.", "or a necromancer."]]},
  {num:12,words:[["Auā e inosia e Ieova o i latou uma o e faia na mea;", "For all that do these things are an abomination unto the LORD:"], ["e tulia foi i latou e Ieova lou Atua ai ou luma ona o na mea e inosia.", "and because of these abominations the LORD thy God doth drive them out from before thee."]]},
  {num:13,words:[["Ia sao lau amio i luma o Ieova lou Atua.", "Thou shalt be perfect with the LORD thy God."]]},
  {num:14,words:[["Auā o nuu nei,", "For these nations,"], ["o le a e fai mou,", "which thou shalt possess,"], ["ua faalogo i latou i e iite i ao o le lagi,", "hearkened unto observers of times,"], ["ma e fai togafiti faataulāitu;", "and unto diviners:"], ["a o oe,", "but as for thee,"], ["e le mafai Ieova lou Atua ona e faia faapea.", "the LORD thy God hath not suffered thee so to do."]]},
  {num:15,words:[["E faatuina e Ieova lou Atua mai ia te oe,", "The LORD thy God will raise up unto thee a Prophet from the midst of thee,"], ["o so lou au uso,", "of thy brethren,"], ["se perofeta mo oe e pei o a'u nei;", "like unto me;"], ["tou te faalogo ia te ia;", "unto him ye shall hearken;"]]},
  {num:16,words:[["e tusa ma mea uma lava na e manao i ai ia Ieova lou Atua i Horepa i le aso o le faapotopotoga,", "According to all that thou desiredst of the LORD thy God in Horeb in the day of the assembly,"], ["na faapea mai,", "saying,"], ["Aua ne'i ou toe faalogo atu i le siufofoga o Ieova lo'u Atua,", "Let me not hear again the voice of the LORD my God,"], ["pe toe vaai atu i lena afi tele,", "neither let me see this great fire any more,"], ["ne'i ou oti.", "that I die not."]]},
  {num:17,words:[["Ona fetalai mai lea o Ieova ia te au,", "And the LORD said unto me,"], ["Ua lelei a latou na latou fai mai ai.", "They have well spoken that which they have spoken."]]},
  {num:18,words:[["Ou te faatuina mo i latou,", "I will raise them up a Prophet from among their brethren,"], ["o so latou uso,", "like unto thee,"], ["se perofeta e pei o oe; ou te tuuina atu foi a'u upu i lona gutu,", "and will put my words in his mouth;"], ["e fai atu foi e ia ia te i latou o mea uma lava ou te fai atu ai ia te ia.", "and he shall speak unto them all that I shall command him."]]},
  {num:19,words:[["O le tagata foi e le faalogo i a'u upu,", "And it shall come to pass,"], ["e fai atu ai e ia i lo'u igoa, o a'u nei,", "that whosoever will not hearken unto my words which he shall speak in my name,"], ["ou te taui atu ia te ia.", "I will require it of him."]]},
  {num:20,words:[["A o le perofeta e faamaualuga ma tautala i se upu i lo'u igoa,", "But the prophet,"], ["ou te lei fai ane ia te ia e tautala atu ai,", "which shall presume to speak a word in my name,"], ["pe tautala ia i igoa o atua ese,", "which I have not commanded him to speak, or that shall speak in the name of other gods,"], ["e oti lea lava perofeta.", "even that prophet shall die."]]},
  {num:21,words:[["Afai foi e te faapea ifo i lou loto,", "And if thou say in thine heart,"], ["Pe faapefea ona matou iloa o le upu e lei fetalaia e Ieova?", "How shall we know the word which the LORD hath not spoken?"]]},
  {num:22,words:[["A tautala se perofeta i le suafa o Ieova,", "When a prophet speaketh in the name of the LORD,"], ["afai e le oo le mea,", "if the thing follow not,"], ["e le taunuu foi,", "nor come to pass,"], ["o le upu lea ua le fetalaia mai e Ieova;", "that is the thing which the LORD hath not spoken,"], ["o le faamaualuga o lea perofeta ua tautala ai o ia;", "but the prophet hath spoken it presumptuously:"], ["aua e te fefe ia te ia.", "thou shalt not be afraid of him."]]},
];
renderVerseSet(deu_ch_18_Verses, 'deu-ch18-verses');

var deu_ch_19_Verses = [
  {num:1,words:[["A Faaumatia e Ieova lou Atua o nuu ua foaiina mai o lo latou laueleele e Ieova lou Atua,", "When the LORD thy God hath cut off the nations, whose land the LORD thy God giveth thee,"], ["pe a e fai ai mou,", "and thou succeedest them,"], ["ma e nofo i o latou aai ma o latou fale;", "and dwellest in their cities, and in their houses;"]]},
  {num:2,words:[["ona e vavaeeseina lea o aai e tolu mo oe,", "Thou shalt separate three cities for thee in the midst of thy land,"], ["i lou laueleele ua foaiina mai e Ieova lou Atua ia te oe e fai mou.", "which the LORD thy God giveth thee to possess it."]]},
  {num:3,words:[["Ia e teuteu se ala mo oe,", "Thou shalt prepare thee a way,"], ["ma ia e vaetoluina itu o lou laueleele,", "and divide the coasts of thy land,"], ["e foaiina mou tofi e Ieova lou Atua,", "which the LORD thy God giveth thee to inherit, into three parts,"], ["ina ia sosola i ai o i latou uma o e fasioti tagata.", "that every slayer may flee thither."]]},
  {num:4,words:[["O le upu foi lenei i le fasioti tagata,", "And this is the case of the slayer,"], ["e sola i ai,", "which shall flee thither,"], ["e ola ai o ia;", "that he may live:"], ["o le na te fasioti i lē la te tuaoi ma le le iloa,", "Whoso killeth his neighbour ignorantly,"], ["e lei muai ita foi ia te ia;", "whom he hated not in time past;"]]},
  {num:5,words:[["a ua la o ma lē la te tuaoi i le vao e ta laau,", "As when a man goeth into the wood with his neighbour to hew wood,"], ["ua ta ifo le tai lona lima e ta ai le laau i le mătau,", "and his hand fetcheth a stroke with the axe to cut down the tree,"], ["ona mole atu ai lea o le uamea ai le 'au,", "and the head slippeth from the helve,"], ["ua lavea ai lē la te tuaoi,", "and lighteth upon his neighbour,"], ["ua oti ai o ia;", "that he die;"], ["o ia lava na te sola i se tasi o ia aai,", "he shall flee unto one of those cities,"], ["e ola ai;", "and live:"]]},
  {num:6,words:[["ina ne'i tuliloaina le fasioti tagata e le na te taui ma sui le toto,", "Lest the avenger of the blood pursue the slayer,"], ["a o tiga lona loto,", "while his heart is hot,"], ["ma maua atu ia te ia,", "and overtake him,"], ["auā ua mamao le ala,", "because the way is long,"], ["ona fasioti ai lea ia te ia;", "and slay him;"], ["a e le tatau ia te ia le oti,", "whereas he was not worthy of death,"], ["auā e lei muai ita o ia ia te ia.", "inasmuch as he hated him not in time past."]]},
  {num:7,words:[["O le mea lea ou te fai atu ai ia te oe,", "Wherefore I command thee,"], ["e faapea atu,", "saying,"], ["Ia e vavaeeseina mo oe o aai e tolu.", "Thou shalt separate three cities for thee."]]},
  {num:8,words:[["Afai foi e faalauteleina e Ieova lou Atua lou laueleele,", "And if the LORD thy God enlarge thy coast,"], ["e faapei ona ia tauto i ou tamā;", "as he hath sworn unto thy fathers,"], ["ma foaiina mai ia te oe le laueleele uma lava ua na fetalaia mai e avatu i ou tamā;", "and give thee all the land which he promised to give unto thy fathers;"]]},
  {num:9,words:[["afai e te anaana e fai o nei poloaiga uma,", "If thou shalt keep all these commandments to do them,"], ["ou te fai atu ai ia te oe i le aso nei,", "which I command thee this day,"], ["ia alofa atu ia Ieova lou Atua ma savali i ona ala i aso uma lava;", "to love the LORD thy God, and to walk ever in his ways;"], ["ona e toe faaopoopo lea mo oe o aai e tolu,", "then shalt thou add three cities more for thee,"], ["i na aai e tolu;", "beside these three:"]]},
  {num:10,words:[["Ina ne'i faamaligiina le toto o le ua le sala i lou laueleele ua foaiina mai e Ieova lou Atua ia te oe e fai mou tofi,", "That innocent blood be not shed in thy land, which the LORD thy God giveth thee for an inheritance,"], ["ina ne'i ia te oe le sala ona o le loto.", "and so blood be upon thee."]]},
  {num:11,words:[["A e afai e ita se tagata i lē la te tuaoi,", "But if any man hate his neighbour,"], ["ma lamalama ia te ia,", "and lie in wait for him,"], ["ma tulai atu,", "and rise up against him,"], ["ma fasi ia te ia ia oti,", "and smite him mortally that he die,"], ["ona sola lea o ia i se tasi o ia aai;", "and fleeth into one of these cities:"]]},
  {num:12,words:[["ona aauina atu lea nisi e toeaina o lona aai e aamiina atu ai o ia,", "Then the elders of his city shall send and fetch him thence,"], ["ma tuuina atu o ia i le pule a le na te tauia ma sui le toto,", "and deliver him into the hand of the avenger of blood,"], ["ia oti ai o ia.", "that he may die."]]},
  {num:13,words:[["Aua ne'i e alofa ia te ia,", "Thine eye shall not pity him,"], ["a ia e tuueseina le sala o le toto o le ua le sala i Isaraelu,", "but thou shalt put away the guilt of innocent blood from Israel,"], ["e te lelei ai.", "that it may go well with thee."]]},
  {num:14,words:[["Aua e te sii le tuaoi o lē lua te tuaoi,", "Thou shalt not remove thy neighbour's landmark, which they of old time have set in thine inheritance,"], ["o le tuaoi sa faia e na mua i lou fanua o le a fai mou tofi i le nuu e foaiina e Ieova lou Atua ia te oe e fai mou.", "which thou shalt inherit in the land that the LORD thy God giveth thee to possess it."]]},
  {num:15,words:[["Aua ne'i tulai atu se molimau e toatasi e molimau i se amioletonu a se tagata,", "One witness shall not rise up against a man for any iniquity,"], ["po o se agasala,", "or for any sin,"], ["i agasala uma lava e agasala ai o ia;", "in any sin that he sinneth: at the mouth of two witnesses,"], ["a o mau a e molimau e toalua,", "or at the mouth of three witnesses,"], ["po o mau a e molimau e toatolu e faamaoni ai le mea.", "shall the matter be established."]]},
  {num:16,words:[["Afai e tulai atu se molimau faasaua e molimau ai se amio leaga a se tagata;", "If a false witness rise up against any man to testify against him that which is wrong;"]]},
  {num:17,words:[["ona tutū ai lea o ia tagata e toalua ua i ai le finauga,", "Then both the men,"], ["i luma o Ieova,", "between whom the controversy is,"], ["i luma o le au faitaulaga ma faamasino,", "shall stand before the LORD, before the priests and the judges,"], ["e i ai i ia ona po;", "which shall be in those days;"]]},
  {num:18,words:[["ona matuā suesue lea e faamasino;", "And the judges shall make diligent inquisition:"], ["faauta foi,", "and,"], ["afai o le molimau o le molimau pepelo ia,", "behold, if the witness be a false witness,"], ["ua na tala pepelo i lona uso;", "and hath testified falsely against his brother;"]]},
  {num:19,words:[["ona outou faia lea ia te ia,", "Then shall ye do unto him,"], ["e pei ona manatu o ia, e fai i lona uso;", "as he had thought to have done unto his brother:"], ["ona e tuueseina ai lea o le leaga ai ia te oe.", "so shalt thou put the evil away from among you."]]},
  {num:20,words:[["Ona faalogo ai lea,", "And those which remain shall hear,"], ["ma matatau ai nisi uma lava,", "and fear,"], ["ma latou le toe faia se mea leaga faapea i lou nuu.", "and shall henceforth commit no more any such evil among you."]]},
  {num:21,words:[["Aua ne'i e alofa ia te ia;", "And thine eye shall not pity;"], ["a ia sui atu le ola i le ola,", "but life shall go for life,"], ["o le mata i le mata,", "eye for eye,"], ["o le nifo i le nifo,", "tooth for tooth,"], ["o le lima i le lima,", "hand for hand,"], ["ma le vae i le vae.", "foot for foot."]]},
];
renderVerseSet(deu_ch_19_Verses, 'deu-ch19-verses');

var deu_ch_20_Verses = [
  {num:1,words:[["A ē alu atu e tau ai se taua ma lou fili;", "When thou goest out to battle against thine enemies,"], ["a ē ilo atu solofanua,", "and seest horses,"], ["ma kariota,", "and chariots,"], ["ma le nuu e sili ona toatele ia te oe,", "and a people more than thou,"], ["aua ne'i e fefe ia te i latou;", "be not afraid of them:"], ["auā o ia te oe Ieova lou Atua,", "for the LORD thy God is with thee,"], ["o le na aveina ae oe ai le nuu o Aikupito.", "which brought thee up out of the land of Egypt."]]},
  {num:2,words:[["A latalata ona outou tau,", "And it shall be,"], ["ona faalatalata atu lea o le faitaulaga,", "when ye are come nigh unto the battle,"], ["ma tautalatala i le nuu,", "that the priest shall approach and speak unto the people,"]]},
  {num:3,words:[["e faapea atu ia te i latou,", "And shall say unto them,"], ["Isaraelu e,", "Hear,"], ["faalogo mai ia,", "O Israel,"], ["ua outou faalatalata atu i le aso nei e tau le taua ma o outou fili;", "ye approach this day unto battle against your enemies:"], ["aua ne'i faavaivai o outou loto,", "let not your hearts faint,"], ["aua tou te fefefe,", "fear not,"], ["aua tou te matatau,", "and do not tremble,"], ["aua foi tou te gatete ia te i latou;", "neither be ye terrified because of them;"]]},
  {num:4,words:[["auā o Ieova lo outou Atua tou te o ma ia,", "For the LORD your God is he that goeth with you,"], ["na te tau ai la outou taua ma o outou fili,", "to fight for you against your enemies,"], ["na te faaolaina outou.", "to save you."]]},
  {num:5,words:[["Ia fai atu foi le au faipule i le nuu,", "And the officers shall speak unto the people,"], ["ia faapea atu,", "saying,"], ["O ai se tagata ua faia sona fale fou, a e lei faaulufaleina? Ina alu o ia,", "What man is there that hath built a new house,"], ["ina foi atu i lona fale,", "and hath not dedicated it? let him go and return to his house,"], ["ne'i oti o ia i le taua,", "lest he die in the battle,"], ["ona faaulufaleina ai lea e se tasi.", "and another man dedicate it."]]},
  {num:6,words:[["O ai foi se tagata ua faia se tovine,", "And what man is he that hath planted a vineyard,"], ["a e lei faatatagaina? Ina alu ia,", "and hath not yet eaten of it? let him also go and return unto his house,"], ["ina foi atu i lona fale, ne'i oti o ia i le taua,", "lest he die in the battle,"], ["ona faatatagaina ai lea e se tasi.", "and another man eat of it."]]},
  {num:7,words:[["O ai foi se tagata ua la fai le feagaiga ma se fafine e fai mana avā,", "And what man is there that hath betrothed a wife,"], ["a e lei faatasia? Ina alu ia,", "and hath not taken her? let him go and return unto his house,"], ["ina foi atu i lona fale, ne'i oti o ia i le taua,", "lest he die in the battle,"], ["ona fai ai lea o ia ma avā a se tasi tagata.", "and another man take her."]]},
  {num:8,words:[["Ia toe tautala atu foi le au faipule i le nuu, ia latou faapea atu,", "And the officers shall speak further unto the people,"], ["O ai ea se tagata e fefe,", "and they shall say,"], ["ma faavaivai lona loto? Ina alu ia,", "What man is there that is fearful and fainthearted? let him go and return unto his house,"], ["ma foi atu i lona fale, ne'i faavaivai loto o ona uso e pei o lona loto.", "lest his brethren's heart faint as well as his heart."]]},
  {num:9,words:[["A uma foi ona tautala atu o le au faipule i le nuu,", "And it shall be, when the officers have made an end of speaking unto the people,"], ["ona tofia lea e i latou o alii e ave 'au e ta'ita'iina le nuu.", "that they shall make captains of the armies to lead the people."]]},
  {num:10,words:[["A ē faalatalata i se aai e tau ai le taua,", "When thou comest nigh unto a city to fight against it,"], ["ona e valaau atu lea i ai ia ola le taua;", "then proclaim peace unto it."]]},
  {num:11,words:[["afai foi e tali mai i latou ia te oe,", "And it shall be,"], ["ina ola ia,", "if it make thee answer of peace,"], ["ma latou faaavanoa faitotoa ia te oe,", "and open unto thee, then it shall be,"], ["ona avea ai lea o tagata uma e maua ai ma ē au mai taulaga ia te oe,", "that all the people that is found therein shall be tributaries unto thee,"], ["ma latou auauna ia te oe.", "and they shall serve thee."]]},
  {num:12,words:[["A e afai e le mafai ia te i latou ona fai o se leleiga ma oe,", "And if it will make no peace with thee,"], ["a e fia tau lava i latou ma oe,", "but will make war against thee,"], ["ona e siosioina atu ai lea;", "then thou shalt besiege it:"]]},
  {num:13,words:[["pe a tuuina mai foi e Ieova lou Atua ia te oe,", "And when the LORD thy God hath delivered it into thine hands,"], ["ia e fasiotia tane uma lava o i ai i le pelu;", "thou shalt smite every male thereof with the edge of the sword:"]]},
  {num:14,words:[["na o fafine,", "But the women,"], ["ma tama iti,", "and the little ones,"], ["ma manu vaefa,", "and the cattle,"], ["ma mea uma lava o i le aai,", "and all that is in the city, even all the spoil thereof,"], ["o le oloa uma o i ai e te vetea mou;", "shalt thou take unto thyself;"], ["e te 'ai foi i mea a ou fili,", "and thou shalt eat the spoil of thine enemies,"], ["ua foaiina mai e Ieova lou Atua ia te oe.", "which the LORD thy God hath given thee."]]},
  {num:15,words:[["Ia faapea ona e fai i aai uma ē matuā vava mamao ma oe,", "Thus shalt thou do unto all the cities which are very far off from thee,"], ["e le ni aai ia o na nuu.", "which are not of the cities of these nations."]]},
  {num:16,words:[["A o aai o na nuu e foaiina mai e Ieova lou Atua ia te oe e fai mou tofi,", "But of the cities of these people, which the LORD thy God doth give thee for an inheritance,"], ["aua ne'i e faaolaina ai se tasi e ola.", "thou shalt save alive nothing that breatheth:"]]},
  {num:17,words:[["A ia e matuā faaumatia i latou;", "But thou shalt utterly destroy them;"], ["o sa Hetī,", "namely,"], ["ma sa Amorī,", "the Hittites,"], ["o sa Kananā,", "and the Amorites,"], ["ma sa Perisē,", "the Canaanites, and the Perizzites,"], ["o sa Hivī,", "the Hivites,"], ["ma sa Iepuse;", "and the Jebusites;"], ["e pei ona fetalai mai o Ieova lou Atua ia te oe;", "as the LORD thy God hath commanded thee:"]]},
  {num:18,words:[["ina ne'i latou a'oa'o mai ia te outou e fai e tusa ma a latou mea inosia uma,", "That they teach you not to do after all their abominations,"], ["ua latou faia i o latou atua;", "which they have done unto their gods;"], ["ona outou agasala ai lea ia Ieova lo outou Atua.", "so should ye sin against the LORD your God."]]},
  {num:19,words:[["Afai foi e tele ni aso ua e siosioina ai se aai,", "When thou shalt besiege a city a long time,"], ["ma tau ai le taua ina ia maua,", "in making war against it to take it,"], ["aua ne'i e faataumaoi ona laau i ta a'i i le mătau; auā e te 'ai ai,", "thou shalt not destroy the trees thereof by forcing an axe against them:"], ["aua e te ta i lalo e fai a'i se mea i le siosioina o le aai ,", "for thou mayest eat of them,"], ["(auā o le laau o le fanua mo tagata ia).", "and thou shalt not cut them down (for the tree of the field is man's life) to employ them in the siege:"]]},
  {num:20,words:[["Na o laau ua e iloa e le ni laau aina ia,", "Only the trees which thou knowest that they be not trees for meat,"], ["e te faataumaoi ma ta i lalo;", "thou shalt destroy and cut them down;"], ["e te faia foi se 'olo e faafeagai ma lea aai lua te tau ai le taua,", "and thou shalt build bulwarks against the city that maketh war with thee,"], ["seia faatoilaloina.", "until it be subdued."]]},
];
renderVerseSet(deu_ch_20_Verses, 'deu-ch20-verses');

var deu_ch_21_Verses = [
  {num:1,words:[["Afai e maua se tagata ua fasiotia i le laueleele ua foaiina mai e Ieova lou Atua ia te oe e fai mou o loo taatia i le vao,", "If one be found slain in the land which the LORD thy God giveth thee to possess it, lying in the field,"], ["a e le iloa po o ai na na fasi ia te ia;", "and it be not known who hath slain him:"]]},
  {num:2,words:[["ia o atu ou toeaina ma ou faamasino,", "Then thy elders and thy judges shall come forth,"], ["ma ia latou fuatia atu o va o lē ua fasiotia ma aai e vagavagai;", "and they shall measure unto the cities which are round about him that is slain:"]]},
  {num:3,words:[["o le aai foi e lata i le ua fasiotia ia ave e toeaina o lea aai se povi fafine,", "And it shall be, that the city which is next unto the slain man,"], ["ua na le fai se galuega,", "even the elders of that city shall take an heifer,"], ["ua na le toso i le amo;", "which hath not been wrought with, and which hath not drawn in the yoke;"]]},
  {num:4,words:[["ia ta'ita'iina foi e toeaina o lea aai le povi fafine i se alia e tafe pea,", "And the elders of that city shall bring down the heifer unto a rough valley,"], ["e le galueina e tagata , e le luluina ai foi ni saito,", "which is neither eared nor sown,"], ["ona latou vaea ai lea le ua o le povi fafine i le alia;", "and shall strike off the heifer's neck there in the valley:"]]},
  {num:5,words:[["ona faalatalata atu ai lea o faitaulaga,", "And the priests the sons of Levi shall come near;"], ["o le fanauga a Levi;", "for them the LORD thy God hath chosen to minister unto him,"], ["auā ua filifilia i latou e Ieova lou Atua e auauna ia te ia, ma faamanuia atu i le suafa Ieova;", "and to bless in the name of the LORD;"], ["o a latou upu foi e tonu ai finauga uma ma fasiga uma lava;", "and by their word shall every controversy and every stroke be tried:"]]},
  {num:6,words:[["o toeaina uma foi o lea aai,", "And all the elders of that city,"], ["ua lata i le ua fasiotia,", "that are next unto the slain man,"], ["latou te fafano o latou lima i luga o le povi fafine na vaea lona ua i le alia;", "shall wash their hands over the heifer that is beheaded in the valley:"]]},
  {num:7,words:[["ona latou fai mai lea,", "And they shall answer and say,"], ["e faapea mai, E lei faamaligiina lenei toto e o matou lima,", "Our hands have not shed this blood,"], ["e lei vaai i ai foi o matou mata.", "neither have our eyes seen it."]]},
  {num:8,words:[["Ieova e,", "Be merciful,"], ["ia e faamagalo mai i lou nuu o Isaraelu,", "O LORD,"], ["ua e togiolaina;", "unto thy people Israel, whom thou hast redeemed,"], ["aua foi e te faaee mai i lou nuu o Isaraelu le toto o le ua le sala.", "and lay not innocent blood unto thy people of Israel's charge."], ["Ona faamagaloina ai lea o i latou ai le toto.", "And the blood shall be forgiven them."]]},
  {num:9,words:[["Ona e tuueseina ai lea ia te oe o le toto o le ua le sala,", "So shalt thou put away the guilt of innocent blood from among you,"], ["pe a e faia le mea tonu i luma o Ieova.", "when thou shalt do that which is right in the sight of the LORD."]]},
  {num:10,words:[["A ē alu atu e tau ai le taua ma ou fili,", "When thou goest forth to war against thine enemies,"], ["pe a tuuina mai foi i latou ia te oe e Ieova lou Atua,", "and the LORD thy God hath delivered them into thine hands,"], ["ma e ave i latou o tagata o taua,", "and thou hast taken them captive,"]]},
  {num:11,words:[["ma e iloa se fafine lalelei i nā tagata o taua,", "And seest among the captives a beautiful woman,"], ["ua e manao foi i ai,", "and hast a desire unto her,"], ["ma e ave e fai mau avā;", "that thou wouldest have her to thy wife;"]]},
  {num:12,words:[["ona e au mai lea ia te ia i lou fale;", "Then thou shalt bring her home to thine house;"], ["ona tafi lea e ia o lona ulu,", "and she shall shave her head,"], ["ma salasala e ia ona atigilima;", "and pare her nails;"]]},
  {num:13,words:[["ia to ese foi e ia lona ofu faatagata o taua,", "And she shall put the raiment of her captivity from off her,"], ["ma nofo o ia i lou fale,", "and shall remain in thine house,"], ["e tagi foi o ia i lona tamā ma lona tinā i le masina atoa;", "and bewail her father and her mother a full month:"], ["ona e alu ane lea ia te ia,", "and after that thou shalt go in unto her,"], ["e fai foi oe mana tane,", "and be her husband,"], ["e fai foi o ia mau avā.", "and she shall be thy wife."]]},
  {num:14,words:[["Afai foi e leai sou fiafia ia te ia,", "And it shall be,"], ["ona e tuuina atu lea o ia ia sa'o lona loto;", "if thou have no delight in her,"], ["a e aua lava ne'i e faatau ia te ia i tupe,", "then thou shalt let her go whither she will; but thou shalt not sell her at all for money,"], ["aua foi e te fai o ia ma pologa,", "thou shalt not make merchandise of her,"], ["auā ua e faasaunoa ia te ia", "because thou hast humbled her."]]},
  {num:15,words:[["Afai e toalua avā a se tasi tagata,", "If a man have two wives,"], ["ua fiafia ia i le tasi,", "one beloved,"], ["a e 'ino'ino i le tasi,", "and another hated,"], ["ma ua la fananau ia te ia o a la tama tane,", "and they have born him children,"], ["o le ua ia fiafia i ai ma le ua inosia;", "both the beloved and the hated;"], ["afai foi e luai fanau mai le tama a le ua inosia;", "and if the firstborn son be hers that was hated:"]]},
  {num:16,words:[["a oo i le aso na te tofia ai ana mea i ona atalii,", "Then it shall be,"], ["e le mafai ona avea ma ulumatua le tama a le ua ia fiafia i ai,", "when he maketh his sons to inherit that which he hath,"], ["a e tuua le tama a le ua inosia,", "that he may not make the son of the beloved firstborn before the son of the hated,"], ["auā o le ulumatua ia;", "which is indeed the firstborn:"]]},
  {num:17,words:[["a ia faailogaina lava e ia o le ulumatua o le tama lea a le ua inosia,", "But he shall acknowledge the son of the hated for the firstborn,"], ["i lona avatu ia te ia o vaega e lua i mea uma lava ua ia te ia;", "by giving him a double portion of all that he hath:"], ["auā o ia le amataga o lona malosi;", "for he is the beginning of his strength;"], ["e ona le tofi o le ulumatua.", "the right of the firstborn is his."]]},
  {num:18,words:[["Afai e vaogata ma le finauvale le atalii o se tasi tagata,", "If a man have a stubborn and rebellious son,"], ["e le faalogo i le upu a lona tamā,", "which will not obey the voice of his father,"], ["po o le upu a lona tinā,", "or the voice of his mother, and that,"], ["pe a uma ona la aoai atu i ai,", "when they have chastened him,"], ["a e le faalogo lava o ia ia te i laua;", "will not hearken unto them:"]]},
  {num:19,words:[["ona tago ai lea o lona tamā ma lona tinā ia te ia,", "Then shall his father and his mother lay hold on him,"], ["ma avatu ia te ia i toeaina o lana aai,", "and bring him out unto the elders of his city,"], ["i le faitotoa o lana aai;", "and unto the gate of his place;"]]},
  {num:20,words:[["ona fai atu lea o i laua i toeaina o lana aai,", "And they shall say unto the elders of his city,"], ["O la ma tama nei ua vaogata ma le finauvale ia,", "This our son is stubborn and rebellious,"], ["e lei faalogo lava i a ma upu;", "he will not obey our voice;"], ["o le 'ai tele foi ia,", "he is a glutton,"], ["ma le inu ia onā.", "and a drunkard."]]},
  {num:21,words:[["Ona fetogi ai lea o tagata uma o lana aai ia te ia i maa,", "And all the men of his city shall stone him with stones,"], ["ia oti o ia;", "that he die:"], ["ona e tuueseina ai lea o le leaga ia te oe;", "so shalt thou put evil away from among you;"], ["e faalogo ai foi Isaraelu uma lava,", "and all Israel shall hear,"], ["ma latou matatau ai.", "and fear."]]},
  {num:22,words:[["Afai foi o se tagata ua na fai se agasala e tatau ona oti ai o ia,", "And if a man have committed a sin worthy of death,"], ["a oo ia te ia le oti,", "and he be to be put to death,"], ["ua e faatautau foi ia te ia i se laau;", "and thou hang him on a tree:"]]},
  {num:23,words:[["aua ne'i aoina lona tino i le laau,", "His body shall not remain all night upon the tree,"], ["a ia e tanu lava ia te ia i lea aso;", "but thou shalt in any wise bury him that day;"], ["(auā ua faafanoina e le Atua le ua faatautauina;", "(for he that is hanged is accursed of God; ) that thy land be not defiled,"], [") ina ne'i leaga ai lou laueleele ua foaiina mai e Ieova lou Atua ia te oe e fai mou tofi.", "which the LORD thy God giveth thee for an inheritance."]]},
];
renderVerseSet(deu_ch_21_Verses, 'deu-ch21-verses');

var deu_ch_22_Verses = [
  {num:1,words:[["A ē iloa le povi a lou uso po o lana mamoe ua se,", "Thou shalt not see thy brother's ox or his sheep go astray,"], ["aua ne'i e lafi ia te ia;", "and hide thyself from them:"], ["a ia e matuā ta'ita'iina atu i lou uso.", "thou shalt in any case bring them again unto thy brother."]]},
  {num:2,words:[["Afai foi lua te le felatai ma lou uso,", "And if thy brother be not nigh unto thee,"], ["po ua e le iloa o ia,", "or if thou know him not,"], ["ona e ta'ita'iina ai lea i lou fale,", "then thou shalt bring it unto thine own house,"], ["ona i ai lea ia te oe seia sailia mai e lou uso,", "and it shall be with thee until thy brother seek after it,"], ["ona e avatu ai lea ia te ia.", "and thou shalt restore it to him again."]]},
  {num:3,words:[["Ia e faapea foi ona fai i lana asini;", "In like manner shalt thou do with his ass;"], ["e faapea foi ona e fai i lona ofu;", "and so shalt thou do with his raiment;"], ["ia e faapea foi ona fai i mea uma ua le iloa a lou uso,", "and with all lost thing of thy brother's, which he hath lost,"], ["ua le iloa e ia,", "and thou hast found,"], ["a ua e maua;", "shalt thou do likewise:"], ["e le mafai ona e lafi ai.", "thou mayest not hide thyself."]]},
  {num:4,words:[["Aua ne'i e iloa le asini a lou uso po o lana povi ua paū i le ala,", "Thou shalt not see thy brother's ass or his ox fall down by the way,"], ["ma e lafi ai;", "and hide thyself from them:"], ["a ia oulua toalua ma ia e faatu ia te ia.", "thou shalt surely help him to lift them up again."]]},
  {num:5,words:[["Aua ne'i ofu le fafine i le ofu o le tane;", "The woman shall not wear that which pertaineth unto a man,"], ["aua foi le ofu le tane i le ofu o le fafine;", "neither shall a man put on a woman's garment:"], ["auā e inosia e Ieova lou Atua i latou uma lava o e faia na mea.", "for all that do so are abomination unto the LORD thy God."]]},
  {num:6,words:[["Afai o i ai i ou luma se ofaga o se manu i le ala,", "If a bird's nest chance to be before thee in the way in any tree,"], ["i se laau po o le laueleele,", "or on the ground,"], ["o i ai ni tama po o fua,", "whether they be young ones, or eggs,"], ["o loo moe ai le tinā i ana tama,", "and the dam sitting upon the young,"], ["po ona fua,", "or upon the eggs,"], ["aua ne'i e ave faatasi le tinā ma ana tam;", "thou shalt not take the dam with the young:"]]},
  {num:7,words:[["ia e tuu atu lava le tinā e faasola,", "But thou shalt in any wise let the dam go,"], ["a ia e ave ma oe ana,", "and take the young to thee;"], ["tama; ina ia lelei ai oe,", "that it may be well with thee,"], ["ma e faafualoa ai ou aso.", "and that thou mayest prolong thy days."]]},
  {num:8,words:[["A ē fai se fale fou,", "When thou buildest a new house,"], ["ia e fai se puipui e sio ai i luga o lou fale,", "then thou shalt make a battlement for thy roof,"], ["ne'i e faamaligiina le toto talu lou fale,", "that thou bring not blood upon thine house,"], ["pe afai e paū ai se tasi.", "if any man fall from thence."]]},
  {num:9,words:[["Aua e te totō fua eseese i lou tovine;", "Thou shalt not sow thy vineyard with divers seeds:"], ["ne'i leaga ai mea e tutupu i au fua na e totōina,", "lest the fruit of thy seed which thou hast sown, and the fruit of thy vineyard,"], ["atoa ma le fua o lou tovine.", "be defiled."]]},
  {num:10,words:[["Aua e te suatia le fanua i se povi ma se asini e faatasi.", "Thou shalt not plow with an ox and an ass together."]]},
  {num:11,words:[["Aua e te ofu i se ofu ie lalaga fefiloi i mea uiga eseese,", "Thou shalt not wear a garment of divers sorts,"], ["o fulufulu mamoe ma lino.", "as of woollen and linen together."]]},
  {num:12,words:[["Ia e faia mo oe o tuupao i pito e fa o lou ofu e te ofu ai.", "Thou shalt make thee fringes upon the four quarters of thy vesture, wherewith thou coverest thyself."]]},
  {num:13,words:[["Afai e fai avā se tagata,", "If any man take a wife, and go in unto her,"], ["ma alu i ai,", "and hate her,"]]},
  {num:14,words:[["a e 'ino'ino ia te ia,", "And give occasions of speech against her,"], ["ma fai mea e upuia ai o ia,", "and bring up an evil name upon her,"], ["ma ta'uleagaina ai o ia, ua faapea ane foi o ia,", "and say,"], ["Na ou fai avā i lenei fafine,", "I took this woman,"], ["na ou alu i ai,", "and when I came to her,"], ["ona ou iloa ai lea e le se taupou o ia;", "I found her not a maid:"]]},
  {num:15,words:[["ona ave ai lea e le tamā ma le tinā o le teine o failoga o le taupou o le teine,", "Then shall the father of the damsel,"], ["ma avatu ai i toeaina o le aai,", "and her mother,"], ["i le faitotoa;", "take and bring forth the tokens of the damsel's virginity unto the elders of the city in the gate:"]]},
  {num:16,words:[["ona fai atu lea o le tamā o le teine i toeaina,", "And the damsel's father shall say unto the elders,"], ["Na ou avatu lo'u afafine i lenei tagata e fai mana avā,", "I gave my daughter unto this man to wife,"], ["a ua 'ino'ino o ia ia te ia;", "and he hateth her;"]]},
  {num:17,words:[["faauta foi,", "And,"], ["ua upuia le teine talu o ia,", "lo,"], ["ua faapea ana,", "he hath given occasions of speech against her, saying,"], ["Ua ou iloa o lou afafine e le se taupou ia;", "I found not thy daughter a maid;"], ["a o faailoga nei o le taupou o lo'u afafine.", "and yet these are the tokens of my daughter's virginity."], ["Ona fola atu lea e i laua o le ie i luma o toeaina o le aai.", "And they shall spread the cloth before the elders of the city."]]},
  {num:18,words:[["Ona ave lea e toeaina o lea aai lena tagata, ma latou sasa ia te ia;", "And the elders of that city shall take that man and chastise him;"]]},
  {num:19,words:[["latou te faasalaina atu foi o ia i tupe e selau,", "And they shall amerce him in an hundred shekels of silver,"], ["ma avatua i le tamā o le teine,", "and give them unto the father of the damsel,"], ["auā o ia ua ta'uleagaina ai se taupou Isaraelu. E fai pea foi o ia māna avā;", "because he hath brought up an evil name upon a virgin of Israel: and she shall be his wife;"], ["na te le toe mafai ona alei ia te ia i ona aso uma lava.", "he may not put her away all his days."]]},
  {num:20,words:[["A e peitai afai ua moni lena upu,", "But if this thing be true,"], ["ua le maua faailoga o le taupou o le teine;", "and the tokens of virginity be not found for the damsel:"]]},
  {num:21,words:[["ona latou avatu lea o le teine i le faitotoa o le fale o lona tamā,", "Then they shall bring out the damsel to the door of her father's house,"], ["ona fetogi lea e tagata o lana aai ia te ia i maa,", "and the men of her city shall stone her with stones that she die:"], ["ia oti; auā ua faia e ia le mea leaga i Isaraelu,", "because she hath wrought folly in Israel,"], ["ina ua faitaaga i le aiga o lona tamā;", "to play the whore in her father's house:"], ["ona outou tuueseina ai lea o le leaga ia te outou.", "so shalt thou put evil away from among you."]]},
  {num:22,words:[["A iloa se tane ua la momoe ma se fafine nofo tane,", "If a man be found lying with a woman married to an husband,"], ["ia oti i laua,", "then they shall both of them die,"], ["o le tane na la momoe ma le fafine,", "both the man that lay with the woman,"], ["atoa ma le fafine;", "and the woman:"], ["ona e tuueseina ai lea o le leaga ia Isaraelu.", "so shalt thou put away evil from Israel."]]},
  {num:23,words:[["Afai o se teine taupou ua fafautane,", "If a damsel that is a virgin be betrothed unto an husband,"], ["ua maua o ia e se tane i le aai,", "and a man find her in the city,"], ["ma la momoe ma ia;", "and lie with her;"]]},
  {num:24,words:[["ona outou ta'ita'iina atu lea o i laua i le faitotoa o lena aai,", "Then ye shall bring them both out unto the gate of that city,"], ["ma outou fetogi ia te i laua i mea,", "and ye shall stone them with stones that they die;"], ["ia oti;", "the damsel,"], ["o le teine,", "because she cried not,"], ["ina ua le alaga o ia i le aai;", "being in the city;"], ["o le tane foi,", "and the man,"], ["ina ua faaleagaina e ia le avā a lē la te tuaoi;", "because he hath humbled his neighbour's wife:"], ["ona e tuueseina ai lea o le leaga ia te oe.", "so thou shalt put away evil from among you."]]},
  {num:25,words:[["A e afai maua i le vao e se tane se teine ua faufautane,", "But if a man find a betrothed damsel in the field,"], ["a toso faamalosi foi le tane ia te ia,", "and the man force her,"], ["ma la momoe ma ia;", "and lie with her:"], ["ia oti lava tau o le tane na momoe ma ia;", "then the man only that lay with her shall die:"]]},
  {num:26,words:[["a o le teine,", "But unto the damsel thou shalt do nothing;"], ["aua tou te faia se mea ia te ia;", "there is in the damsel no sin worthy of death:"], ["auā e le o i le teine se agasala ia oti ai o ai ;", "for as when a man riseth against his neighbour, and slayeth him,"], ["auā ua tusa le mea nei ma le tulai atu o le tgama fasioti i lē la te tuaoi;", "even so is this matter:"]]},
  {num:27,words:[["auā ua na maua o ia i le vao,", "For he found her in the field,"], ["na alaga foi le teine ua faufautane,", "and the betrothed damsel cried,"], ["a ua leai se tasi e laveai ia te ia.", "and there was none to save her."]]},
  {num:28,words:[["A e afai foi e maua e se tane se teine taupou ua le faufautane,", "If a man find a damsel that is a virgin,"], ["ma tago atu ia te ia,", "which is not betrothed,"], ["ma la momoe ma ia,", "and lay hold on her, and lie with her,"], ["ua maua foi i laua;", "and they be found;"]]},
  {num:29,words:[["ia avatu e le tane na la momoe ma ia i le tamā o le teine o tupe e lima sefulu,", "Then the man that lay with her shall give unto the damsel's father fifty shekels of silver,"], ["ona fai ai lea o ia mana avā;", "and she shall be his wife;"], ["auā ua na na faaleaga ia te ia,", "because he hath humbled her,"], ["na te le mafai ona alei ia te ia i ona aso uma lava.", "he may not put her away all his days."]]},
  {num:30,words:[["Aua ne'i fai avā se tasi i le avā a lona tamā;", "A man shall not take his father's wife,"], ["aua foi te susue le ie o lona tamā.", "nor discover his father's skirt."]]},
];
renderVerseSet(deu_ch_22_Verses, 'deu-ch22-verses');

var deu_ch_23_Verses = [
  {num:1,words:[["Aua ne'i alu i le faapotopotoga a Ieova se tagata ua manua ua momomoina ona fuāmanava ,", "He that is wounded in the stones, or hath his privy member cut off,"], ["po ua vavaeeseina lona aualuma.", "shall not enter into the congregation of the LORD."]]},
  {num:2,words:[["Aua ne'i alu se tama toifale i le faapotopotoga a Ieova;", "A bastard shall not enter into the congregation of the LORD;"], ["aua lava ne'i alu o ia i le faapotopotoga a Ieova e oo lava i le sefulu o augātupulaga.", "even to his tenth generation shall he not enter into the congregation of the LORD."]]},
  {num:3,words:[["Aua ne'i alu so sa Amorī, po o so sa Moapī i le faapotopotoga a Ieova;", "An Ammonite or Moabite shall not enter into the congregation of the LORD;"], ["e oo lava i le sefulu o augātupulaga, aua ne'i latou o i le faapotopotoga a Ieova e oo i le faavavau;", "even to their tenth generation shall they not enter into the congregation of the LORD for ever:"]]},
  {num:4,words:[["auā na latou le fafetaiai atu ia te outou i le ala ma ni areto ma ni vai,", "Because they met you not with bread and with water in the way,"], ["ina o outou o mai mai Aikupito;", "when ye came forth out of Egypt;"], ["auā foi na latou faaoloa ia Palaamo le atalii o Peoro, nai Petoru i Mesopotamia,", "and because they hired against thee Balaam the son of Beor of Pethor of Mesopotamia,"], ["ma te faafano ia te oe.", "to curse thee."]]},
  {num:5,words:[["A e lei finagalo Ieova lou Atua e faafofoga ia Palaamo;", "Nevertheless the LORD thy God would not hearken unto Balaam;"], ["a ua faaliliuina e Ieova lou Atua le faafano e fai ma faamanuia ia te oe,", "but the LORD thy God turned the curse into a blessing unto thee,"], ["auā na alofa mai Ieova lou Atua ia te oe.", "because the LORD thy God loved thee."]]},
  {num:6,words:[["Aua ne'i e fai se mea e filemu ai i latou, pe manuia ai i latou i ou aso uma lava e faavavau.", "Thou shalt not seek their peace nor their prosperity all thy days for ever."]]},
  {num:7,words:[["Aua e te 'ino'ino i so sa Etomā,", "Thou shalt not abhor an Edomite;"], ["auā o lou uso lea;", "for he is thy brother:"], ["aua e te 'ino'ino i se Aikupito,", "thou shalt not abhor an Egyptian;"], ["auā sa fai oe ma tagata ese i lona nuu.", "because thou wast a stranger in his land."]]},
  {num:8,words:[["O atalii e fanau mai ia te i latou i lona tolu o tupulaga e ō i latou i le faapotopotoga a Ieova.", "The children that are begotten of them shall enter into the congregation of the LORD in their third generation."]]},
  {num:9,words:[["Pe a o atu 'au e tau le taua ma e ita mai ia te oe, ia oe,", "When the host goeth forth against thine enemies,"], ["ne'i e faia se mea leaga.", "then keep thee from every wicked thing."]]},
  {num:10,words:[["Afai o ia te outou se tagata e oo ia te ia le leaga i le po,", "If there be among you any man,"], ["ia alu ia i tua o le toagālauapi,", "that is not clean by reason of uncleanness that chanceth him by night, then shall he go abroad out of the camp,"], ["aua ne'i toe foi mai o ia i le toagālauapi;", "he shall not come within the camp:"]]},
  {num:11,words:[["a oo i le afiafi,", "But it shall be,"], ["ona taele ai lea o ia i le vai;", "when evening cometh on,"], ["a goto foi le la,", "he shall wash himself with water: and when the sun is down,"], ["ia toe foi mai o ia i le toagālauapi.", "he shall come into the camp again."]]},
  {num:12,words:[["Ia ia te oe foi se mea i tua o le toagālauapi,", "Thou shalt have a place also without the camp,"], ["e te alu atu foi i ai;", "whither thou shalt go forth abroad:"]]},
  {num:13,words:[["ia ia ie te oe foi sina suo i lau auupega;", "And thou shalt have a paddle upon thy weapon;"], ["a ē ui foi i le vao,", "and it shall be,"], ["ia e eli a'i,", "when thou wilt ease thyself abroad,"], ["ona e liliu lea,", "thou shalt dig therewith,"], ["ma tanu lou otaota;", "and shalt turn back and cover that which cometh from thee:"]]},
  {num:14,words:[["auā o loo savali Ieova lou Atua i totonu o lau toagālauapi,", "For the LORD thy God walketh in the midst of thy camp,"], ["e laveai ia te oe,", "to deliver thee,"], ["ma tuuina mai e ua ita ia te oe i ou luma;", "and to give up thine enemies before thee;"], ["o le mea lea e faapaiaina ai lau toagālauapi;", "therefore shall thy camp be holy:"], ["ne'i silasila o ia i se mea leaga o ia te oe,", "that he see no unclean thing in thee,"], ["ma liliu ese o ia ia te oe.", "and turn away from thee."]]},
  {num:15,words:[["Aua e te tuuina atu i lona matai le auauna ua sola mai ia te oe i lona matai;", "Thou shalt not deliver unto his master the servant which is escaped from his master unto thee:"]]},
  {num:16,words:[["e mau o ia ia te oe,", "He shall dwell with thee,"], ["i lou nuu,", "even among you,"], ["i le mea e filifilia e ia i se tasi o au aai,", "in that place which he shall choose in one of thy gates,"], ["e lelei ia te ia;", "where it liketh him best:"], ["aua ne'i e faasaua ia te ia.", "thou shalt not oppress him."]]},
  {num:17,words:[["Aua ne'i ai se fafine talitane o afafine o Isaraelu;", "There shall be no whore of the daughters of Israel,"], ["aua foi ne'i ai se tane faasotoma o atalii o Isaraelu,", "nor a sodomite of the sons of Israel."]]},
  {num:18,words:[["Aua ne'i e avatu i le fale o Ieova lou Atua le totogi o le fafine talitane,", "Thou shalt not bring the hire of a whore,"], ["po o le tau o se ulī,", "or the price of a dog,"], ["e fai ma mea na tauto ai;", "into the house of the LORD thy God for any vow:"], ["auā e inosia nei mea e lua e Ieova lou Atua.", "for even both these are abomination unto the LORD thy God."]]},
  {num:19,words:[["Aua ne'i e avatu i lou uso se mea e totogi faasili mai ai;", "Thou shalt not lend upon usury to thy brother;"], ["o le totogi faasili mai i ario,", "usury of money,"], ["po o le totogi faasili mai i mea e 'ai,", "usury of victuals,"], ["po o le totogi faasili mai i nisi mea uma e totogi faasili mai ai;", "usury of any thing that is lent upon usury:"]]},
  {num:20,words:[["e te avatu mea e totogi faasili mai ai i le tagata ese; a o lou uso,", "Unto a stranger thou mayest lend upon usury;"], ["aua e te avatu i ai ni mea e totogi faasili mai ai;", "but unto thy brother thou shalt not lend upon usury:"], ["ina ia faamanuia mai ai Ieova lou Atua ia te oe i mea uma lava e te faia i ou lima, i le nuu e te alu i ai e fai mou.", "that the LORD thy God may bless thee in all that thou settest thine hand to in the land whither thou goest to possess it."]]},
  {num:21,words:[["Afai e te tauto i se tautoga ia Ieova lou Atua,", "When thou shalt vow a vow unto the LORD thy God,"], ["aua ne'i e faatuai ona avatu ai;", "thou shalt not slack to pay it:"], ["auā e matuā sueina atu ai ia te oe e Ieova lou Atua;", "for the LORD thy God will surely require it of thee;"], ["e fai lea ma agasala ia te oe.", "and it would be sin in thee."]]},
  {num:22,words:[["A e afai e te le tauto lava,", "But if thou shalt forbear to vow,"], ["e le se agasala lea ia te oe.", "it shall be no sin in thee."]]},
  {num:23,words:[["O le upu ua mavae atu i lou gutu ia e anaana i ai ma e faia,", "That which is gone out of thy lips thou shalt keep and perform;"], ["o le taulaga e loto ina fai,", "even a freewill offering,"], ["e tusa ma lau tautoga ia Ieova lou Atua,", "according as thou hast vowed unto the LORD thy God,"], ["ua folafolaina e oe.", "which thou hast promised with thy mouth."]]},
  {num:24,words:[["Pe a e alu i le tovine o lē lua te tuaoi,", "When thou comest into thy neighbour's vineyard,"], ["e te 'ai vine faitalia oe seia e ma'ona;", "then thou mayest eat grapes thy fill at thine own pleasure;"], ["a e aua e te fafao nisi i lau ato.", "but thou shalt not put any in thy vessel."]]},
  {num:25,words:[["Pe a e alu i le saito o loo tu o lē lua te tuaoi,", "When thou comest into the standing corn of thy neighbour,"], ["e te tau mai ona fua i lou lima;", "then thou mayest pluck the ears with thine hand;"], ["a e aua e te selesele i lau selesaito le saito o loo tu o lē lua te tuaoi.", "but thou shalt not move a sickle unto thy neighbour's standing corn."]]},
];
renderVerseSet(deu_ch_23_Verses, 'deu-ch23-verses');

var deu_ch_24_Verses = [
  {num:1,words:[["Afai e fai avā se tasi i se fafine,", "When a man hath taken a wife,"], ["ua la nonofo,", "and married her,"], ["a oo foi ina le toe fiafia o ia i ai,", "and it come to pass that she find no favour in his eyes,"], ["auā ua na iloa ia te ia se mea leaga;", "because he hath found some uncleanness in her:"], ["ona tusi ai lea e ia se tusi alei ma ia,", "then let him write her a bill of divorcement,"], ["ma avatu ai ia te ia,", "and give it in her hand,"], ["ma auina atu o ia ai lona fale.", "and send her out of his house."]]},
  {num:2,words:[["Pe a alu ese foi o ia i lona fale,", "And when she is departed out of his house,"], ["ona alu ai lea o ia ma nofo i se tasi tane;", "she may go and be another man's wife."]]},
  {num:3,words:[["afai foi e 'ino'ino ia te ia lana tane mulimuli,", "And if the latter husband hate her,"], ["ma tusi se tusi alei ma ia,", "and write her a bill of divorcement,"], ["ma avatu ai ia te ia,", "and giveth it in her hand,"], ["ma auina atu o ia ai lona fale;", "and sendeth her out of his house;"], ["pe afai foi ua oti le tane mulimuli,", "or if the latter husband die,"], ["na fai avā ia te ia;", "which took her to be his wife;"]]},
  {num:4,words:[["e le mafai i lana muai tane,", "Her former husband,"], ["sa na auina o ia,", "which sent her away,"], ["ona toe fai o ia mana avā,", "may not take her again to be his wife, after that she is defiled;"], ["ina ua uma ona faaleagaina o ia;", "for that is abomination before the LORD:"], ["auā o le mea inosia lea i luma o Ieova;", "and thou shalt not cause the land to sin,"], ["aua foi ne'i e faatupuina le agasala i le nuu ua foaiina mai e Ieova lou Atua ia te oe e fai mou tofi.", "which the LORD thy God giveth thee for an inheritance."]]},
  {num:5,words:[["Afai foi e faatoa fai avā se tasi,", "When a man hath taken a new wife,"], ["aua ne'i alu o ia i le taua,", "he shall not go out to war,"], ["aua foi ne'i togia o ia i se feau a le nuu ;", "neither shall he be charged with any business:"], ["ia saoloto o ia i lona aiga i le tausaga e tasi,", "but he shall be free at home one year,"], ["ma faafiafia atu ai i lana avā ua fai.", "and shall cheer up his wife which he hath taken."]]},
  {num:6,words:[["Aua ne'i ave faafaatau e se tagata se maaolo i lalo, po o se maaolo i luga;", "No man shall take the nether or the upper millstone to pledge:"], ["auā e ave ai faafaatau le ola o le tagata .", "for he taketh a man's life to pledge."]]},
  {num:7,words:[["Afai ua maua se tagata ua gaoi i se tasi o ona uso o le fanauga a Isaraelu,", "If a man be found stealing any of his brethren of the children of Israel,"], ["ma fai o ia ma pologa,", "and maketh merchandise of him,"], ["pe faatauina atu o ia;", "or selleth him;"], ["ia oti lea tagata gaoi;", "then that thief shall die;"], ["ona e tuueseina ai lea o le leaga ia te oe.", "and thou shalt put evil away from among you."]]},
  {num:8,words:[["Ia oe i le ma'i lepela,", "Take heed in the plague of leprosy,"], ["ia e matuā anaana,", "that thou observe diligently,"], ["ma e faia mea uma lava e pei ona a'oa'oina ai outou e le au faitaulaga, o sa Levī;", "and do according to all that the priests the Levites shall teach you:"], ["e faapei ona ou fai atu ai ia te i latou,", "as I commanded them,"], ["ia outou anaana i ai ia faia.", "so ye shall observe to do."]]},
  {num:9,words:[["Ia e manatua le mea na faia e Ieova lou Atua ia Miriama i le ala,", "Remember what the LORD thy God did unto Miriam by the way,"], ["ina ua outou o mai ai nai Aikupito.", "after that ye were come forth out of Egypt."]]},
  {num:10,words:[["Afai e avatu o oe se mea ua aitalafu mai e lē lua te tuaoi,", "When thou dost lend thy brother any thing,"], ["aua ne'i e alu i lona fale e au mai ai lana mea ua tuu faafaatau a ia e tu i fafo,", "thou shalt not go into his house to fetch his pledge."]]},
  {num:11,words:[["ona au mai ai lea i fafo ia te oe o le me ua tuu faafaatau e le tagata na e avatu i ai mea ua aitalafu mai.", "Thou shalt stand abroad, and the man to whom thou dost lend shall bring out the pledge abroad unto thee."]]},
  {num:12,words:[["Afai foi o le tagata mativa o ia,", "And if the man be poor,"], ["aua e te moegaiina lana mea ua tuu faafaatau;", "thou shalt not sleep with his pledge:"]]},
  {num:13,words:[["a ia e toe avatua lava ia te ia le mea ua tuu faafaatau a o lei goto le la,", "In any case thou shalt deliver him the pledge again when the sun goeth down,"], ["ina ia moe o ia i lona lava ofu,", "that he may sleep in his own raiment,"], ["ma faamanu ia te oe;", "and bless thee:"], ["e avea foi lea ma amiotonu ia te oe i luma o Ieova lou Atua.", "and it shall be righteousness unto thee before the LORD thy God."]]},
  {num:14,words:[["Aua e te faasaua i se auauna tauia ua puapuapatia ma le mativa,", "Thou shalt not oppress an hired servant that is poor and needy,"], ["o sou uso,", "whether he be of thy brethren,"], ["po o se āumau ia te oe o i lou nuu i au aai;", "or of thy strangers that are in thy land within thy gates:"]]},
  {num:15,words:[["ia e avatu ia te ia lona totogi i lona lava aso,", "At his day thou shalt give him his hire,"], ["a o lei goto le la;", "neither shall the sun go down upon it;"], ["auā ua mativa o ia,", "for he is poor,"], ["ua naunau foi i ai lona loto;", "and setteth his heart upon it:"], ["ne'i valaau o ia ia Ieova ona o oe,", "lest he cry against thee unto the LORD,"], ["ona fai lea ma agasala ia te oe.", "and it be sin unto thee."]]},
  {num:16,words:[["Aua ne'i fasiotia le tamā e sui a'i le atalii,", "The fathers shall not be put to death for the children,"], ["aua foi ne'i fasiotia le atalii, e sui a'i le tamā;", "neither shall the children be put to death for the fathers:"], ["a ia taitasi le tagata ma fasiotia o ia i lana lava agasala.", "every man shall be put to death for his own sin."]]},
  {num:17,words:[["Aua ne'i e faapiopioina le faamasinoga i le tagata ese,", "Thou shalt not pervert the judgment of the stranger,"], ["po o le ua āumatuā;", "nor of the fatherless;"], ["aua foi ne'i e fai faafaatau le ofu o le fafine ua oti lana tane;", "nor take a widow's raiment to pledge:"]]},
  {num:18,words:[["a ia e manatua na fai oe ma auauna i Aikupito,", "But thou shalt remember that thou wast a bondman in Egypt,"], ["a ua laveaiina oe e Ieova lou Atua ai lea mea;", "and the LORD thy God redeemed thee thence:"], ["o le mea lea ou te fai atu ai ia te oe e faia lenei mea.", "therefore I command thee to do this thing."]]},
  {num:19,words:[["A ē selesele i lau saito i lou fanua,", "When thou cuttest down thine harvest in thy field,"], ["a ua galo ia te oe se tasi fusi saito i le fanua,", "and hast forgot a sheaf in the field,"], ["aua ne'i e foi atu e au mai ai;", "thou shalt not go again to fetch it:"], ["a ia tuu ai mo le tagata ese,", "it shall be for the stranger,"], ["ma le ua aumatuā,", "for the fatherless,"], ["ma le fafine ua oti lana tane;", "and for the widow:"], ["ina ia faamanuia oe e Ieova lou Atua i mea uma lava e faia e ou lima.", "that the LORD thy God may bless thee in all the work of thine hands."]]},
  {num:20,words:[["A ē tautā i lāu olive,", "When thou beatest thine olive tree,"], ["aua e te toe suesue ona la;", "thou shalt not go over the boughs again:"], ["a ia tuu ai mo le tagata ese,", "it shall be for the stranger,"], ["ma le ua āumatuā,", "for the fatherless,"], ["ma le fafine ua oti lana tane.", "and for the widow."]]},
  {num:21,words:[["A ē tau i fua o lau tovine,", "When thou gatherest the grapes of thy vineyard,"], ["aua e te foi faalua e tau mai ai;", "thou shalt not glean it afterward:"], ["a ia tuu ai mo le tagata ese,", "it shall be for the stranger,"], ["ma le ua āumatuā,", "for the fatherless,"], ["ma le fafine ua oti lana tane.", "and for the widow."]]},
  {num:22,words:[["E te manatua na fai oe ma auauna i le nuu o Aikupito;", "And thou shalt remember that thou wast a bondman in the land of Egypt:"], ["o le mea lea ou te fai atu ai ia te oe ia e faia lenei mea.", "therefore I command thee to do this thing."]]},
];
renderVerseSet(deu_ch_24_Verses, 'deu-ch24-verses');

var deu_ch_25_Verses = [
  {num:1,words:[["Afai e faia e tagata se fefinauaiga,", "If there be a controversy between men,"], ["ma latou o mai i le faamasinoga,", "and they come unto judgment,"], ["ina ia faamasinoina ai i latou e faamasino ;", "that the judges may judge them;"], ["ona latou ta'uamiotonuina atu lea le ua amiotonu,", "then they shall justify the righteous,"], ["a e faasalaina le ua amioleaga.", "and condemn the wicked."]]},
  {num:2,words:[["Afai foi e tatau ona sasaina o le ua amioleaga,", "And it shall be, if the wicked man be worthy to be beaten,"], ["ona fai atu lea e le faamasino e faataatia ia te ia,", "that the judge shall cause him to lie down,"], ["ma sasaina o ia i ona luma,", "and to be beaten before his face,"], ["ia faatatau le faitau o ona ta i lana amio leaga.", "according to his fault, by a certain number."]]},
  {num:3,words:[["A fagafulu ona ta,", "Forty stripes he may give him,"], ["soia,", "and not exceed:"], ["a e aua ne'i faasili ai;", "lest,"], ["ne'i faaopoopo o ia i ai,", "if he should exceed,"], ["ma ta ia te ia i ni ta e tele,", "and beat him above these with many stripes,"], ["ona inosia ai lea o lou uso i ou luma.", "then thy brother should seem vile unto thee."]]},
  {num:4,words:[["Aua ne'i e fusi le gutu o le povi a o solisolia e ia le saito .", "Thou shalt not muzzle the ox when he treadeth out the corn."]]},
  {num:5,words:[["Afai e mau faatasi le uso,", "If brethren dwell together,"], ["a oti se tasi o i laua,", "and one of them die,"], ["e leai sana fanau,", "and have no child,"], ["aua ne'i nofo tane le avā a le ua oti i se tasi tagata ese;", "the wife of the dead shall not marry without unto a stranger:"], ["a ia alu i ai le uso o lana tane,", "her husband's brother shall go in unto her,"], ["ia fai mana avā,", "and take her to him to wife,"], ["ma tausi tama ia te ia.", "and perform the duty of an husband's brother unto her."]]},
  {num:6,words:[["Ona avatu ai lea o le igoa o lona uso ua oti i le tama ulumatua e fanau mai ia te ia,", "And it shall be, that the firstborn which she beareth shall succeed in the name of his brother which is dead,"], ["ina ne'i soloia lona igoa ia Isaraelu.", "that his name be not put out of Israel."]]},
  {num:7,words:[["Afai foi e le loto lea tagata,", "And if the man like not to take his brother's wife,"], ["e fai mana le avā a lona uso,", "then let his brother's wife go up to the gate unto the elders,"], ["ona alu ae ai lea o le avā a lona uso i toeaina i le faitotoa o le aai , ma fai atu,", "and say,"], ["E le mafai le uso o la'u tane ona faatumau mo lona uso se igoa ia Isaraelu,", "My husband's brother refuseth to raise up unto his brother a name in Israel,"], ["e le fia tausi tama mai o ia ia te au.", "he will not perform the duty of my husband's brother."]]},
  {num:8,words:[["Ona aami lea ia te ia e toeaina o lona aai,", "Then the elders of his city shall call him,"], ["ona tautala lea o i latou ia te ia;", "and speak unto him:"], ["afai foi e tu mai o ia,", "and if he stand to it,"], ["ma fai mai,", "and say,"], ["Ou te le fia fai avā ia te ia;", "I like not to take her;"]]},
  {num:9,words:[["ona sōsō atu lea o le avā a lona uso ia te ia i luma o toeaina,", "Then shall his brother's wife come unto him in the presence of the elders,"], ["ma to ese lona seevae ai lona vae,", "and loose his shoe from off his foot,"], ["ma feanu i ona luma, ma fai ane,", "and spit in his face,"], ["e faapea,", "and shall answer and say,"], ["E faapena lava ona fai i le tagata na te le mafaia ona ati ae le aiga o lona uso.", "So shall it be done unto that man that will not build up his brother's house."]]},
  {num:10,words:[["Ona ta'ua lea o lona igoa i Isaraelu,", "And his name shall be called in Israel,"], ["O le aiga o le ua toeseina lona seevae.", "The house of him that hath his shoe loosed."]]},
  {num:11,words:[["A femisai tagata,", "When men strive together one with another,"], ["o lea tagata ma lea tagata,", "and the wife of the one draweth near for to deliver her husband out of the hand of him that smiteth him,"], ["ona sōsō atu lea o le avā a le tasi na te laveaiina lana tane ai le lima o lē na te fasi ia te ia, ona tago atu lea o lona lima,", "and putteth forth her hand,"], ["ma papalu ia te ia;", "and taketh him by the secrets:"]]},
  {num:12,words:[["ona e tutū ese lava lea o lona tapulima,", "Then thou shalt cut off her hand,"], ["aua e te alofa ia te ia.", "thine eye shall not pity her."]]},
  {num:13,words:[["Aua ne'i ia te oe i lau taga o maa eseese e fua ai ,", "Thou shalt not have in thy bag divers weights,"], ["o le latele ma lē laitiiti.", "a great and a small."]]},
  {num:14,words:[["Aua ne'i ia te oe i lou fale o efa eseese,", "Thou shalt not have in thine house divers measures,"], ["o lē latele ma lē laitiiti.", "a great and a small."]]},
  {num:15,words:[["A ia ia te oe le maa fua atoatoa ma le tonu,", "But thou shalt have a perfect and just weight,"], ["ia ia te oe foi o le efa atoatoa ma le tonu;", "a perfect and just measure shalt thou have:"], ["ina ia faafualoa ai ou aso i le laueleele ua foaiina mai e Ieova lou Atua ia te oe.", "that thy days may be lengthened in the land which the LORD thy God giveth thee."]]},
  {num:16,words:[["Auā e inosia e Ieova lou Atua o i latou uma o e faia ia mea,", "For all that do such things, and all that do unrighteously,"], ["e taitasi uma o e faia le amioletonu.", "are an abomination unto the LORD thy God."]]},
  {num:17,words:[["Ia e manatua le mea na faia e Amaleka ia te oe i le ala,", "Remember what Amalek did unto thee by the way,"], ["ina ua outou o mai nai Aikupito;", "when ye were come forth out of Egypt;"]]},
  {num:18,words:[["ina ua faafetaiai mai o ia ia te oe i le ala,", "How he met thee by the way,"], ["ma ua na fafasi i ou tagata na mulimuli,", "and smote the hindmost of thee,"], ["o e na vaivai uma na mulimuli atu ia te oe,", "even all that were feeble behind thee,"], ["a o ē lailoa ma le lavā;", "when thou wast faint and weary;"], ["e lei mata'u foi o ia i le Atua.", "and he feared not God."]]},
  {num:19,words:[["Pe a oo foi ina avatu e Ieova lou Atua o le malologa ia te oe i e ita ia te oe uma lava o e vagavagai ia te oe,", "Therefore it shall be,"], ["i le nuu ua foaiina mai e Ieova lou Atua ia te oe e fai mou tofi,", "when the LORD thy God hath given thee rest from all thine enemies round about,"], ["ia fai mou lava,", "in the land which the LORD thy God giveth thee for an inheritance to possess it,"], ["ia e soloiesea le faamanatuga o Amaleka ai le lalolagi;", "that thou shalt blot out the remembrance of Amalek from under heaven;"], ["aua ne'i galo ia te oe.", "thou shalt not forget it."]]},
];
renderVerseSet(deu_ch_25_Verses, 'deu-ch25-verses');

var deu_ch_26_Verses = [
  {num:1,words:[["A ē oo atu foi i le nuu ua foaiina mai e Ieova lou Atua ia te oe e fai mou tofi,", "And it shall be,"], ["a e fai mou lava,", "when thou art come in unto the land which the LORD thy God giveth thee for an inheritance, and possessest it,"], ["ma e nofo ai;", "and dwellest therein;"]]},
  {num:2,words:[["ona e au mai ai lea o faapolopolo o fua uma lava o le laueleele,", "That thou shalt take of the first of all the fruit of the earth,"], ["e te au mai ai ai lou nuu ua foaiina mai e Ieova lou Atua ia te oe,", "which thou shalt bring of thy land that the LORD thy God giveth thee,"], ["ma e tuuina ai i se ato,", "and shalt put it in a basket,"], ["ma e alu atu i le mea e filifilia e Ieova lou Atua e tuu ai lona suafa", "and shalt go unto the place which the LORD thy God shall choose to place his name there."]]},
  {num:3,words:[["ona e alu atu lea i le faitaulaga e i ai i ia ona po,", "And thou shalt go unto the priest that shall be in those days,"], ["ma e fai atu ia te ia,", "and say unto him,"], ["Ou te faailo atu i le aso nei ia Ieova lou Atua,", "I profess this day unto the LORD thy God,"], ["ua ou oo mai i le nuu sa tauto ai Ieova i o tatou tamā na te foaiina ia te i tatou.", "that I am come unto the country which the LORD sware unto our fathers for to give us."]]},
  {num:4,words:[["Ona talia lea e le faitaulaga le ato nai lou lima,", "And the priest shall take the basket out of thine hand,"], ["ma tuu atu ai i luma o le fata faitaulaga o Ieova lou Atua.", "and set it down before the altar of the LORD thy God."]]},
  {num:5,words:[["Ona e tautala atu lea,", "And thou shalt speak and say before the LORD thy God,"], ["ma faapea atu i luma o Ieova lou Atua,", "A Syrian ready to perish was my father,"], ["O lo'u tamā o le Suria ia na fai a oti;", "and he went down into Egypt,"], ["ona alu ifo ai lea o ia i Aikupito,", "and sojourned there with a few,"], ["na āumau ai foi o ia ma ni nai toaitiiti,", "and became there a nation,"], ["ua avea ai foi ma nuu tele,", "great,"], ["e malolosi,", "mighty,"], ["ma le toatele;", "and populous:"]]},
  {num:6,words:[["ona agaleagaina lea o i tatou e tagata Aikupito,", "And the Egyptians evil entreated us,"], ["ma latou faatiga mai ia te i tatou,", "and afflicted us,"], ["ma latou tuu mai ia te i tatou o galuega mamafa;", "and laid upon us hard bondage:"]]},
  {num:7,words:[["ona tatou alalaga atu lea ia Ieova le Atua o tatou tamā,", "And when we cried unto the LORD God of our fathers,"], ["na faafofoga mai foi o Ieova i o tatou leo,", "the LORD heard our voice,"], ["ma ua silasila mai i o tatou tiga,", "and looked on our affliction,"], ["ma a tatou galuega mamafa,", "and our labour,"], ["ma le sauaina o i tatou;", "and our oppression:"]]},
  {num:8,words:[["ona aumaia lea o i tatou e Ieova nai Aikupito i le aao malosi,", "And the LORD brought us forth out of Egypt with a mighty hand,"], ["ma le aao faaloaloa,", "and with an outstretched arm,"], ["atoa ma mea matautia tele,", "and with great terribleness,"], ["ma faailoga,", "and with signs,"], ["ma vavega;", "and with wonders:"]]},
  {num:9,words:[["ua faaoo mai foi e ia ia i tatou i lenei mea,", "And he hath brought us into this place,"], ["ma ua foai mai ia te i tatou lenei nuu,", "and hath given us this land,"], ["o le nuu o tafe ai le sua susu ma le meli;", "even a land that floweth with milk and honey."]]},
  {num:10,words:[["o lenei foi,", "And now,"], ["Ieova e,", "behold,"], ["faauta mai,", "I have brought the firstfruits of the land, which thou,"], ["ua ou aumaia le faapolopolo o fua o le laueleele,", "O LORD,"], ["ua e foaiina mai ia te au.", "hast given me."], ["Ona e tuuina atu ai lea i luma o Ieova lou Atua,", "And thou shalt set it before the LORD thy God,"], ["e te ifo atu foi i luma o Ieova lou Atua;", "and worship before the LORD thy God:"]]},
  {num:11,words:[["ia e olioli foi i mea lelei uma lava ua foaiina mai e Ieova lou Atua ia te oe ma lou aiga,", "And thou shalt rejoice in every good thing which the LORD thy God hath given unto thee,"], ["o oe,", "and unto thine house,"], ["ma lo sa Levī,", "thou, and the Levite,"], ["ma le tagata ese o ia te oe.", "and the stranger that is among you."]]},
  {num:12,words:[["Pe a uma ona avatu e oe o mea uma e sefulu a'i au mea ua maua mai i lona tolu o tausaga,", "When thou hast made an end of tithing all the tithes of thine increase the third year,"], ["o le tausaga lea e avatu ai mea e sefulu a'i,", "which is the year of tithing,"], ["ma ua e avatua i lo sa Levī,", "and hast given it unto the Levite,"], ["ma le tagata ese,", "the stranger, the fatherless,"], ["ma le ua āumatuā,", "and the widow,"], ["ma le fafine ua oti lana tane,", "that they may eat within thy gates,"], ["latou te aai ai ma latou maoona ai i au aai;", "and be filled;"]]},
  {num:13,words:[["ona e fai atu lea i luma o Ieova lou Atua,", "Then thou shalt say before the LORD thy God,"], ["Ua ou aumaia mea paia nai lo'u fale,", "I have brought away the hallowed things out of mine house,"], ["ua ou avatua foi i lo sa Levī,", "and also have given them unto the Levite,"], ["ma le tagata ese,", "and unto the stranger,"], ["ma le ua āumatuā,", "to the fatherless,"], ["ma le fafine ua oti lana tane,", "and to the widow,"], ["e tusa ma au poloaiga uma lava ua e poloai mai ai ia te au;", "according to all thy commandments which thou hast commanded me:"], ["ua ou le tuumavaega i au poloaiga,", "I have not transgressed thy commandments,"], ["ua le galo foi ia te au;", "neither have I forgotten them:"]]},
  {num:14,words:[["ou te lei 'ai ai i lo'u faanoanoa,", "I have not eaten thereof in my mourning,"], ["ou te lei ave sina ia mea i se mea e leaga ou te lei avatu sina ia mea mo e ua oti;", "neither have I taken away ought thereof for any unclean use,"], ["ua ou faalogo i le siufofoga o Ieova lo'u Atua,", "nor given ought thereof for the dead: but I have hearkened to the voice of the LORD my God,"], ["ua ou faia e tusa ma mea uma lava ua e poloai mai ai ia te au.", "and have done according to all that thou hast commanded me."]]},
  {num:15,words:[["Ia e silasila mai mai lou afioaga paia,", "Look down from thy holy habitation,"], ["mai le lagi,", "from heaven,"], ["ma e faamanuia mai i lou nuu o Isaraelu,", "and bless thy people Israel,"], ["ma le laueleele ua e foaiina mai ia te i matou,", "and the land which thou hast given us,"], ["e faapei ona e tauto ai i o matou tamā,", "as thou swarest unto our fathers,"], ["o le nuu o tafe ai le suāsusu ma le meli.", "a land that floweth with milk and honey."]]},
  {num:16,words:[["O le aso nei ua poloai mai ai Ieova lou Atua ia te oe ia e faia nei tulafono ma faamasinoga;", "This day the LORD thy God hath commanded thee to do these statutes and judgments:"], ["ia e tausi foi i ai,", "thou shalt therefore keep and do them with all thine heart,"], ["ma e faia ma lou loto atoa ma lou agaga atoa", "and with all thy soul."]]},
  {num:17,words:[["Ua e matuā fai mai i le aso nei o Ieova o lou Atua ia;", "Thou hast avouched the LORD this day to be thy God,"], ["e te savali foi i ona ala,", "and to walk in his ways,"], ["ma e tausi i ana tulafono,", "and to keep his statutes,"], ["ma ana poloaiga,", "and his commandments,"], ["ma ana faamasinoga,", "and his judgments,"], ["ma e faalogo i lona siufofoga;", "and to hearken unto his voice:"]]},
  {num:18,words:[["ua matuā fetalai mai foi Ieova i le aso nei e fai oe mona nuu,", "And the LORD hath avouched thee this day to be his peculiar people,"], ["o le oloa tāua, e pei ona ia fetalaia mai ia te oe,", "as he hath promised thee,"], ["ina ia e tausi foi i ana poloaiga uma lava,", "and that thou shouldest keep all his commandments;"]]},
  {num:19,words:[["ina ia faasilisiliina foi o oe e ia i nuu uma lava na ia faia,", "And to make thee high above all nations which he hath made,"], ["i le viiga,", "in praise,"], ["ma le ta'ua,", "and in name,"], ["ma le matagofie;", "and in honour;"], ["ina ia avea foi oe ma nuu paia ia Ieova lou Atua,", "and that thou mayest be an holy people unto the LORD thy God,"], ["e pei ona ia fetalaia mai ai.", "as he hath spoken."]]},
];
renderVerseSet(deu_ch_26_Verses, 'deu-ch26-verses');

var deu_ch_27_Verses = [
  {num:1,words:[["Ua fai atu Mose ma toeaina o Isaraelu i le nuu,", "And Moses with the elders of Israel commanded the people,"], ["ua faapea atu,", "saying,"], ["Ia outou tausi i poloaiga uma lava ou te fai atu ai ia te outou i le aso nei.", "Keep all the commandments which I command you this day."]]},
  {num:2,words:[["O le aso foi tou te sopoia atu ai Ioritana,", "And it shall be on the day when ye shall pass over Jordan unto the land which the LORD thy God giveth thee,"], ["i le nuu ua foaiina mai e Ieova lou Atua ia te oe, ia e faatuina ai mo oe ni maa tetele,", "that thou shalt set thee up great stones,"], ["ma ē valia i panisina;", "and plaister them with plaister:"]]},
  {num:3,words:[["ia e tusia foi i ai o upu uma lava o lenei tulafono,", "And thou shalt write upon them all the words of this law,"], ["pe a e sopoia atu,", "when thou art passed over,"], ["ina ia e alu atu ai i le nuu ua foaiina mai e Ieova lou Atua ia te oe,", "that thou mayest go in unto the land which the LORD thy God giveth thee,"], ["o le nuu o tafe ai le suāsusu ma le meli;", "a land that floweth with milk and honey;"], ["e pei ona fetalaia mai ai e Ieova o le Atua o ou tamā ia te oe.", "as the LORD God of thy fathers hath promised thee."]]},
  {num:4,words:[["Pe a outou sopoia atu Ioritana,", "Therefore it shall be when ye be gone over Jordan,"], ["ona outou faatuina lea o na maa,", "that ye shall set up these stones,"], ["ou te fai atu ai ia te outou i le aso nei,", "which I command you this day,"], ["i le mauga o Evalu,", "in mount Ebal,"], ["ia e valia foi i panisina.", "and thou shalt plaister them with plaister."]]},
  {num:5,words:[["Ia e ati ae foi i lea mea le fata faitaulaga mo Ieova lou Atua,", "And there shalt thou build an altar unto the LORD thy God,"], ["o le fata maa;", "an altar of stones:"], ["aua ne'i e talai ai i se uamea.", "thou shalt not lift up any iron tool upon them."]]},
  {num:6,words:[["O maa atoatoa e te ati a'i le fata faitaulaga o Ieova lou Atua;", "Thou shalt build the altar of the LORD thy God of whole stones:"], ["ma e fai ai taulaga mu ia Ieova lou Atua i ona luga;", "and thou shalt offer burnt offerings thereon unto the LORD thy God:"]]},
  {num:7,words:[["ia e fai ai foi taulaga faafetai,", "And thou shalt offer peace offerings,"], ["ma e 'ai ai i lea mea,", "and shalt eat there,"], ["ma olioli i luma o Ieova lou Atua.", "and rejoice before the LORD thy God."]]},
  {num:8,words:[["Ia e tusi foi i maa o upu uma lava o lenei tulafono, ia togitogi lelei lava.", "And thou shalt write upon the stones all the words of this law very plainly."]]},
  {num:9,words:[["Ona tautala atu lea o Mose ma le au faitaulaga,", "And Moses and the priests the Levites spake unto all Israel,"], ["o sa Levī ia Isaraelu uma lava,", "saying,"], ["ua faapea atu, Isaraelu e,", "Take heed,"], ["ia e faasaga mai,", "and hearken,"], ["ma e faalogologo mai;", "O Israel;"], ["o le aso nei ua aveaai oe ma nuu mo Ieova lou Atua.", "this day thou art become the people of the LORD thy God."]]},
  {num:10,words:[["Ia e faalogo foi i le siufofoga o ieova lou Atua,", "Thou shalt therefore obey the voice of the LORD thy God,"], ["ma ia e faia ana poloaiga ma ana tulafono,", "and do his commandments and his statutes,"], ["ou te fai atu ai ia te oe i le aso nei.", "which I command thee this day."]]},
  {num:11,words:[["Ua fai atu foi Mose i le nuu i lea lava aso,", "And Moses charged the people the same day,"], ["ua faapea atu,", "saying,"]]},
  {num:12,words:[["E tutū i latou nei i le mauga o Keresema e faamanuia atu i le nuu,", "These shall stand upon mount Gerizim to bless the people,"], ["pe a outou sopoia atu Ioritana;", "when ye are come over Jordan;"], ["o Simeona,", "Simeon,"], ["ma Levi,", "and Levi, and Judah,"], ["ma Iuta ma Isakara,", "and Issachar,"], ["ma Iosefa,", "and Joseph,"], ["ma Peniamina.", "and Benjamin:"]]},
  {num:13,words:[["E tutū foi i latou nei i le mauga o Evalu e faafano;", "And these shall stand upon mount Ebal to curse;"], ["o Reupena,", "Reuben,"], ["o Kato,", "Gad, and Asher,"], ["ma Asera ma Sepulona,", "and Zebulun,"], ["o Tanu,", "Dan,"], ["ma Nafatali.", "and Naphtali."]]},
  {num:14,words:[["E fai atu foi sa Levī ma le leo tele,", "And the Levites shall speak,"], ["e faapea atu i tagata uma lava o Isaraelu,", "and say unto all the men of Israel with a loud voice,"]]},
  {num:15,words:[["Ia malaia lava le tagata na te faia se tupua ua ta,", "Cursed be the man that maketh any graven or molten image,"], ["po o se tupua uamea,", "an abomination unto the LORD,"], ["o le mea e inosia e Ieova, ua faia i lima o le tufuga,", "the work of the hands of the craftsman,"], ["ma tuu ai i se mea lilo.", "and putteth it in a secret place."], ["Ona tali mai ai lea o le nuu uma lava, e faapea mai,", "And all the people shall answer and say,"], ["Amene.", "Amen."]]},
  {num:16,words:[["Ia malaia le na te faaleaogaina lona tamā po o lona tinā. Ona tali mai ai lea o le nuu uma lava,", "Cursed be he that setteth light by his father or his mother. And all the people shall say,"], ["Amene.", "Amen."]]},
  {num:17,words:[["Ia malaia le na te sii le tuaoi o lē la te tuaoi. Ona tali mai ai lea o le nuu uma lava,", "Cursed be he that removeth his neighbour's landmark. And all the people shall say,"], ["Amene.", "Amen."]]},
  {num:18,words:[["Ia malaia le na te faaseseina le tauaso i le ala. Ona tali mai ai lea o le nuu uma,", "Cursed be he that maketh the blind to wander out of the way. And all the people shall say,"], ["Amene.", "Amen."]]},
  {num:19,words:[["Ia malaia le na te faapiopioina le faamasinoga i le tagata ese,", "Cursed be he that perverteth the judgment of the stranger,"], ["ma le ua āumatuā,", "fatherless,"], ["ma le fafine ua oti lana tane. Ona tali mai ai lea o le nuu uma,", "and widow. And all the people shall say,"], ["Amene.", "Amen."]]},
  {num:20,words:[["Ia malaia le la te momoe ma le avā a lona tamā;", "Cursed be he that lieth with his father's wife;"], ["auā e susue e ia le ie o lona tamā. Ona tali mai ai lea o le nuu uma,", "because he uncovereth his father's skirt. And all the people shall say,"], ["Amene.", "Amen."]]},
  {num:21,words:[["Ia malaia lē la te momoe ma se manu. Ona tali mai ai lea o le nuu uma lava,", "Cursed be he that lieth with any manner of beast. And all the people shall say,"], ["Amene.", "Amen."]]},
  {num:22,words:[["Ia malaia lē la te momoe ma lona tuafafine,", "Cursed be he that lieth with his sister,"], ["o le afafine o lona tamā,", "the daughter of his father,"], ["po o le tama teine a lona tinā. Ona tali mai ai lea o le nuu umā lava,", "or the daughter of his mother. And all the people shall say,"], ["Amene.", "Amen."]]},
  {num:23,words:[["Ia malaia lē la te momoe ma le tinā o lana avā. Ona tali mai ai lea o le nuu uma,", "Cursed be he that lieth with his mother in law. And all the people shall say,"], ["Amene.", "Amen."]]},
  {num:24,words:[["Ia malaia le na te fasi faaliolilo lē la te tuaoi. Ona tali mai ai lea o le nuu uma,", "Cursed be he that smiteth his neighbour secretly. And all the people shall say,"], ["Amene.", "Amen."]]},
  {num:25,words:[["Ia malaia le na te talia se taui e fasioti ai se tagata ua le sala. Ona tali mai ai lea o le nuu uma,", "Cursed be he that taketh reward to slay an innocent person. And all the people shall say,"], ["Amene.", "Amen."]]},
  {num:26,words:[["Ia malaia le na te le faamauina upu o lenei tulafono e faia. Ona tali mai ai lea o le nuu uma,", "Cursed be he that confirmeth not all the words of this law to do them. And all the people shall say,"], ["Amene.", "Amen."]]},
];
renderVerseSet(deu_ch_27_Verses, 'deu-ch27-verses');

var deu_ch_28_Verses = [
  {num:1,words:[["Afai foi e te matuā faalogo i le siufofoga o Ieova lou Atua,", "And it shall come to pass,"], ["e anaana e fai ana poloaiga uma lava ou te fai atu ai ia te oe i le aso nei,", "if thou shalt hearken diligently unto the voice of the LORD thy God,"], ["ona faasilisiliina lea o oe e Ieova lou Atua,", "to observe and to do all his commandments which I command thee this day,"], ["i nuu uma lava o le lalolagi;", "that the LORD thy God will set thee on high above all nations of the earth:"]]},
  {num:2,words:[["e maua foi e oe o nei mea uma e manuia ai;", "And all these blessings shall come on thee,"], ["e oo lava ia ia te oe,", "and overtake thee,"], ["pe afai e te faalogo i le siufofoga o Ieova lou Atua.", "if thou shalt hearken unto the voice of the LORD thy God."]]},
  {num:3,words:[["E manuia oe i le aai,", "Blessed shalt thou be in the city,"], ["e manuia oe i le fanua.", "and blessed shalt thou be in the field."]]},
  {num:4,words:[["E manuia oe i lau fanau,", "Blessed shall be the fruit of thy body,"], ["ma le fua o lou laueleele,", "and the fruit of thy ground,"], ["ma fanau a au manu vaefa,", "and the fruit of thy cattle,"], ["o tama a au povi,", "the increase of thy kine,"], ["ma ou lafu mamoe.", "and the flocks of thy sheep."]]},
  {num:5,words:[["E manuia lau ato, atoa ma lau mea e palu ai falaoa.", "Blessed shall be thy basket and thy store."]]},
  {num:6,words:[["E manuia oe pe a e sau,", "Blessed shalt thou be when thou comest in,"], ["e manuia foi oe pe a e alu atu.", "and blessed shalt thou be when thou goest out."]]},
  {num:7,words:[["E tuuina mai e Ieova o e ita ia te oe o e laga mai ia te oe ia fasia i ou luma;", "The LORD shall cause thine enemies that rise up against thee to be smitten before thy face:"], ["o le ala e tasi e o mai ai i latou ia te oe,", "they shall come out against thee one way,"], ["a o ala e fitu e sosola atu ai i latou i ou luma.", "and flee before thee seven ways."]]},
  {num:8,words:[["E pule Ieova ia manuia oe i ou fale saito,", "The LORD shall command the blessing upon thee in thy storehouses,"], ["ma mea uma lava e tago i ai ou lima;", "and in all that thou settest thine hand unto;"], ["na te faamanuia foi ia te oe i le nuu ua foaiina mai e Ieova lou Atua ia te oe.", "and he shall bless thee in the land which the LORD thy God giveth thee."]]},
  {num:9,words:[["E fai foi oe e Ieova ma nuu paia mo ia,", "The LORD shall establish thee an holy people unto himself,"], ["e pei ona tauto mai o ia ia te oe,", "as he hath sworn unto thee,"], ["pe afai e te tausiusi i poloaiga a Ieova lou Atua,", "if thou shalt keep the commandments of the LORD thy God,"], ["ma e savali i ona ala.", "and walk in his ways."]]},
  {num:10,words:[["Ona iloa ai lea e nuu uma o le lalolagi ua faaigoaina oe i le suafa o Ieova;", "And all people of the earth shall see that thou art called by the name of the LORD;"], ["ona matatau ai lea o i latou ia te oe.", "and they shall be afraid of thee."]]},
  {num:11,words:[["E faateleina e Ieova o mea lelei ia te oe,", "And the LORD shall make thee plenteous in goods,"], ["o lau fanau,", "in the fruit of thy body,"], ["ma fanau a au manu vaefa,", "and in the fruit of thy cattle,"], ["ma le fua o lou laueleele,", "and in the fruit of thy ground,"], ["i le laueleele na tauto ai Ieova i ou tamā na te foaiina mai ia te oe.", "in the land which the LORD sware unto thy fathers to give thee."]]},
  {num:12,words:[["E tatala mai e Ieova lana tuugāoloa lelei mā oe,", "The LORD shall open unto thee his good treasure,"], ["o le lagi lea,", "the heaven to give the rain unto thy land in his season,"], ["e foaiina mai ai o le ua i lou nuu i ona po e tatau ai, a faamanuia ai foi mea uma e te faia i ou lima;", "and to bless all the work of thine hand:"], ["e te avatu mea i nuu e tele,", "and thou shalt lend unto many nations,"], ["a ē te le nonō atu.", "and thou shalt not borrow."]]},
  {num:13,words:[["E fai foi oe e Ieova ma ulu,", "And the LORD shall make thee the head,"], ["a e le fai ma iu;", "and not the tail;"], ["e te aupitoaluga lava,", "and thou shalt be above only,"], ["a e te le laulalo; pe afai e te faalogo i poloaiga a Ieova lou Atua,", "and thou shalt not be beneath;"], ["ou te fai atu ai ia te oe i le aso nei,", "if that thou hearken unto the commandments of the LORD thy God,"], ["e tausi i ai,", "which I command thee this day,"], ["ma e faia;", "to observe and to do them:"]]},
  {num:14,words:[["aua foi e te alu ese i upu uma ou te fai atu ai ia te outou i le aso nei,", "And thou shalt not go aside from any of the words which I command thee this day,"], ["i le itu taumatau,", "to the right hand,"], ["po o le itu taugavale, e mulimuli atu ai i atua ese,", "or to the left,"], ["ma auauna i ai.", "to go after other gods to serve them."]]},
  {num:15,words:[["A e afai e te le faalogo i le siufofoga o Ieova lou Atua,", "But it shall come to pass,"], ["e anaana e foi ana poloaiga uma ma ana tulafono ou te fai atu ai ia te oe i le aso nei;", "if thou wilt not hearken unto the voice of the LORD thy God,"], ["ona maua mai ai lea o oe i nei malaia uma,", "to observe to do all his commandments and his statutes which I command thee this day; that all these curses shall come upon thee,"], ["e oo lava ia ia te oe.", "and overtake thee:"]]},
  {num:16,words:[["E malaia oe i le aai,", "Cursed shalt thou be in the city,"], ["e malaia foi oe i le fanua.", "and cursed shalt thou be in the field."]]},
  {num:17,words:[["E malaia lau ato, atoa ma lau mea e palu ai falaoa.", "Cursed shall be thy basket and thy store."]]},
  {num:18,words:[["E malaia lau fanau,", "Cursed shall be the fruit of thy body,"], ["ma le fua o lou laueleele,", "and the fruit of thy land, the increase of thy kine,"], ["o tama a au povi ma ou lafu mamoe.", "and the flocks of thy sheep."]]},
  {num:19,words:[["E malaia oe pe a e sau,", "Cursed shalt thou be when thou comest in,"], ["e malaia foi oe pe a e alu atu.", "and cursed shalt thou be when thou goest out."]]},
  {num:20,words:[["E faaoo e Ieova ia te oe le malaia,", "The LORD shall send upon thee cursing,"], ["ma le atuatuvale,", "vexation,"], ["ma le aoaiga,", "and rebuke,"], ["i mea uma lava e tago i ai ou lima e faia,", "in all that thou settest thine hand unto for to do,"], ["seia faaumatia oe,", "until thou be destroyed,"], ["ma e vave fano lava;", "and until thou perish quickly;"], ["ona o le leaga o lau amio,", "because of the wickedness of thy doings,"], ["na e lafoai mai ai ia te au.", "whereby thou hast forsaken me."]]},
  {num:21,words:[["E faapipii atu e Ieova le faama'i ia te oe,", "The LORD shall make the pestilence cleave unto thee, until he have consumed thee from off the land,"], ["seia faaumatia oe e ia ai le laueleele e te alu i ai e fai mou.", "whither thou goest to possess it."]]},
  {num:22,words:[["E taia oe e Ieova i le ma'i faaiiva,", "The LORD shall smite thee with a consumption,"], ["ma le ma'i vevela,", "and with a fever,"], ["ma le ma'i fulafula,", "and with an inflammation,"], ["ma le vevela tele lava;", "and with an extreme burning,"], ["ma le naumati,", "and with the sword,"], ["ma le mamae,", "and with blasting,"], ["ma le polopologa;", "and with mildew;"], ["e tuliloa ia mea ia te oe seia faaumatia ai oe.", "and they shall pursue thee until thou perish."]]},
  {num:23,words:[["E avea foi lou lagi o i ou luga ma 'apa memea,", "And thy heaven that is over thy head shall be brass,"], ["ma le lalologi o i ou lalo e fai lea ma uamea.", "and the earth that is under thee shall be iron."]]},
  {num:24,words:[["E faia e Ieova le ua i lou nuu ma efuefu ninii ma efuefu;", "The LORD shall make the rain of thy land powder and dust:"], ["e totō ifo ia mai le lagi i ou luga,", "from heaven shall it come down upon thee,"], ["seia faaumatia ai oe.", "until thou be destroyed."]]},
  {num:25,words:[["E tuuina atu oe e Ieova ia fasia i luma o e ita ia te oe;", "The LORD shall cause thee to be smitten before thine enemies:"], ["e te alu atu ia te i latou i le ala e tasi,", "thou shalt go out one way against them,"], ["a e te sola i ala e fitu i o latou luma;", "and flee seven ways before them:"], ["e tuuina atu foi oe ia faasaunoa i ai malo uma o le lalolagi.", "and shalt be removed into all the kingdoms of the earth."]]},
  {num:26,words:[["E fai foi lou tino oti ma mea e 'ai mā manu felelei uma,", "And thy carcase shall be meat unto all fowls of the air,"], ["ma manu vaefa e tataa,", "and unto the beasts of the earth,"], ["a leai se na te tulia.", "and no man shall fray them away."]]},
  {num:27,words:[["E taia oe e Ieova i le ma'i fulafula o Aikupito,", "The LORD will smite thee with the botch of Egypt,"], ["ma le silailalo,", "and with the emerods,"], ["ma le ma'i pa'upa'ua,", "and with the scab,"], ["ma le ma'i mageso,", "and with the itch,"], ["e le mafai ona faamaloloina ai oe.", "whereof thou canst not be healed."]]},
  {num:28,words:[["E taia oe e Ieova i le faavalemalosi,", "The LORD shall smite thee with madness,"], ["ma le tauaso,", "and blindness,"], ["ma le loto atuatuvale;", "and astonishment of heart:"]]},
  {num:29,words:[["e te tautago i le tutonu o le la,", "And thou shalt grope at noonday,"], ["e pei ona tautago o le tauaso i le pouliuli;", "as the blind gropeth in darkness,"], ["e te le manuia foi i ou ala, na ona faasauaina oe,", "and thou shalt not prosper in thy ways:"], ["ma faoa au mea i aso uma lava,", "and thou shalt be only oppressed and spoiled evermore,"], ["a e leai se laveai ia te oe .", "and no man shall save thee."]]},
  {num:30,words:[["Lua te fai le feagaiga ma le fafine e fai mau avā,", "Thou shalt betroth a wife,"], ["a e toso o ia e le tasi tane;", "and another man shall lie with her:"], ["e te faia se fale,", "thou shalt build an house,"], ["a e te le mau ai;", "and thou shalt not dwell therein:"], ["e te faia se tovine,", "thou shalt plant a vineyard,"], ["a e te le faatatagaina.", "and shalt not gather the grapes thereof."]]},
  {num:31,words:[["E fasia lau povi i ou luma,", "Thine ox shall be slain before thine eyes,"], ["a e te le 'ai ai;", "and thou shalt not eat thereof:"], ["e faoa lau asini i ou luma,", "thine ass shall be violently taken away from before thy face,"], ["a e le toe foi mai ia te oe;", "and shall not be restored to thee:"], ["e avatu au mamoe i e ita mai ia te oe,", "thy sheep shall be given unto thine enemies,"], ["a e le ia te oe se na te laveaiina.", "and thou shalt have none to rescue them."]]},
  {num:32,words:[["E foaiina atu ou atalii ma ou afafine i le nuu ese,", "Thy sons and thy daughters shall be given unto another people,"], ["e vaavaai foi ou mata,", "and thine eyes shall look,"], ["ma fole ai, ona o i latou i le aso atoa;", "and fail with longing for them all the day long:"], ["e leai foi se malosi ia te oe e laveai .", "and there shall be no might in thine hand."]]},
  {num:33,words:[["E 'aina le fua o lou laueleele,", "The fruit of thy land,"], ["ma au galuega uma lava,", "and all thy labours,"], ["e le nuu e te le iloa; na ona faasauaina lava oe,", "shall a nation which thou knowest not eat up;"], ["ma faataugaina i aso uma lava;", "and thou shalt be only oppressed and crushed alway:"]]},
  {num:34,words:[["e te faavalemalosi foi ona o mea e vaai i ai ou mata.", "So that thou shalt be mad for the sight of thine eyes which thou shalt see."]]},
  {num:35,words:[["E taia oe e Ieova i le papala leaga,", "The LORD shall smite thee in the knees,"], ["i ou tulivae ma ou vae,", "and in the legs,"], ["e le mafai ona faamamafuina;", "with a sore botch that cannot be healed,"], ["e fua mai i ou alofivae e oo lava i lou tumuai.", "from the sole of thy foot unto the top of thy head."]]},
  {num:36,words:[["E ta'ita'iina e Ieova o oe,", "The LORD shall bring thee,"], ["ma lou tupu ua e tofia mo oe,", "and thy king which thou shalt set over thee,"], ["i le nuu ua le iloa e oe po o ou tamā;", "unto a nation which neither thou nor thy fathers have known;"], ["e te auauna foi i lea mea i atua ese,", "and there shalt thou serve other gods,"], ["o laau ma maa.", "wood and stone."]]},
  {num:37,words:[["E avea foi oe ma mea e ofo ai,", "And thou shalt become an astonishment,"], ["ma upu faatusa,", "a proverb,"], ["ma tauemuga,", "and a byword,"], ["i nuu uma lava e ta'ita'iina i ai oe e Ieova.", "among all nations whither the LORD shall lead thee."]]},
  {num:38,words:[["E te ave ni fua e tele e totō i le fanua,", "Thou shalt carry much seed out into the field,"], ["a e itiiti ni mea e te faapotopoto mai ai;", "and shalt gather but little in;"], ["auā e 'aina e le sē akerise.", "for the locust shall consume it."]]},
  {num:39,words:[["E te faia ni tovine,", "Thou shalt plant vineyards,"], ["ma e galue i ai ,", "and dress them,"], ["a e te le inu i le uaina,", "but shalt neither drink of the wine,"], ["pe tau mai ni fua ;", "nor gather the grapes;"], ["auā e 'aina e anufe.", "for the worms shall eat them."]]},
  {num:40,words:[["E ia te oe olive i ou fanua uma,", "Thou shalt have olive trees throughout all thy coasts,"], ["a e le uu oe i le uu;", "but thou shalt not anoint thyself with the oil;"], ["auā e malili fua o lou olive.", "for thine olive shall cast his fruit."]]},
  {num:41,words:[["E fanau ia te oe atalii ma afafine,", "Thou shalt beget sons and daughters,"], ["a e le fai i latou mau;", "but thou shalt not enjoy them;"], ["auā e avea i latou faatagataotaua.", "for they shall go into captivity."]]},
  {num:42,words:[["O au laau uma ma fua o lou laueleele e faaumatia ia e le sē selasala.", "All thy trees and fruit of thy land shall the locust consume."]]},
  {num:43,words:[["O le tagata ese e ia te oe e matuā faasilisili lava o ia ia te oe; a o oe,", "The stranger that is within thee shall get up above thee very high;"], ["e te matuā maulalo lava ia te ia .", "and thou shalt come down very low."]]},
  {num:44,words:[["E te no mea ia te ia,", "He shall lend to thee,"], ["a e le no mea o ia ia te oe;", "and thou shalt not lend to him:"], ["e avea o ia ma ulu,", "he shall be the head,"], ["a e avea oe ma i'u.", "and thou shalt be the tail."]]},
  {num:45,words:[["E maua mai oe i nei malaia uma,", "Moreover all these curses shall come upon thee,"], ["e tuliloa ia ia te oe,", "and shall pursue thee,"], ["ma oo lava ia te oe,", "and overtake thee,"], ["seia faaumatia oe;", "till thou be destroyed;"], ["auā ua e le faalogo i le siufofoga o Ieova lou Atua,", "because thou hearkenedst not unto the voice of the LORD thy God,"], ["e tausi i ana poloaiga ma ana tulafono na ia poloai mai ai ia te oe;", "to keep his commandments and his statutes which he commanded thee:"]]},
  {num:46,words:[["E ia te oe ma au fanau ia mea,", "And they shall be upon thee for a sign and for a wonder,"], ["e fai ma faailoga ma vavega e faavavau.", "and upon thy seed for ever."]]},
  {num:47,words:[["Auā ua e le auauna ia Ieova lou Atua ma le olioli,", "Because thou servedst not the LORD thy God with joyfulness,"], ["ma le fiafia o le loto,", "and with gladness of heart,"], ["ona o le tele o mea uma;", "for the abundance of all things;"]]},
  {num:48,words:[["o le mea lea e te auauna ai ma le fia ai,", "Therefore shalt thou serve thine enemies which the LORD shall send against thee,"], ["ma le fia inu,", "in hunger,"], ["ma le le lavalavā,", "and in thirst,"], ["ma le mativa i mea uma lava,", "and in nakedness,"], ["i e ita ia te oe e aauina mai e Ieova ia te oe;", "and in want of all things:"], ["na te faaee foi le amo uamea i lou ua,", "and he shall put a yoke of iron upon thy neck,"], ["seia faaumatia oe e ia.", "until he have destroyed thee."]]},
  {num:49,words:[["E auina mai e Ieova ia te oe le nuu mai le mea mamao,", "The LORD shall bring a nation against thee from far,"], ["mai le tuluiga o le lalolagi,", "from the end of the earth,"], ["e pei ona lele mai o le aeto;", "as swift as the eagle flieth;"], ["o le nuu e te le lagona la latou gagana;", "a nation whose tongue thou shalt not understand;"]]},
  {num:50,words:[["o le nuu mata sauā,", "A nation of fierce countenance,"], ["e le faailogaina e i latou o toeaina,", "which shall not regard the person of the old,"], ["e le alofa foi i tama;", "nor shew favour to the young:"]]},
  {num:51,words:[["e 'aina foi e i latou o fanau a au manu vaefa,", "And he shall eat the fruit of thy cattle,"], ["ma fua o lou laueleele,", "and the fruit of thy land,"], ["seia faaumatia oe;", "until thou be destroyed:"], ["latou te le faatoeina ma oe ni saito,", "which also shall not leave thee either corn,"], ["po o uaina,", "wine,"], ["po o suāuu,", "or oil,"], ["o se tama a au povi,", "or the increase of thy kine,"], ["po o ou lafu mamoe,", "or flocks of thy sheep,"], ["seia faaumatia oe e ia.", "until he have destroyed thee."]]},
  {num:52,words:[["Latou te siosio ia te oe i le taua i au aai uma,", "And he shall besiege thee in all thy gates,"], ["seia soloia ou pa maualuluga ma le faigata,", "until thy high and fenced walls come down,"], ["sa e faatuatua i ai,", "wherein thou trustedst, throughout all thy land:"], ["i lou nuu uma;", "and he shall besiege thee in all thy gates throughout all thy land,"], ["latou te siosio ia te oe i au aai uma i lou nuu uma ua foaiina mai e Ieova lou Atua ia te oe.", "which the LORD thy God hath given thee."]]},
  {num:53,words:[["E 'aina foi e oe au fanau ua foaiina mai e Ieova lou Atua ia te oe,", "And thou shalt eat the fruit of thine own body,"], ["o tino o ou atalii ma ou afafine,", "the flesh of thy sons and of thy daughters,"], ["ina ua siosioina oe,", "which the LORD thy God hath given thee, in the siege,"], ["ma tigaina,", "and in the straitness,"], ["e faatigateleina ai oe e i latou ua ita ia te oe.", "wherewith thine enemies shall distress thee:"]]},
  {num:54,words:[["O le tagata o ia te oe e tino văivai,", "So that the man that is tender among you,"], ["ma ua matuā faapelepeleina,", "and very delicate,"], ["e le alofa o ia i lona uso,", "his eye shall be evil toward his brother,"], ["ma lana avā pele,", "and toward the wife of his bosom,"], ["ma ana fanau ua totoe e ua faatotoeina;", "and toward the remnant of his children which he shall leave:"]]},
  {num:55,words:[["e le avatua lava e ia i so latou sina fāsi tino o ona atalii na te 'aina;", "So that he will not give to any of them of the flesh of his children whom he shall eat:"], ["auā ua leai lava sina mea ua toe ia te ia ina ua siosioina,", "because he hath nothing left him in the siege,"], ["ma tigaina,", "and in the straitness,"], ["e faatigateleina ai oe e i latou ua ita ia te oe i au aai uma.", "wherewith thine enemies shall distress thee in all thy gates."]]},
  {num:56,words:[["O le fafine tino văivai o ia te oe,", "The tender and delicate woman among you,"], ["ma le ua faapelepeleina,", "which would not adventure to set the sole of her foot upon the ground for delicateness and tenderness,"], ["na te le faata'ita'i ona tuu ifo o lona alofivae e tu i le laueleele ona o lona faapelepeleina ma lona tino văivai, e le alofa o ia i lana tane pele,", "her eye shall be evil toward the husband of her bosom,"], ["ma lana tama tane,", "and toward her son,"], ["ma lana tama teine,", "and toward her daughter,"]]},
  {num:57,words:[["ma lona fanua e paū i ona vae,", "And toward her young one that cometh out from between her feet,"], ["ma ana fanau e fanau mai ai e ia;", "and toward her children which she shall bear:"], ["auā e 'aina e ia faalilolilo ona o le oge o mea uma lava ina ua siosioina, ma tigaina,", "for she shall eat them for want of all things secretly in the siege and straitness,"], ["e faatigaina ai oe e i latou o e ita ia te oe i au aai.", "wherewith thine enemy shall distress thee in thy gates."]]},
  {num:58,words:[["Pe afai e te le anaana e fai i upu uma lava o lenei tulafono ua tusia i lenei tusi,", "If thou wilt not observe to do all the words of this law that are written in this book,"], ["ina ia e mata'u i lenei suafa mamalu ma le matautia,", "that thou mayest fear this glorious and fearful name,"], ["O Ieova Lou Atua ;", "THE LORD THY GOD;"]]},
  {num:59,words:[["ona faaoo lea e Ieova o mala ia te oe,", "Then the LORD will make thy plagues wonderful,"], ["ma mala i au fanau,", "and the plagues of thy seed,"], ["e ofo ai, o mala tetele lava,", "even great plagues,"], ["ma le tumau,", "and of long continuance,"], ["ma ma'i leaga,", "and sore sicknesses,"], ["ma le tumau.", "and of long continuance."]]},
  {num:60,words:[["Na te faaoo foi ia te oe o ma'i uma o Aikupito,", "Moreover he will bring upon thee all the diseases of Egypt,"], ["sa e fefe ai;", "which thou wast afraid of;"], ["e pipii lava ia ia te oe.", "and they shall cleave unto thee."]]},
  {num:61,words:[["O ma'i foi uma lava,", "Also every sickness,"], ["ma mala uma lava,", "and every plague,"], ["e lei tusia i le lautusi o lenei tulafono,", "which is not written in the book of this law,"], ["e faaoo ia e Ieova ia te oe,", "them will the LORD bring upon thee,"], ["seia faaumatia oe.", "until thou be destroyed."]]},
  {num:62,words:[["E toaitiiti foi ni o outou e totoe,", "And ye shall be left few in number,"], ["o outou sa toatele e pei o fetu o le lagi;", "whereas ye were as the stars of heaven for multitude;"], ["auā ua e le faalogo i le siufofoga o Ieova lou Atua.", "because thou wouldest not obey the voice of the LORD thy God."]]},
  {num:63,words:[["E pei ona fiafia foi Ieova ia te outou e agalelei ia te outou,", "And it shall come to pass,"], ["ma faatoatele ia te outou;", "that as the LORD rejoiced over you to do you good,"], ["e faapea foi ona fiafia ai o Ieova ia fanoia outou ia te ia,", "and to multiply you; so the LORD will rejoice over you to destroy you,"], ["ma ia faaumatia outou;", "and to bring you to nought;"], ["e tafia foi outou ai le laueleele e te alu i ai e fai mou.", "and ye shall be plucked from off the land whither thou goest to possess it."]]},
  {num:64,words:[["E faataapeape foi Ieova ia te oe i nuu uma,", "And the LORD shall scatter thee among all people,"], ["e afua mai i le tasi tuluiga o le lalolagi e oo atu i le tasi tuluiga o le lalolagi;", "from the one end of the earth even unto the other;"], ["e te auauna foi i ai i atua ese,", "and there thou shalt serve other gods,"], ["o laau ma maa,", "which neither thou nor thy fathers have known,"], ["ua le iloa e oe po o ou tamā.", "even wood and stone."]]},
  {num:65,words:[["O le a e le iloa sina mapu i ia nuu,", "And among these nations shalt thou find no ease,"], ["e leai foi se mea e tumau ai ou alofivae;", "neither shall the sole of thy foot have rest:"], ["e faaoo foi e Ieova ia te oe i ia nuu o le loto gatete,", "but the LORD shall give thee there a trembling heart,"], ["ma mata ua fole,", "and failing of eyes,"], ["ma le loto vaivai;", "and sorrow of mind:"]]},
  {num:66,words:[["e faaletonu foi lou ola;", "And thy life shall hang in doubt before thee;"], ["e te fefe foi i le po atoa ma le ao,", "and thou shalt fear day and night,"], ["e te le sanoola i lou ola.", "and shalt have none assurance of thy life:"]]},
  {num:67,words:[["E te faapea ane i le taeao, E,", "In the morning thou shalt say,"], ["fia oo i le afiafi! E te faapea ane foi i le afiafi,", "Would God it were even! and at even thou shalt say,"], ["E,", "Would God it were morning! for the fear of thine heart wherewith thou shalt fear,"], ["fia oo i le taeao! auā o le fefe o lou loto e te fefe ai, auā foi o mea e vaai i ai ou mata.", "and for the sight of thine eyes which thou shalt see."]]},
  {num:68,words:[["E faafoi atu foi Ieova ia te outou i Aikupito i vaa,", "And the LORD shall bring thee into Egypt again with ships,"], ["(o le ala na ou fai atu ai ia te oe,", "by the way whereof I spake unto thee,"], ["E te le toe vaai lava i ai,", "Thou shalt see it no more again:"], [") e faatauina atu ai foi outou i e ua ita ia te outou e fai ma auauna tane ma auauna fafine,", "and there ye shall be sold unto your enemies for bondmen and bondwomen,"], ["seia leai se na te faatauina outou .", "and no man shall buy you."]]},
];
renderVerseSet(deu_ch_28_Verses, 'deu-ch28-verses');

var deu_ch_29_Verses = [
  {num:1,words:[["O upu nei o le feagaiga sa fetalai mai ai Ieova ia Mose ia faia ma le fanauga a Isaraelu i le nuu o Moapi,", "These are the words of the covenant, which the LORD commanded Moses to make with the children of Israel in the land of Moab,"], ["a e ese le feagaiga sa osia e ia ma i latou i Horepa.", "beside the covenant which he made with them in Horeb."]]},
  {num:2,words:[["Ua valaau atu foi Mose ia Isaraelu uma,", "And Moses called unto all Israel,"], ["ua faapea atu ia te i latou,", "and said unto them,"], ["Ua outou vaaia mea uma lava na faia e Ieova i o outou luma i le nuu o Aikupito ia Farao,", "Ye have seen all that the LORD did before your eyes in the land of Egypt unto Pharaoh,"], ["ma ana auauna uma,", "and unto all his servants,"], ["atoa ma lona nuu uma;", "and unto all his land;"]]},
  {num:3,words:[["o tofotofoga tetele na vaai i ai ou mata;", "The great temptations which thine eyes have seen, the signs,"], ["o ia faailoga ma vavega tetele;", "and those great miracles:"]]},
  {num:4,words:[["a ua le foaiina mai e Ieova ia te outou le loto e lagona,", "Yet the LORD hath not given you an heart to perceive,"], ["ma mata e vaai,", "and eyes to see,"], ["ma taliga e faalogo,", "and ears to hear,"], ["ua oo mai i le aso nei.", "unto this day."]]},
  {num:5,words:[["Na ou ta'ita'iina foi outou i le vao i tausaga e fagafulu;", "And I have led you forty years in the wilderness:"], ["ua le pala o outou ofu na outou ofu ai,", "your clothes are not waxen old upon you,"], ["ua le pala foi o outou seevae i o outou vae.", "and thy shoe is not waxen old upon thy foot."]]},
  {num:6,words:[["E lei aai outou i le areto,", "Ye have not eaten bread,"], ["e lei inu foi outou i le uaina po o le 'ava; ina ia outou iloa,", "neither have ye drunk wine or strong drink:"], ["o a'u o Ieova lo outou Atua.", "that ye might know that I am the LORD your God."]]},
  {num:7,words:[["Na outou o mai foi i lenei mea,", "And when ye came unto this place,"], ["ona o mai lea o Sekono le tupu o Hesepona,", "Sihon the king of Heshbon,"], ["ma Oko le tupu o Vasana,", "and Og the king of Bashan,"], ["e faafetaiai ia te i tatou e tau ai le taua,", "came out against us unto battle,"], ["ona tatou fafasi lea ia te i laua;", "and we smote them:"]]},
  {num:8,words:[["na tatou faoa foi o laua laueleele ma foai atu ai e fai ma tofi o sa Reupenā,", "And we took their land,"], ["ma sa Katō,", "and gave it for an inheritance unto the Reubenites, and to the Gadites,"], ["ma le tasi vaega o le itu aiga o sa Manasē.", "and to the half tribe of Manasseh."]]},
  {num:9,words:[["O lenei,", "Keep therefore the words of this covenant,"], ["ia outou tausi i upu o lenei feagaiga, ma ia outou faia,", "and do them,"], ["ina ia manuia ai outou i mea uma lava tou te faia.", "that ye may prosper in all that ye do."]]},
  {num:10,words:[["Ua outou tutū uma lava i le aso nei i luma o Ieova lo outou Atua;", "Ye stand this day all of you before the LORD your God;"], ["o alii sili o outou,", "your captains of your tribes,"], ["o outou itu aiga, o outou toeaina foi,", "your elders,"], ["ma o outou faipule,", "and your officers,"], ["o tagata uma o Isaraelu;", "with all the men of Israel,"]]},
  {num:11,words:[["o outou tama iti,", "Your little ones,"], ["ma a outou avā,", "your wives,"], ["ma le tagata ese o ia te oe i lau toagālauapi,", "and thy stranger that is in thy camp,"], ["o le na te fai au fafie atoa ma le na te utufia mai ou vai;", "from the hewer of thy wood unto the drawer of thy water:"]]},
  {num:12,words:[["ina ia e faia le feagaiga ma Ieova lou Atua,", "That thou shouldest enter into covenant with the LORD thy God,"], ["ma lana tautoga,", "and into his oath,"], ["o loo fai e Ieova lou Atua ma oe i le aso nei;", "which the LORD thy God maketh with thee this day:"]]},
  {num:13,words:[["ina ia faatumauina oe e ia i le aso nei e fai ma nuu mona,", "That he may establish thee to day for a people unto himself,"], ["ia fai foi o ia mou Atua;", "and that he may be unto thee a God,"], ["e pei ona fetalai mai ai o ia ia te oe,", "as he hath said unto thee,"], ["e pei ona tauto ai foi o ia i ou tamā,", "and as he hath sworn unto thy fathers,"], ["o Aperaamo,", "to Abraham,"], ["ma Isaako,", "to Isaac,"], ["ma Iakopo.", "and to Jacob."]]},
  {num:14,words:[["E le gata foi ia te outou lenei feagaiga ma lenei tautoga ou te faia;", "Neither with you only do I make this covenant and this oath;"]]},
  {num:15,words:[["a e atoa ma e o tutū iinei faatasi ma i tatou i le aso nei i luma o Ieova lo tatou Atua,", "But with him that standeth here with us this day before the LORD our God,"], ["atoa ma i latou e le o faatasi iinei ma i tatou i le aso nei;", "and also with him that is not here with us this day:"]]},
  {num:16,words:[["(auā ua outou iloa lo tatou nonofo i le nuu o Aikupito,", "(For ye know how we have dwelt in the land of Egypt;"], ["ma lo tatou ui mai i nuu na outou ui mai ai;", "and how we came through the nations which ye passed by;"]]},
  {num:17,words:[["na outou iloa foi a latou mea e inosia,", "And ye have seen their abominations,"], ["ma a latou tupua,", "and their idols,"], ["o laau ma maa,", "wood and stone,"], ["o ario ma auro,", "silver and gold,"], ["sa ia te i latou;", "which were among them:"], [")", ")"]]},
  {num:18,words:[["ne'i i ai ia te outou se tane,", "Lest there should be among you man,"], ["po o se faine,", "or woman,"], ["po o se aiga,", "or family,"], ["po o se itu aiga, e liliu ese lona loto i le aso nei,", "or tribe,"], ["ia Ieova lo tatou Atua,", "whose heart turneth away this day from the LORD our God,"], ["ma alu ai e auauna i atua ese o na nuu;", "to go and serve the gods of these nations;"], ["ne'i i ai ia te outou se aa e tupu mai ai mea oona ma laena;", "lest there should be among you a root that beareth gall and wormwood;"]]},
  {num:19,words:[["a oo foi ina faalogo o ia i upu o lenei faafanoga,", "And it come to pass,"], ["ona faaamuia lea o ia e ia i lona loto,", "when he heareth the words of this curse,"], ["e faapea ifo,", "that he bless himself in his heart,"], ["E ui lava ina ou savali i le vaogata o lo'u loto,", "saying,"], ["ma ou faaopoopo i le fia inu,", "I shall have peace,"], ["o le inu ia onā,", "though I walk in the imagination of mine heart,"], ["a e filemu lava a'u;", "to add drunkenness to thirst:"]]},
  {num:20,words:[["e le finagalo Ieova e faamagalo ia te ia,", "The LORD will not spare him,"], ["a e pusa mai le toasa o Ieova ma lona fuā i lea tagata;", "but then the anger of the LORD and his jealousy shall smoke against that man,"], ["e faaee foi ia te ia o mala uma lava ua tusia i lenei tusi;", "and all the curses that are written in this book shall lie upon him,"], ["e sōloia foi e Ieova lona igoa ai le lalolagi.", "and the LORD shall blot out his name from under heaven."]]},
  {num:21,words:[["E vavae ese foi Ieova ia te ia i itu aiga uma lava o Isaraelu ia leaga,", "And the LORD shall separate him unto evil out of all the tribes of Israel,"], ["e tusa ma mala uma o le feagaiga ua tusia i le tusi o lenei tulafono;", "according to all the curses of the covenant that are written in this book of the law:"]]},
  {num:22,words:[["o le tupulaga foi amuli o a outou fanau o e tutupu pe a mavae atu outou,", "So that the generation to come of your children that shall rise up after you,"], ["ma le tagata ese e sau mai le nuu mamao,", "and the stranger that shall come from a far land,"], ["e fai mai i latou,", "shall say,"], ["pe a vaai i latou i mala o lena nuu,", "when they see the plagues of that land,"], ["ma ma'i foi e mamai ai tagata ia Ieova;", "and the sicknesses which the LORD hath laid upon it;"]]},
  {num:23,words:[["o le teio ma le masima,", "And that the whole land thereof is brimstone, and salt,"], ["e mu ai le laueleele uma;", "and burning,"], ["e le ma totōina,", "that it is not sown,"], ["e le fua mai,", "nor beareth, nor any grass groweth therein,"], ["e le tutupu ai ni vao iti,", "like the overthrow of Sodom, and Gomorrah,"], ["e pei o le faaumatia o Sotoma ma Komoro,", "Admah,"], ["o Atama ma Sepoima,", "and Zeboim,"], ["sa faaumatia e Ieova i lona toatamai ma lona toasa;", "which the LORD overthrew in his anger, and in his wrath:"]]},
  {num:24,words:[["e faapea ane lava o nuu uma,", "Even all nations shall say,"], ["Se a le mea ua faapea ai ona fai e Ieova i lena nuu? Se a le mea ua aasa tele ai lenei toasa?", "Wherefore hath the LORD done thus unto this land? what meaneth the heat of this great anger?"]]},
  {num:25,words:[["Ona latou tali mai ai lea,", "Then men shall say,"], ["Auā ua lafoaiina e i latou le feagaiga ma Ieova o le Atua o latou tamā,", "Because they have forsaken the covenant of the LORD God of their fathers,"], ["sa osia e ia ma i latou ina o aumaia i latou e ia mai le nuu o Aikupito;", "which he made with them when he brought them forth out of the land of Egypt:"]]},
  {num:26,words:[["auā na latou o ma auauna i atua ese,", "For they went and served other gods,"], ["ma latou ifo i ai;", "and worshipped them,"], ["o atua na le iloa e i latou,", "gods whom they knew not,"], ["e lei avatu foi se mea mā latou;", "and whom he had not given unto them:"]]},
  {num:27,words:[["na tupu foi le toasa o Ieova i lena nuu,", "And the anger of the LORD was kindled against this land,"], ["ina ia faaoo i ai o mala uma ua tusia i lenei tusi;", "to bring upon it all the curses that are written in this book:"]]},
  {num:28,words:[["na liaiina foi i latou e Ieova nai lo latou laueleele i lona toatamai,", "And the LORD rooted them out of their land in anger,"], ["ma lona maemaea,", "and in wrath,"], ["ma lona toasa e matuā tele,", "and in great indignation,"], ["na ia tiai foi ia te i latou i le tasi nuu e pei,", "and cast them into another land,"], ["ona fai i le aso nei.", "as it is this day."]]},
  {num:29,words:[["O ia Ieova lo tatou Atua mea lilo;", "The secret things belong unto the LORD our God:"], ["a o mea ua faailoa mai o ia te i tatou ia ma a tatou fanau e faavavau,", "but those things which are revealed belong unto us and to our children for ever,"], ["ina ia faia e i tatou o upu uma o lenei tulafono.", "that we may do all the words of this law."]]},
];
renderVerseSet(deu_ch_29_Verses, 'deu-ch29-verses');

var deu_ch_30_Verses = [
  {num:1,words:[["A oo foi ia te oe o nei mea uma o le manuia ma le malaia,", "And it shall come to pass, when all these things are come upon thee,"], ["ua ou tuuina atu i ou luma,", "the blessing and the curse, which I have set before thee,"], ["ma e manatu i ai i nuu uma ua tulia ai oe e Ieova lou Atua,", "and thou shalt call them to mind among all the nations, whither the LORD thy God hath driven thee,"]]},
  {num:2,words:[["ma e toe foi mai ia Ieova lou Atua,", "And shalt return unto the LORD thy God,"], ["o oe ma au fanau,", "and shalt obey his voice according to all that I command thee this day,"], ["ma lou loto atoa ma lou agaga atoa;", "thou and thy children, with all thine heart,"], ["ma e faalogo i lona siufofoga i mea uma lava ou te fai atu ai ia te oe i le aso nei;", "and with all thy soul;"]]},
  {num:3,words:[["ona faaae lea e Ieova lou Atua o lau tafeaga,", "That then the LORD thy God will turn thy captivity,"], ["ma alofa atu ia te oe,", "and have compassion upon thee, and will return and gather thee from all the nations,"], ["ma toe faapotopoto mai ia te oe ai nuu uma ua faataapeapeina ai oe e Ieova lou Atua.", "whither the LORD thy God hath scattered thee."]]},
  {num:4,words:[["Afai e tulia ni o outou i le tuluiga o le lagi,", "If any of thine be driven out unto the outmost parts of heaven,"], ["e faapotopotoina mai ai oe e Ieova lou Atua,", "from thence will the LORD thy God gather thee,"], ["na te au mai ai oe;", "and from thence will he fetch thee:"]]},
  {num:5,words:[["e faaooina mai foi oe e Ieova lou Atua i le nuu sa fai mou tamā,", "And the LORD thy God will bring thee into the land which thy fathers possessed,"], ["e fai foi ia mou;", "and thou shalt possess it;"], ["na te agalelei foi ia te oe,", "and he will do thee good,"], ["ma faatoateleina oe ia sili i ou tamā.", "and multiply thee above thy fathers."]]},
  {num:6,words:[["E faaperitomeina foi e Ieova lou Atua o lou loto,", "And the LORD thy God will circumcise thine heart,"], ["ma loto o lau fanau,", "and the heart of thy seed,"], ["ina ia e alofa atu ia Ieova lou Atua ma lou loto atoa,", "to love the LORD thy God with all thine heart,"], ["ma lou agaga atoa,", "and with all thy soul,"], ["ina ia e ola ai.", "that thou mayest live."]]},
  {num:7,words:[["E faaee atu foi e Ieova lou Atua o na mala uma i e ita ia te oe,", "And the LORD thy God will put all these curses upon thine enemies,"], ["ma e 'ino'ino ia te oe,", "and on them that hate thee,"], ["o e faasaua ia te oe;", "which persecuted thee."]]},
  {num:8,words:[["e te toe foi mai e faalogo i le siufofoga o Ieova,", "And thou shalt return and obey the voice of the LORD,"], ["ma e faia ana poloaiga uma ou te fai atu ai ia te oe i le aso nei.", "and do all his commandments which I command thee this day."]]},
  {num:9,words:[["E faateleina foi e Ieova lou Atua ia te oe i mea uma lava e faia i ou lima,", "And the LORD thy God will make thee plenteous in every work of thine hand,"], ["o lau fanau,", "in the fruit of thy body,"], ["ma fanau a au manu vaefa,", "and in the fruit of thy cattle,"], ["ma fua o lou laueleele,", "and in the fruit of thy land,"], ["ia lelei ai;", "for good:"], ["auā e toe fiafia Ieova ia te oe ina ia lelei ai,", "for the LORD will again rejoice over thee for good,"], ["e pei ona ia fiafia i ou tamā;", "as he rejoiced over thy fathers:"]]},
  {num:10,words:[["pe afai e te faalogo i le siufofoga o Ieova lou Atua,", "If thou shalt hearken unto the voice of the LORD thy God,"], ["e tausi i ana poloaiga ma ana sauniga ua tusia i le tusi o lenei tulafono;", "to keep his commandments and his statutes which are written in this book of the law,"], ["pe afai foi e te foi mai ia Ieova lou Atua ma lou loto atoa,", "and if thou turn unto the LORD thy God with all thine heart,"], ["ma lou agaga atoa.", "and with all thy soul."]]},
  {num:11,words:[["Auā o lenei poloaiga ou te fai atu ai ia te oe i le aso nei,", "For this commandment which I command thee this day,"], ["e le faigata ia te e,", "it is not hidden from thee,"], ["oe le mamao foi ia.", "neither is it far off."]]},
  {num:12,words:[["E le o i le lagi ia,", "It is not in heaven,"], ["ina ia e faapea ane,", "that thou shouldest say,"], ["O ai se alu ae i le lagi mo i tatou,", "Who shall go up for us to heaven,"], ["e au mai ai ia te i tatou,", "and bring it unto us,"], ["ina ia tatou falogo i ai,", "that we may hear it,"], ["ma ia tatou faia?", "and do it?"]]},
  {num:13,words:[["E le o i tala atu o le sami ia,", "Neither is it beyond the sea,"], ["ina ia e faapea ane,", "that thou shouldest say,"], ["O ai se sopoia atu le sami mo i tatou,", "Who shall go over the sea for us,"], ["e au mai ai ia te i tatou,", "and bring it unto us,"], ["ina ia tatou faalogo i ai,", "that we may hear it,"], ["ma ia tatou faia?", "and do it?"]]},
  {num:14,words:[["A e matuā lata mai lava le upu ia te oe,", "But the word is very nigh unto thee,"], ["o i lou gutu,", "in thy mouth,"], ["ma lou loto,", "and in thy heart,"], ["ina ia e faia.", "that thou mayest do it."]]},
  {num:15,words:[["Faauta mai,", "See,"], ["ua ou tuuina atu i ou luma i le aso nei o le ola ma le manuia,", "I have set before thee this day life and good,"], ["o le oti foi ma le malaia;", "and death and evil;"]]},
  {num:16,words:[["i la'u e fai atu ai ia te oe i le aso nei, ina ia e alofa atu ia Ieova lou Atua,", "In that I command thee this day to love the LORD thy God,"], ["ma e savali i ona ala, ma e tausi i ana poloaiga,", "to walk in his ways,"], ["ma ana tulafono,", "and to keep his commandments and his statutes and his judgments,"], ["ma ana faamasinoga, ina ia e ola ai,", "that thou mayest live and multiply:"], ["ma ia faatoateleina ai; e faamanuia foi Ieova lou Atua ia te oe i le nuu e te alu i ai e fai mou.", "and the LORD thy God shall bless thee in the land whither thou goest to possess it."]]},
  {num:17,words:[["A e afai e liliu ese lou loto,", "But if thine heart turn away,"], ["ma e le faalogo,", "so that thou wilt not hear,"], ["a e tosina oe,", "but shalt be drawn away,"], ["ma e ifo atu i atua ese,", "and worship other gods,"], ["ma auauna i ai,", "and serve them;"]]},
  {num:18,words:[["ou te faailoa atu ia te outou i le aso nei,", "I denounce unto you this day,"], ["e matuā faaumatia outou,", "that ye shall surely perish,"], ["e le nofo tulu'i outou i le laueleele e te sopoia atu ai Ioritana,", "and that ye shall not prolong your days upon the land,"], ["ma alu i ai e fai mou.", "whither thou passest over Jordan to go to possess it."]]},
  {num:19,words:[["Ou te valaau i le lagi ma le lalolagi i le aso nei e fai ma molimau ia te outou,", "I call heaven and earth to record this day against you,"], ["ua ou tuuina atu i ou luma o le ola ma le oti,", "that I have set before you life and death,"], ["o le manuia ma le malaia; o lenei,", "blessing and cursing:"], ["ia e filifili i le ola,", "therefore choose life,"], ["ina ia ola ai oe atoa ma lau fanau;", "that both thou and thy seed may live:"]]},
  {num:20,words:[["ina ia e alofa atu ia Ieova lou Atua,", "That thou mayest love the LORD thy God,"], ["ma e faalogo i lona siufofoga,", "and that thou mayest obey his voice,"], ["ma ia e pipii atu ia te ia;", "and that thou mayest cleave unto him:"], ["auā o lou ola ia,", "for he is thy life,"], ["ma le na te faafualoaina ou aso;", "and the length of thy days:"], ["ina ia e mau i le laueleele sa tauto ai Ieova i ou tamā,", "that thou mayest dwell in the land which the LORD sware unto thy fathers,"], ["o Aperaamo,", "to Abraham,"], ["ma Isaako,", "to Isaac,"], ["ma Iakopo,", "and to Jacob,"], ["e foaiina atu ia te i latou.", "to give them."]]},
];
renderVerseSet(deu_ch_30_Verses, 'deu-ch30-verses');

var deu_ch_31_Verses = [
  {num:1,words:[["Ua alu atu foi Mose, ma fai atu i upu nei ia Isaraelu uma.", "And Moses went and spake these words unto all Israel."]]},
  {num:2,words:[["Ua faapea atu ia te i latou,", "And he said unto them,"], ["O o'u tausaga ua selau ma le luafulu ia i le aso nei;", "I am an hundred and twenty years old this day;"], ["ou te le toe lavā ona ou alu atu ma toe sau;", "I can no more go out and come in:"], ["ua fetalai mai foi Ieova ia te au,", "also the LORD hath said unto me,"], ["E te le sopoia atu lenei Ioritana.", "Thou shalt not go over this Jordan."]]},
  {num:3,words:[["O Ieova lou Atua,", "The LORD thy God,"], ["o ia na te sopoia atu i ou luma,", "he will go over before thee,"], ["o ia na te faaumatia ia nuu i ou luma,", "and he will destroy these nations from before thee,"], ["a e fai ai mou;", "and thou shalt possess them:"], ["o Iosua,", "and Joshua,"], ["o ia na te sopoia atu i ou luma,", "he shall go over before thee,"], ["e pei ona fetalai mai ai o Ieova.", "as the LORD hath said."]]},
  {num:4,words:[["E faia foi o Ieova ia te i latou e pei ona faia e ia ia Sekono ma Oko,", "And the LORD shall do unto them as he did to Sihon and to Og,"], ["o tupu o sa Amorī,", "kings of the Amorites,"], ["ma o laua laueleele,", "and unto the land of them,"], ["sa faaumatia i laua e ia.", "whom he destroyed."]]},
  {num:5,words:[["E tuuina mai foi i latou e Ieova i o outou luma ina ia outou faia ia te i latou e tusa ma poloaiga uma ua ou poloai atu ai ia te outou.", "And the LORD shall give them up before your face, that ye may do unto them according unto all the commandments which I have commanded you."]]},
  {num:6,words:[["Ia outou faamalolosi,", "Be strong and of a good courage,"], ["ma outou loto tetele;", "fear not,"], ["aua tou te fefefe,", "nor be afraid of them:"], ["aua foi ne'i matatau i o latou luma; auā o Ieova lou Atua,", "for the LORD thy God,"], ["lua te o faatasi ma ia;", "he it is that doth go with thee;"], ["na te le tuuna oe,", "he will not fail thee,"], ["na te le lafoai ia te oe.", "nor forsake thee."]]},
  {num:7,words:[["Ua valaau atu foi Mose ia Iosua,", "And Moses called unto Joshua,"], ["ua na fai atu foi ia te ia i luma o Isaraelu uma,", "and said unto him in the sight of all Israel,"], ["Ia e faamalosi, ma ia e loto tele;", "Be strong and of a good courage:"], ["auā tou te o ma le nuu nei i le nuu sa tauto ai Ieova i o latou tamā na te foaiina atu ia te i latou;", "for thou must go with this people unto the land which the LORD hath sworn unto their fathers to give them;"], ["e te tofitofia foi mo i latou.", "and thou shalt cause them to inherit it."]]},
  {num:8,words:[["O Ieova foi,", "And the LORD,"], ["o ia na te savali i ou luma;", "he it is that doth go before thee;"], ["lua te faatasi ma ia,", "he will be with thee,"], ["na te le tuuna oe,", "he will not fail thee,"], ["na te le lafoai ia te oe;", "neither forsake thee:"], ["aua e te fefe,", "fear not,"], ["aua foi e te mata'u.", "neither be dismayed."]]},
  {num:9,words:[["Ua tusia foi e Mose lenei tulafono,", "And Moses wrote this law,"], ["ona avatu ai lea i le au faitaulaga o le fanauga a Levi,", "and delivered it unto the priests the sons of Levi,"], ["o e tauave le atolaau o le feagaiga a Ieova,", "which bare the ark of the covenant of the LORD,"], ["atoa foi ma toeaina uma o Isaraelu.", "and unto all the elders of Israel."]]},
  {num:10,words:[["Ua fai atu foi Mose ia te i latou,", "And Moses commanded them,"], ["ua faapea atu,", "saying,"], ["A uma tausaga e fitu,", "At the end of every seven years,"], ["pe a oo i le faapotopotoga i le tausaga o le faasaolotoga,", "in the solemnity of the year of release,"], ["i le tausamiga o fale apitaga,", "in the feast of tabernacles,"]]},
  {num:11,words:[["pe a o atu Isaraelu uma ia iloa i latou i luma o Ieova lou Atua i le mea e filifilia e ia,", "When all Israel is come to appear before the LORD thy God in the place which he shall choose,"], ["ia e faitau atu ai lenei tulafono i luma o Isaraelu uma lava ia latou faalogo ai.", "thou shalt read this law before all Israel in their hearing."]]},
  {num:12,words:[["Ia e faapotopotoina le nuu,", "Gather the people together,"], ["o tane,", "men,"], ["ma fafine,", "and women,"], ["ma tama iti,", "and children,"], ["atoa ma le tagata ese e ia te oe i au aai,", "and thy stranger that is within thy gates,"], ["ina ia latou faalogologo ai,", "that they may hear,"], ["ma ia a'oa'oina i latou,", "and that they may learn,"], ["ma ia latou matatau ia Ieova lo outou Atua,", "and fear the LORD your God,"], ["ma latou anaana e fai o upu uma lava o lenei tulafono.", "and observe to do all the words of this law:"]]},
  {num:13,words:[["O a latou fanau foi,", "And that their children,"], ["e na le iloa,", "which have not known any thing,"], ["ia latou faalogologo,", "may hear,"], ["ma ia a'oa'oina i latou ia matatau ia Ieova lo outou Atua,", "and learn to fear the LORD your God,"], ["i aso uma lava tou te ola ai i le laueleele tou te sopoia atu ai Ioritana e fai mo outou.", "as long as ye live in the land whither ye go over Jordan to possess it."]]},
  {num:14,words:[["Ua fetalai mai Ieova ia Mose,", "And the LORD said unto Moses,"], ["Faauta,", "Behold,"], ["ua lata mai lou aso e te oti ai;", "thy days approach that thou must die:"], ["ia e valaau ia Iosua,", "call Joshua,"], ["ma ia oulua tutū mai i le fale fetafai o le faapotopotoga,", "and present yourselves in the tabernacle of the congregation,"], ["ina ia ou poloai atu ia te ia. Ona o ai lea o Mose ma Iosua,", "that I may give him a charge. And Moses and Joshua went,"], ["ua la tutū mai i le fale fetafai o le faapotopotoga.", "and presented themselves in the tabernacle of the congregation."]]},
  {num:15,words:[["Ona faaali mai lea o Ieova i le fale fetafai i le ao faaniutu;", "And the LORD appeared in the tabernacle in a pillar of a cloud:"], ["ua tu foi le ao faaniutu i le faitotoa o le fale fetafai.", "and the pillar of the cloud stood over the door of the tabernacle."]]},
  {num:16,words:[["Ona fetalai mai lea o Ieova ia Mose,", "And the LORD said unto Moses,"], ["Faauta,", "Behold,"], ["o le a e taoto faatasi ma ou tamā;", "thou shalt sleep with thy fathers;"], ["ona tutū lea o lenei nuu,", "and this people will rise up,"], ["ma latou mulilulua i atua o tagata ese o le nuu latou te o i ai,", "and go a whoring after the gods of the strangers of the land,"], ["e faatasi ai ma i latou,", "whither they go to be among them,"], ["latou te lafoai mai foi ia te au,", "and will forsake me,"], ["ma latou soli i la'u feagaiga na ou osia ma i latou.", "and break my covenant which I have made with them."]]},
  {num:17,words:[["Ona tupu ai lea o lo'u ita ia te i latou i lea aso,", "Then my anger shall be kindled against them in that day,"], ["ona ou lafoai lea ia te i latou,", "and I will forsake them,"], ["ma 'alo o'u mata ia te i latou,", "and I will hide my face from them,"], ["e faaumatia foi i latou,", "and they shall be devoured, and many evils and troubles shall befall them;"], ["e oo ia te i latou o mea leaga o tele ma mea e tiga ai;", "so that they will say in that day,"], ["ona fai ane lea o i latou i lea aso,", "Are not these evils come upon us,"], ["E le ua oo ea nei mea leaga ia te i tatou ina ua le o ia te i tatou lo tatou Atua?", "because our God is not among us?"]]},
  {num:18,words:[["E matuā 'alo o'u mata i lea aso ona o mea leaga uma ua latou faia,", "And I will surely hide my face in that day for all the evils which they shall have wrought,"], ["ina ua latou faasaga i atua ese.", "in that they are turned unto other gods."]]},
  {num:19,words:[["O lenei,", "Now therefore write ye this song for you,"], ["ia outou tusia lenei pese mā outou,", "and teach it the children of Israel:"], ["ma a'oa'o ai i le fanauga a Isaraelu; ia le te'a i o latou gutu,", "put it in their mouths,"], ["ina ia avea lenei pese ma molimau ia te au i le fanauga a Isaraelu.", "that this song may be a witness for me against the children of Israel."]]},
  {num:20,words:[["Auā pe a ou faaoo atu ia te i latou i le laueleele sa ou tauto ai i o latou tamā,", "For when I shall have brought them into the land which I sware unto their fathers,"], ["o tafe ai le suāsusu ma le meli;", "that floweth with milk and honey;"], ["pe a uma foi ona latou aai,", "and they shall have eaten and filled themselves,"], ["ma latou maoona,", "and waxen fat;"], ["ma puputa ai i latou; ona faasaga lea o i latou i atua ese,", "then will they turn unto other gods,"], ["ma auauna atu i ai,", "and serve them,"], ["ma 'ino'ino mai ia te au,", "and provoke me,"], ["ma soli i la u feagaiga.", "and break my covenant."]]},
  {num:21,words:[["A oo foi ia te i latou o mea leaga e tele,", "And it shall come to pass,"], ["ma mea e tiga ai,", "when many evils and troubles are befallen them,"], ["ona fai lea o lenei pese ma molimau ia te i latou;", "that this song shall testify against them as a witness; for it shall not be forgotten out of the mouths of their seed:"], ["auā e le galo ai i gutu o a latou fanau;", "for I know their imagination which they go about,"], ["auā ua ou iloa o latou manatu ua latou faia i le aso nei,", "even now,"], ["a o lei faaooina e a'u o i latou i le nuu na ou tauto ai.", "before I have brought them into the land which I sware."]]},
  {num:22,words:[["Ua tusi foi e Mose lenei pese i lea lava aso,", "Moses therefore wrote this song the same day,"], ["ua na a'oa'o atu ai foi i le fanauga a Isaraelu.", "and taught it the children of Israel."]]},
  {num:23,words:[["Ua poloai atu foi o ia ia Iosua le atalii o Nuno,", "And he gave Joshua the son of Nun a charge,"], ["ua faapea atu,", "and said,"], ["Ia e faamalosi, ma ia e loto tele;", "Be strong and of a good courage:"], ["auā e te faaooina atu le fanauga a Isaraelu i le nuu sa ou tauto ai ia e i latou;", "for thou shalt bring the children of Israel into the land which I sware unto them:"], ["ou te i ai foi ia te oe.", "and I will be with thee."]]},
  {num:24,words:[["Ua uma foi ona tusia e Mose o upu o lenei tulafono i le tusi,", "And it came to pass, when Moses had made an end of writing the words of this law in a book,"], ["ua oo ina atoa,", "until they were finished,"]]},
  {num:25,words:[["ona fai atu lea o Mose i sa Levī,", "That Moses commanded the Levites,"], ["o e sa tauave le atolaau o le feagaiga a Ieova,", "which bare the ark of the covenant of the LORD,"], ["ua faapea atu,", "saying,"]]},
  {num:26,words:[["Ia outou ave le tusi o lenei tulafono,", "Take this book of the law,"], ["ma tuu ai i le itu o le atolaau o le feagaiga a Ieova lo outou Atua,", "and put it in the side of the ark of the covenant of the LORD your God,"], ["ina ia i ai e fai ma molimau ia te oe.", "that it may be there for a witness against thee."]]},
  {num:27,words:[["Auā ua ou iloa lou fouvale,", "For I know thy rebellion,"], ["ma lou ua maaa;", "and thy stiff neck:"], ["faauta,", "behold,"], ["o loo fouvale outou ia Ieova,", "while I am yet alive with you this day,"], ["o loo o tatou ola faatasi i le aso nei;", "ye have been rebellious against the LORD;"], ["e le atili ai ea pe a ou oti?", "and how much more after my death?"]]},
  {num:28,words:[["Ia outou faapotopoto mai ia te au o teoaina uma o outou itu aiga,", "Gather unto me all the elders of your tribes,"], ["ma o outou faipule,", "and your officers,"], ["ina ia ou fai atu nei upu ia latou faalogo ai,", "that I may speak these words in their ears,"], ["ou te valaau foi i le lagi ma le lalolagi e fai ma molimau ia te i latou.", "and call heaven and earth to record against them."]]},
  {num:29,words:[["Auā ua ou iloa pe a mavae lo'u oti,", "For I know that after my death ye will utterly corrupt yourselves,"], ["ona matuā leaga lea o outou,", "and turn aside from the way which I have commanded you;"], ["ma outou o ese i le ala ua ou poloai atu ai ia te outou; e oo foi ia te outou mea leaga i aso amuli;", "and evil will befall you in the latter days;"], ["auā e faia e outou mea leaga i luma o Ieova,", "because ye will do evil in the sight of the LORD,"], ["i lo outou faaonoono ia te ia i le galuega a o outou lima.", "to provoke him to anger through the work of your hands."]]},
  {num:30,words:[["Ua fai atu foi Mose a o faalogologo mai le faapotopotoga uma o Isaraelu o upu o lenei pese,", "And Moses spake in the ears of all the congregation of Israel the words of this song,"], ["ua oo ina atoa", "until they were ended."]]},
];
renderVerseSet(deu_ch_31_Verses, 'deu-ch31-verses');

var deu_ch_32_Verses = [
  {num:1,words:[["Le lagi e,", "Give ear,"], ["uai mai ia ou taliga,", "O ye heavens,"], ["ona ou tautala atu ai lea;", "and I will speak; and hear,"], ["le lalolagi e,", "O earth,"], ["faalogologo mai ia i upu a lo'u gutu.", "the words of my mouth."]]},
  {num:2,words:[["O la'u mataupu e sisina ifo ia e pei o le ua,", "My doctrine shall drop as the rain,"], ["o la'u tautalaga e toto ifo lea e pei o le sau;", "my speech shall distil as the dew,"], ["e pei o timuga i le vao mu'a,", "as the small rain upon the tender herb,"], ["e pei o uaga foi i le vao iti;", "and as the showers upon the grass:"]]},
  {num:3,words:[["auā ou te valaau atu i le suafa o Ieova;", "Because I will publish the name of the LORD:"], ["ia outou vivii atu i le silisili ese o lo tatou Atua.", "ascribe ye greatness unto our God."]]},
  {num:4,words:[["O le Papa,", "He is the Rock,"], ["e sao lava lana galuega;", "his work is perfect:"], ["auā e tonu ona ala uma lava; o le Atua faamaoni,", "for all his ways are judgment:"], ["e le o ia te ia se amioletonu,", "a God of truth and without iniquity,"], ["o le amiotonu ma le amio sa'o lava ia.", "just and right is he."]]},
  {num:5,words:[["Ua leaga i latou,", "They have corrupted themselves,"], ["e le o lana fanau, a o lo latou ila;", "their spot is not the spot of his children:"], ["o le tupulaga faapiopio ma le faa'ole'ole.", "they are a perverse and crooked generation."]]},
  {num:6,words:[["Tou te faapea ea ona taui atu ia Ieova,", "Do ye thus requite the LORD,"], ["le nuu valea e ma le le poto? E le o lou Tamā ea o ia sa faatauina mai ai oe? E le o ia ea na faia oe,", "O foolish people and unwise? is not he thy father that hath bought thee? hath he not made thee,"], ["ma na faatumauina oe?", "and established thee?"]]},
  {num:7,words:[["Ia e manatua aso o le vavau;", "Remember the days of old,"], ["mafaufau ia i tausaga o lea tupulaga ma lea tupulaga;", "consider the years of many generations:"], ["fesili atu i lou tamā,", "ask thy father,"], ["na te ta'u mai ai ia te oe;", "and he will shew thee;"], ["o outou toeaina foi,", "thy elders,"], ["latou te fai mai ai ia te oe.", "and they will tell thee."]]},
  {num:8,words:[["O ona po na tofitofia ai e le Silisili ese o nuu,", "When the most High divided to the nations their inheritance,"], ["ma na faataapeapeina e ia le fanau a Atamu, na ia faia tuaoi o le nuu,", "when he separated the sons of Adam,"], ["e tusa ma le faitau o le fanauga a Isaraelu.", "he set the bounds of the people according to the number of the children of Israel."]]},
  {num:9,words:[["Auā o le tofi o Ieova o lona nuu lea;", "For the LORD'S portion is his people;"], ["o Iakopo o lona tofi lea ua fuafuaina.", "Jacob is the lot of his inheritance."]]},
  {num:10,words:[["Na ia maua o ia i le vao,", "He found him in a desert land,"], ["o le mea e le āina, e uio ai manu feai,", "and in the waste howling wilderness;"], ["ma ua gaogao;", "he led him about,"], ["na ia siosio ia te ia, ma a'oa'o atu ia te ia,", "he instructed him,"], ["na ia leoleo ia te ia e pei o lona tamatamaimata.", "he kept him as the apple of his eye."]]},
  {num:11,words:[["E pei o le aeto ona faaoso i ana tama,", "As an eagle stirreth up her nest,"], ["e faapepepepe i luga o ana tama,", "fluttereth over her young,"], ["e fola ona apaau,", "spreadeth abroad her wings,"], ["e saposapo ia te i latou,", "taketh them,"], ["e ave ia te i latou i luga i ona apaau;", "beareth them on her wings:"]]},
  {num:12,words:[["sa faapea Ieova e toatasi ona ta'ita'i ia te ia,", "So the LORD alone did lead him,"], ["sa leai foi se atua ese e toalua ma ia.", "and there was no strange god with him."]]},
  {num:13,words:[["Na ia faatietie ia te ia i mea maualuluga o le lalolagi,", "He made him ride on the high places of the earth,"], ["ina ia 'ai foi o ia i fua o le fanua;", "that he might eat the increase of the fields;"], ["na ia fafaga foi ia te ia i le meli mai le papa,", "and he made him to suck honey out of the rock,"], ["ma le suāuu mai le papa alā;", "and oil out of the flinty rock;"]]},
  {num:14,words:[["o suāsusu to'a o povi,", "Butter of kine,"], ["ma suāsusu o mamoe,", "and milk of sheep,"], ["o e pepeti foi o tamai mamoe,", "with fat of lambs,"], ["ma mamoe poa o Vasana,", "and rams of the breed of Bashan,"], ["o 'oti poa foi,", "and goats,"], ["ma le saito e sili ona lelei;", "with the fat of kidneys of wheat;"], ["na e inu foi i le suāvine totototo e le suia.", "and thou didst drink the pure blood of the grape."]]},
  {num:15,words:[["Na puta Iesuruna,", "But Jeshurun waxed fat,"], ["ma ua vaogata;", "and kicked:"], ["ua e puta,", "thou art waxen fat,"], ["ua e tino tele,", "thou art grown thick,"], ["ua e puta lava;", "thou art covered with fatness;"], ["ona tuulafoaiina lea e ia o le Atua na ia faia o ia,", "then he forsook God which made him,"], ["ma ua 'ino'ino o ia i le Papa o lona olataga.", "and lightly esteemed the Rock of his salvation."]]},
  {num:16,words:[["Na latou faatupuina lona fuā ona o atua ese;", "They provoked him to jealousy with strange gods,"], ["na latou faaonoono ia te ia i mea inosia.", "with abominations provoked they him to anger."]]},
  {num:17,words:[["Na latou fai taulaga i temoni,", "They sacrificed unto devils,"], ["e le o le Atua;", "not to God;"], ["o atua na le iloa e i latou; o atua fou,", "to gods whom they knew not,"], ["na se'i tutupu,", "to new gods that came newly up,"], ["na le matatau i ai o outou tamā.", "whom your fathers feared not."]]},
  {num:18,words:[["Ua le manatua e oe le Papa na fanaua oe,", "Of the Rock that begat thee thou art unmindful,"], ["ma ua e faagalogaloina le Atua na ia faia oe.", "and hast forgotten God that formed thee."]]},
  {num:19,words:[["Na silasila Ieova,", "And when the LORD saw it,"], ["ona 'ino'ino lea o ia ia te i latou ,", "he abhorred them, because of the provoking of his sons,"], ["ona o le faaonoono mai o ona atalii ma ona afafine.", "and of his daughters."]]},
  {num:20,words:[["Ona fetalai mai lea o ia,", "And he said,"], ["Ou te 'alo o'u mata ia te i latou,", "I will hide my face from them,"], ["ia ou iloa pe se a lo latou iuga;", "I will see what their end shall be:"], ["auā o le tupulaga faapiopio i latou,", "for they are a very froward generation,"], ["o le fanau ua le o i ai se faamaoni.", "children in whom is no faith."]]},
  {num:21,words:[["Ua faatupuina e i latou lo'u fuā i le mea ua le se atua;", "They have moved me to jealousy with that which is not God;"], ["ua faaonoono i latou ia te au i a latou mea faatauvaa;", "they have provoked me to anger with their vanities:"], ["o au foi, ou te faatupuina lo latou fuā ia te i latou e le se nuu;", "and I will move them to jealousy with those which are not a people;"], ["ou te faaonoono ia te i latou i le nuu valea.", "I will provoke them to anger with a foolish nation."]]},
  {num:22,words:[["Auā ua si'a le afi i lo'u ita,", "For a fire is kindled in mine anger,"], ["e mu ifo foi ia e oo lava i seoli e maulalo lava;", "and shall burn unto the lowest hell,"], ["e faaumatia ai le lalolagi ma ona fua,", "and shall consume the earth with her increase,"], ["e mu ai foi faavae o mauga.", "and set on fire the foundations of the mountains."]]},
  {num:23,words:[["Ou te faaputuina i luga ia te i latou mea leaga;", "I will heap mischiefs upon them;"], ["ou te faauma atu a'u u fanafana ia te i latou.", "I will spend mine arrows upon them."]]},
  {num:24,words:[["E tinovavale i latou i le oge,", "They shall be burnt with hunger,"], ["e faaumatia foi i le ma'i vevela,", "and devoured with burning heat,"], ["ma le mala e fano ai;", "and with bitter destruction:"], ["ou te auina foi manu feai īa te i latou,", "I will also send the teeth of beasts upon them,"], ["ma mea oona o gata o le eleele.", "with the poison of serpents of the dust."]]},
  {num:25,words:[["O le pelu i tua o le aai ,", "The sword without,"], ["ma le mata'u i totonu,", "and terror within,"], ["e faumatia ai taulelea ma taupou,", "shall destroy both the young man and the virgin,"], ["o tama meamea ma tagata ulusinā.", "the suckling also with the man of gray hairs."]]},
  {num:26,words:[["Na ou fai ane,", "I said,"], ["Ou te faataapeape ia te i latou,", "I would scatter them into corners,"], ["ou te faateaeseina lo latou faamanatuga i tagata;", "I would make the remembrance of them to cease from among men:"]]},
  {num:27,words:[["ana ou le fefe i le faaonoono o e ita mai,", "Were it not that I feared the wrath of the enemy,"], ["ne'i le iloa e o latou fili,", "lest their adversaries should behave themselves strangely,"], ["ne'i latou faapea ane,", "and lest they should say,"], ["O tatou lima malosi,", "Our hand is high,"], ["a e le o Ieova na faia o nei mea uma.", "and the LORD hath not done all this."]]},
  {num:28,words:[["Auā o le nuu i latou e le o i ai ni pulega,", "For they are a nation void of counsel,"], ["ua leai foi se faautauta ia te i latou.", "neither is there any understanding in them."]]},
  {num:29,words:[["E,", "O that they were wise,"], ["ana latou popoto,", "that they understood this,"], ["ana latou iloa lenei mea! Ina ia latou mafaufau i o latou iuga.", "that they would consider their latter end!"]]},
  {num:30,words:[["Pe faapefea ona tulia e le toatasi le toaafe,", "How should one chase a thousand,"], ["ma tutuli e le toalua o afe e sefulu,", "and two put ten thousand to flight,"], ["ane le faatauina atu i latou e lo latou Papa,", "except their Rock had sold them,"], ["ma tuuina atu i latou e Ieova?", "and the LORD had shut them up?"]]},
  {num:31,words:[["(Auā e le pei o lo tatou Papa lo latou papa,", "For their rock is not as our Rock,"], ["ua fai foi o e ita mai ia te i tatou ma faamasino i ai .)", "even our enemies themselves being judges."]]},
  {num:32,words:[["Auā o lo latou vine mai le vine o Sotoma lea,", "For their vine is of the vine of Sodom,"], ["mai fanua o Komoro foi;", "and of the fields of Gomorrah:"], ["o latou fua o vine o vine oona ia,", "their grapes are grapes of gall,"], ["e oona foi o latou fuifuivine;", "their clusters are bitter:"]]},
  {num:33,words:[["o le mea 'ona o gata o latou uaina,", "Their wine is the poison of dragons,"], ["ma le mea matuā 'ona o asipi.", "and the cruel venom of asps."]]},
  {num:34,words:[["E le teua ea lenei mea e au,", "Is not this laid up in store with me,"], ["ma faamauina faatasi ma a'u oloa?", "and sealed up among my treasures?"]]},
  {num:35,words:[["O ia te au le taui ma sui,", "To me belongeth vengeance,"], ["atoa ma le taui atu i ona po e mapeva ai o latou vae;", "and recompence;"], ["auā ua lata mai le aso latou te malaia ai,", "their foot shall slide in due time: for the day of their calamity is at hand,"], ["o loo faataalise mai foi mea a oo ia te i latou.", "and the things that shall come upon them make haste."]]},
  {num:36,words:[["Auā e faamasinoina e Ieova lona nuu,", "For the LORD shall judge his people,"], ["e salamo foi o ia ona o ana auauna,", "and repent himself for his servants,"], ["pe a silafia e ia ua mavae lo latou malosi,", "when he seeth that their power is gone, and there is none shut up,"], ["ma ua le toe se pologa po o se saoloto.", "or left."]]},
  {num:37,words:[["Ona fetalai mai lea o ia,", "And he shall say,"], ["O fea o i ai o latou atua,", "Where are their gods,"], ["o le papa na latou faatuatua i ai,", "their rock in whom they trusted,"]]},
  {num:38,words:[["o e na aai i ga'o o a latou taulaga,", "Which did eat the fat of their sacrifices,"], ["o e na inu le uaina o a latou taulaga i mea e inu? Ia latou tutū mai, ma fesoasoani ia te outou,", "and drank the wine of their drink offerings? let them rise up and help you,"], ["ia fai i latou ma lafitaga mo outou.", "and be your protection."]]},
  {num:39,words:[["O lenei,", "See now that I,"], ["ia outou iloa o a'u,", "even I,"], ["o a'u lava o ia,", "am he,"], ["e leai foi se atua e toalua ma a'u;", "and there is no god with me:"], ["ou te fasiotia,", "I kill,"], ["ma ou faaolaina;", "and I make alive;"], ["ou te taia,", "I wound,"], ["ma ou faamaloloina;", "and I heal:"], ["e leai foi se na te laveai mai ai lo'u lima.", "neither is there any that can deliver out of my hand."]]},
  {num:40,words:[["Auā ou te sii lo'u lima i le lagi,", "For I lift up my hand to heaven,"], ["ma ou faapea ane,", "and say,"], ["Ou te ola e faavavau.", "I live for ever."]]},
  {num:41,words:[["Afai ou te faamaai la'u pelu pupula,", "If I whet my glittering sword,"], ["ma tago lo'u lima i le faamasinoga,", "and mine hand take hold on judgment;"], ["ou te taui ma sui i e o fai a'u ma fili,", "I will render vengeance to mine enemies,"], ["ma ou taui atu i e o 'ino'ino mai ia te au.", "and will reward them that hate me."]]},
  {num:42,words:[["Ou te faainu ia onā a'u u fanafana i le toto,", "I will make mine arrows drunk with blood,"], ["e 'ai foi la'u pelu i tino o tagata ;", "and my sword shall devour flesh;"], ["o le toto o e ua fasia, ma e ua faatagataotaua,", "and that with the blood of the slain and of the captives,"], ["o alii sili o e ita mai.", "from the beginning of revenges upon the enemy."]]},
  {num:43,words:[["Outou nuu ese e,", "Rejoice,"], ["ina olioli ia faatasi ma lona nuu;", "O ye nations, with his people:"], ["auā na te taui ma sui le toto o ana auauna,", "for he will avenge the blood of his servants,"], ["na te tuuina atu foi le taui i e o fai o ia ma fili;", "and will render vengeance to his adversaries, and will be merciful unto his land,"], ["e togiolaina foi e ia le laueleele o lona nuu.", "and to his people."]]},
  {num:44,words:[["Ua alu atu Mose,", "And Moses came and spake all the words of this song in the ears of the people,"], ["ma fai atu i upu uma o lenei pese a o faalogologo mai le nuu,", "he,"], ["o i laua ma Iosua le atalii o Nuno.", "and Hoshea the son of Nun."]]},
  {num:45,words:[["Ua uma foi ona fai atu e Mose nei upu uma ia Isaraelu uma lava;", "And Moses made an end of speaking all these words to all Israel:"]]},
  {num:46,words:[["ona ia fai atu lea ia te i latou,", "And he said unto them,"], ["Ia outou manatunatu i upu uma ou te ta'u atu ia te outou i le aso ne'i;", "Set your hearts unto all the words which I testify among you this day, which ye shall command your children to observe to do,"], ["tou te poloai atu ai i a outou fanau ia anaana e faia upu uma o lenei tulafono.", "all the words of this law."]]},
  {num:47,words:[["Auā e le se upu faatauvaa lea ia te outou,", "For it is not a vain thing for you;"], ["auā o i ai lo outou ola;", "because it is your life:"], ["o lenei mea foi tou te faafualoa ai o outou aso i le laueleele,", "and through this thing ye shall prolong your days in the land,"], ["tou te sopoia atu ai Ioritana e fai mo outou.", "whither ye go over Jordan to possess it."]]},
  {num:48,words:[["Ua fetalai mai foi Ieova ia Mose i lea lava aso,", "And the LORD spake unto Moses that selfsame day,"], ["ua faapea mai,", "saying,"]]},
  {num:49,words:[["Ina alu ae ia oe i lena mauga,", "Get thee up into this mountain Abarim,"], ["o Aperima,", "unto mount Nebo,"], ["o le mauga o Nepo,", "which is in the land of Moab,"], ["o i le nuu o Moapi,", "that is over against Jericho;"], ["o loo fesagai ma Ieriko;", "and behold the land of Canaan,"], ["ma e vaai atu i le nuu o Kanana ua ou foaiina atu i le fanauga a Isaraelu e fai mo latou.", "which I give unto the children of Israel for a possession:"]]},
  {num:50,words:[["E te oti foi i le mauga e te alu ae i ai,", "And die in the mount whither thou goest up,"], ["e faatasiina atu foi oe i lou nuu,", "and be gathered unto thy people;"], ["e faapei ona oti o Arona lou uso i le mauga o Horo,", "as Aaron thy brother died in mount Hor,"], ["ua faatasiina atu foi i lona nuu;", "and was gathered unto his people:"]]},
  {num:51,words:[["auā na agasala mai oulua ia te au i luma o le fanauga a Isaraelu i le vai o Meripa-katesa i le vao o Tisina;", "Because ye trespassed against me among the children of Israel at the waters of Meribah-Kadesh, in the wilderness of Zin;"], ["auā na le faapaiaina o a'u e oulua i luma o le fanauga a Isaraelu.", "because ye sanctified me not in the midst of the children of Israel."]]},
  {num:52,words:[["E vaai atu oe i le nuu o i ou luma,", "Yet thou shalt see the land before thee;"], ["a e te le oo i le nuu ua ou foaiina atu i le fanauga a Isaraelu.", "but thou shalt not go thither unto the land which I give the children of Israel."]]},
];
renderVerseSet(deu_ch_32_Verses, 'deu-ch32-verses');

var deu_ch_33_Verses = [
  {num:1,words:[["O le manuia lenei, na faamanuia atu ai le fanauga a Isaraelu e Mose,", "And this is the blessing,"], ["le tagata o le Atua, a o lei oti o ia. Ua ia faapea atu, Na afio mai Ieova mai Sinai,", "wherewith Moses the man of God blessed the children of Israel before his death."]]},
  {num:2,words:[["na afio ae foi o ia i Seira ia te i latou;", "And he said, The LORD came from Sinai,"], ["na pupula mai o ia mai le mauga o Parana,", "and rose up from Seir unto them;"], ["na ia afio mai foi ma le au paia e manomano;", "he shined forth from mount Paran,"], ["mai lona aao taumatau le afi o le tulafono mo i latou.", "and he came with ten thousands of saints: from his right hand went a fiery law for them."]]},
  {num:3,words:[["E moni,", "Yea,"], ["ua alofa o ia i le nuu;", "he loved the people;"], ["o i lou lima lona au paia uma lava;", "all his saints are in thy hand:"], ["ua latou nonofo i ou vae;", "and they sat down at thy feet;"], ["e talia e i latou au afioga.", "every one shall receive of thy words."]]},
  {num:4,words:[["Na tuuina mai e Mose le tulafono ia te i tatou,", "Moses commanded us a law,"], ["o le tofi lea mo le faapotopotoga o Iakopo.", "even the inheritance of the congregation of Jacob."]]},
  {num:5,words:[["Na fai foi o ia ma tupu i Iesuruna,", "And he was king in Jeshurun,"], ["ina o faapotopotoina o alii sili o le nuu atoa ma itu aiga o Isaraelu.", "when the heads of the people and the tribes of Israel were gathered together."]]},
  {num:6,words:[["Ia ola Reupena,", "Let Reuben live,"], ["aua le oti;", "and not die;"], ["aua foi le toaitiiti ona tagata.", "and let not his men be few."]]},
  {num:7,words:[["O le upu lenei ia Iuta;", "And this is the blessing of Judah:"], ["na ia faapea mai ai,", "and he said,"], ["Ieova e,", "Hear,"], ["faafofoga mai ia i le leo o Iuta,", "LORD, the voice of Judah,"], ["ma e aumaia o ia i lona nuu;", "and bring him unto his people:"], ["ia lima malosi lava o ia;", "let his hands be sufficient for him;"], ["ia fai foi oe ma fesoasoani ia te ia i e ita ia te ia.", "and be thou an help to him from his enemies."]]},
  {num:8,words:[["Na ia fapea mai foi ia Levi,", "And of Levi he said,"], ["Ia i ai lou Tumema ma lou Urima i lou tagata paia na e tofotofoina i Mase,", "Let thy Thummim and thy Urim be with thy holy one, whom thou didst prove at Massah,"], ["na e finau ia te ia i le vai o Meripa;", "and with whom thou didst strive at the waters of Meribah;"]]},
  {num:9,words:[["o le na fai atu i lona tamā ma lona tinā,", "Who said unto his father and to his mother,"], ["Ua ou le ilo atu ia te ia;", "I have not seen him;"], ["o le na le iloa foi ona uso,", "neither did he acknowledge his brethren,"], ["ua na le iloa foi ana fanau;", "nor knew his own children:"], ["auā ua latou tausi i lau afioga,", "for they have observed thy word,"], ["ua latou taofi foi i lau feagaiga.", "and kept thy covenant."]]},
  {num:10,words:[["Latou te a'oa'o atu ia Iakopo i au faamasinoga,", "They shall teach Jacob thy judgments,"], ["ma Isaraelu i lau tulafono;", "and Israel thy law:"], ["latou te tuuina atu i ou luma o mea manogi,", "they shall put incense before thee,"], ["ma le taulaga mu uma i lou fata faitaulaga.", "and whole burnt sacrifice upon thine altar."]]},
  {num:11,words:[["Ieova e,", "Bless,"], ["ia e faamanuia ana oloa,", "LORD,"], ["ma e fiafia i le galuega a ona lima;", "his substance, and accept the work of his hands:"], ["ia e ta i papātua o e laga mai ia te ia,", "smite through the loins of them that rise against him,"], ["ma i latou o e ita mai ia te ia,", "and of them that hate him,"], ["ne'i latou toe laga mai.", "that they rise not again."]]},
  {num:12,words:[["Na ia faapea mai ia Peniamina,", "And of Benjamin he said,"], ["O le pele ia Ieova e nofo o ia ma le filemu faatasi ma ia;", "The beloved of the LORD shall dwell in safety by him;"], ["na te faamamalu ia te ia i le aso atoa;", "and the LORD shall cover him all the day long,"], ["e nofo foi o ia i le va o ona tau'au.", "and he shall dwell between his shoulders."]]},
  {num:13,words:[["Na ia faapea mai foi ia Iosefa,", "And of Joseph he said,"], ["Ia faamanuia lona laueleele e Ieova i mea e sili ona lelei mai le lagi,", "Blessed of the LORD be his land,"], ["o le sau,", "for the precious things of heaven, for the dew,"], ["ma mea lelei mai le mea loloto o loo i lalo;", "and for the deep that coucheth beneath,"]]},
  {num:14,words:[["ma mea e sili ona lelei e tutupu i le la,", "And for the precious fruits brought forth by the sun,"], ["ma mea e sili ona lelei e tutupu i masina;", "and for the precious things put forth by the moon,"]]},
  {num:15,words:[["ma mea e sili ona lelei i mauga o le vavau,", "And for the chief things of the ancient mountains,"], ["ma mea e sili ona lelei o mauga iti o le faavavau,", "and for the precious things of the lasting hills,"]]},
  {num:16,words:[["ma mea e sili ona lelei o le laueleele ma mea uma ua tumu ai,", "And for the precious things of the earth and fulness thereof,"], ["ma le finagalo alofa o le na nofo i le laau talatala,", "and for the good will of him that dwelt in the bush:"], ["ia oo lava lea i luga o le ulu o Iosefa;", "let the blessing come upon the head of Joseph,"], ["ma le tumuai o le na sili i ona uso.", "and upon the top of the head of him that was separated from his brethren."]]},
  {num:17,words:[["O lona matagofie o le uluai tama a lana povi lea;", "His glory is like the firstling of his bullock,"], ["o ona nifo o nifo o le rema ia;", "and his horns are like the horns of unicorns:"], ["na te suatia ai nuu uma ia oo i tuluiga o le lalolagi;", "with them he shall push the people together to the ends of the earth:"], ["o mano ia o Efaraima,", "and they are the ten thousands of Ephraim,"], ["o afe foi ia o Manase.", "and they are the thousands of Manasseh."]]},
  {num:18,words:[["Na ia faapea mai foi ia Sepulona,", "And of Zebulun he said,"], ["Sepulona e,", "Rejoice, Zebulun,"], ["ia e olioli i lou alu atu;", "in thy going out;"], ["ma oe Isakara e,", "and, Issachar,"], ["ia e olioli i totonu o ou fale ie.", "in thy tents."]]},
  {num:19,words:[["E valaau i laua i nuu e o mai i le mauga;", "They shall call the people unto the mountain;"], ["latou te fai ai taulaga tatau;", "there they shall offer sacrifices of righteousness:"], ["auā e maua mai e i laua le oloa tele mai le sami,", "for they shall suck of the abundance of the seas,"], ["ma le oloa ua lilo i le oneone.", "and of treasures hid in the sand."]]},
  {num:20,words:[["Na ia faapea mai foi ia Kato,", "And of Gad he said,"], ["Ia manuia le na te faalauteleina Kato. O loo taoto o ia e pei o se leona,", "Blessed be he that enlargeth Gad: he dwelleth as a lion,"], ["ua saeia foi e ia le lima atoa ma le tumuai.", "and teareth the arm with the crown of the head."]]},
  {num:21,words:[["Ua na vaaia foi le mea e sili mo ia,", "And he provided the first part for himself,"], ["auā ua faamauina i lea mea o le tofi e le faipule;", "because there,"], ["na latou o,", "in a portion of the lawgiver, was he seated;"], ["o ia ma alii sili o le nuu;", "and he came with the heads of the people,"], ["na ia faia mea tonu mai ia Ieova,", "he executed the justice of the LORD,"], ["ma ona faamasinoga faatasi ma Isaraelu.", "and his judgments with Israel."]]},
  {num:22,words:[["Na ia faapea foi ia Tanu,", "And of Dan he said,"], ["O Tanu o le leona taanoa ia,", "Dan is a lion's whelp:"], ["e oso mai o ia mai Vasana.", "he shall leap from Bashan."]]},
  {num:23,words:[["Na ia faapea mai foi ia Nafatali,", "And of Naphtali he said,"], ["Nafatali e,", "O Naphtali,"], ["ua e mălie i le alofa,", "satisfied with favour,"], ["ma ua tumu i le manuia mai ia Ieova;", "and full with the blessing of the LORD:"], ["ia e fai mou le vai ma le itu i toga.", "possess thou the west and the south."]]},
  {num:24,words:[["Na ia faapea mai foi ia Asera,", "And of Asher he said,"], ["O Asera,", "Let Asher be blessed with children;"], ["e manuia o ia i ana fanau; ia fiafia ona uso ia te ia;", "let him be acceptable to his brethren,"], ["ia fufui foi e ia lona vae i le suāuu.", "and let him dip his foot in oil."]]},
  {num:25,words:[["O ou faamau o uamea ma 'apa memea ia;", "Thy shoes shall be iron and brass; and as thy days,"], ["e pei o ou aso foi e faapea lou malosi.", "so shall thy strength be."]]},
  {num:26,words:[["E leai lava se la te tutusa ma le Atua o Iesuruna,", "There is none like unto the God of Jeshurun,"], ["o loo tietie i le lagi e fai ma ou fesoasoani,", "who rideth upon the heaven in thy help,"], ["e tietie foi i ao o le lagi i lona mamalu.", "and in his excellency on the sky."]]},
  {num:27,words:[["O le mea e te nofo ai o le Atua o le faavavau lea;", "The eternal God is thy refuge,"], ["o i ou lalo foi aao o le faavavau;", "and underneath are the everlasting arms:"], ["e tulia foi e ia i ou luma le ua ita mai;", "and he shall thrust out the enemy from before thee;"], ["na te fetalai mai foi,", "and shall say,"], ["Ia e faaumatia i latou .", "Destroy them."]]},
  {num:28,words:[["E nofo Isaraelu e toatasi ma le filemu;", "Israel then shall dwell in safety alone:"], ["o le vaipuna o Iakopo e i ai lea i le nuu o saito ma uaina;", "the fountain of Jacob shall be upon a land of corn and wine;"], ["o lona lagi foi e totō ifo ai le sau.", "also his heavens shall drop down dew."]]},
  {num:29,words:[["Isaraelu e,", "Happy art thou, O Israel:"], ["amuia oe! O ai se nuu e tutusa ma oe? O le nuu ua faaolaina e Ieova! O le talita e fesoasoani ia te oe,", "who is like unto thee, O people saved by the LORD,"], ["o ia foi le pelu e mamalu ai oe! E faataga vivii ia te oe o e ita ia te oe,", "the shield of thy help,"], ["e te solia foi a latou mea maualuluga.", "and who is the sword of thy excellency! and thine enemies shall be found liars unto thee; and thou shalt tread upon their high places."]]},
];
renderVerseSet(deu_ch_33_Verses, 'deu-ch33-verses');

var deu_ch_34_Verses = [
  {num:1,words:[["Ua alu ae foi Mose nai le eleele laugatasi o Moapi i le mauga o Nepo,", "And Moses went up from the plains of Moab unto the mountain of Nebo,"], ["i le tumutumu o Peseka,", "to the top of Pisgah,"], ["e fesagai ma Ieriko.", "that is over against Jericho."], ["Ona faasino atu lea e Ieova ia te ia le nuu uma lava o Kiliata e oo lava i Tanu.", "And the LORD shewed him all the land of Gilead, unto Dan,"]]},
  {num:2,words:[["O Nafatali uma foi,", "And all Naphtali,"], ["ma le nuu o Efaraima,", "and the land of Ephraim,"], ["ma Manase,", "and Manasseh,"], ["ma le nuu uma o Iuta,", "and all the land of Judah,"], ["e oo atu lava i le sami tupito,", "unto the utmost sea,"]]},
  {num:3,words:[["ma le itu i toga,", "And the south,"], ["ma le eleele laugatasi o le vanu o Ieriko,", "and the plain of the valley of Jericho,"], ["o le aai o laau o pāma,", "the city of palm trees,"], ["e oo atu i Soara.", "unto Zoar."]]},
  {num:4,words:[["Ua fetalai mai foi Ieova ia te ia,", "And the LORD said unto him,"], ["O le nuu lena na ou tauto ai ia Aperaamo,", "This is the land which I sware unto Abraham,"], ["ma Isaako,", "unto Isaac,"], ["ma Iakopo,", "and unto Jacob,"], ["ua faapea atu,", "saying,"], ["Ou te foaiina atu i lau fanau;", "I will give it unto thy seed:"], ["ua ou faaali atu ai ia te oe i ou mata,", "I have caused thee to see it with thine eyes,"], ["a e te le sopoia atu i ai.", "but thou shalt not go over thither."]]},
  {num:5,words:[["Ua oti foi Mose le auauna a Ieova i lea mea i le nuu o Moapi,", "So Moses the servant of the LORD died there in the land of Moab,"], ["e pei ona fetalai mai ai o Ieova.", "according to the word of the LORD."]]},
  {num:6,words:[["Ua ia tanu foi ia te ia i le vanu i le nuu o Moapi,", "And he buried him in a valley in the land of Moab,"], ["e faafeagai ma Petepeora;", "over against Beth-peor:"], ["a e le iloa e se tagata lona tuugamau ua oo mai lava i le aso nei.", "but no man knoweth of his sepulchre unto this day."]]},
  {num:7,words:[["Ua oti foi Mose ina ua selau ma le lua sefulu ona tausaga;", "And Moses was an hundred and twenty years old when he died:"], ["e lei puaoa ona mata,", "his eye was not dim,"], ["e lei mavae foi lona malosi.", "nor his natural force abated."]]},
  {num:8,words:[["Ua fetagisi foi le fanauga a Isaraelu ia Mose i le eleele laugatasi o Moapi i aso e tolu sefulu;", "And the children of Israel wept for Moses in the plains of Moab thirty days:"], ["ona atoatoa ai lea o aso na fetagisi ma faanoanoa ai ia Mose.", "so the days of weeping and mourning for Moses were ended."]]},
  {num:9,words:[["Ua tumu foi Iosua le atalii o Nuno i le agaga e poto ai;", "And Joshua the son of Nun was full of the spirit of wisdom;"], ["auā na faaee atu e Mose ona lima i luga ia te ia;", "for Moses had laid his hands upon him:"], ["na faalogo foi le fanauga a Isaraelu ia te ia,", "and the children of Israel hearkened unto him,"], ["ma ua latou faia e pei ona poloai mai ai o Ieova ia Mose.", "and did as the LORD commanded Moses."]]},
  {num:10,words:[["Ua le toe tu mai se perofeta ia Isaraelu e pei o Mose,", "And there arose not a prophet since in Israel like unto Moses,"], ["sa la fesagai ma Ieova;", "whom the LORD knew face to face,"]]},
  {num:11,words:[["e pei o ia i faailoga uma ma vavega,", "In all the signs and the wonders,"], ["sa auina atu ai o ia e Ieova e fai i le nuu o Aikupito ia Farao,", "which the LORD sent him to do in the land of Egypt to Pharaoh,"], ["ma ana auauna uma,", "and to all his servants,"], ["atoa ma lona nuu uma lava,", "and to all his land,"]]},
  {num:12,words:[["ma le aao malosi uma,", "And in all that mighty hand,"], ["atoa ma mea matuā matautia uma na faia e Mose i luma o Isaraelu uma lava.", "and in all the great terror which Moses shewed in the sight of all Israel."]]},
];
renderVerseSet(deu_ch_34_Verses, 'deu-ch34-verses');

})();